{
  "name": "Nexus",
  "description": "A modern, AI-powered social messaging app featuring a unique Triage Inbox, smart action item detection, and chat summarization."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  name: string;
  avatar: string;
}

export interface Message {
  id: string;
  senderId: string;
  text: string;
  timestamp: Date;
  isActionItem?: boolean;
}

export interface Chat {
  id: string;
  name: string;
  isGroup: boolean;
  priority: 'high' | 'normal';
  unreadCount: number;
  participants: User[];
  messages: Message[];
  lastMessage?: string;
  lastMessageTime?: Date;
}

export interface ActionItem {
  id: string;
  sourceMessageId: string;
  chatId: string;
  title: string; // Extracted action
  dueDateTime: string; // Extracted date/time
  isCompleted: boolean;
}

export type TabType = 'priority' | 'groups' | 'actions';

import { GoogleGenAI, Type } from "@google/genai";
import { Message } from "../types";

// Initialize the API client
// Note: In a production app, never expose keys on the client.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = 'gemini-3-flash-preview';

/**
 * Summarizes a list of messages using Gemini.
 */
export const summarizeChat = async (messages: Message[]): Promise<string> => {
  if (messages.length === 0) return "No messages to summarize.";

  const transcript = messages
    .map(m => `${m.senderId === 'me' ? 'Me' : 'Them'}: ${m.text}`)
    .join('\n');

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `You are a helpful assistant for a messaging app called Nexus. 
      Summarize the following chat conversation into a concise paragraph (max 3 sentences), highlighting key points and decisions.

      Transcript:
      ${transcript}`,
    });

    return response.text || "Could not generate summary.";
  } catch (error) {
    console.error("Gemini Summarize Error:", error);
    return "Unable to summarize at this time.";
  }
};

/**
 * Analyzes a message to see if it contains an action item (date/time).
 */
export const detectActionItem = async (text: string): Promise<{ isAction: boolean; title?: string; dateTime?: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Analyze the following message. Does it contain a specific intent to do something at a specific date or time?
      Examples of matches: "Let's meet tomorrow at 5pm", "Deadline is Friday", "Call me in 10 mins".
      Examples of non-matches: "I love history", "What time is it?".

      Message: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isAction: { type: Type.BOOLEAN, description: "True if the message contains a scheduled task or reminder." },
            title: { type: Type.STRING, description: "A short title for the action item (e.g., 'Meeting with John')." },
            dateTime: { type: Type.STRING, description: "The extracted date/time in a readable format." }
          },
          required: ["isAction"]
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return { isAction: false };
  } catch (error) {
    console.error("Gemini Action Detection Error:", error);
    return { isAction: false };
  }
};

import React from 'react';
import { ActionItem } from '../types';
import { CheckCircle, Calendar, ArrowRight } from 'lucide-react';

interface ActionCardProps {
  item: ActionItem;
  onComplete: (id: string) => void;
  onGoToChat: (chatId: string) => void;
}

export const ActionCard: React.FC<ActionCardProps> = ({ item, onComplete, onGoToChat }) => {
  return (
    <div className={`
      relative overflow-hidden rounded-xl p-4 mb-3 border transition-all duration-300
      ${item.isCompleted 
        ? 'bg-gray-100 dark:bg-gray-800 border-gray-200 dark:border-gray-700 opacity-60' 
        : 'bg-white dark:bg-nexus-card border-nexus-primary/30 shadow-sm hover:shadow-md'
      }
    `}>
      {/* Decorative gradient bar on left */}
      {!item.isCompleted && (
        <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-gradient-to-b from-nexus-primary to-nexus-accent"></div>
      )}

      <div className="flex justify-between items-start pl-2">
        <div className="flex-1">
          <h4 className={`font-bold text-lg mb-1 ${item.isCompleted ? 'line-through text-gray-500' : 'text-slate-800 dark:text-white'}`}>
            {item.title}
          </h4>
          <div className="flex items-center text-sm text-gray-600 dark:text-gray-400 mb-3">
            <Calendar size={14} className="mr-1.5" />
            <span>{item.dueDateTime}</span>
          </div>
        </div>

        <button 
          onClick={() => onComplete(item.id)}
          className={`p-2 rounded-full transition-colors ${item.isCompleted ? 'text-nexus-success' : 'text-gray-300 hover:text-nexus-success'}`}
        >
          <CheckCircle size={24} fill={item.isCompleted ? "currentColor" : "none"} />
        </button>
      </div>

      <div className="flex justify-end pl-2">
         <button 
           onClick={() => onGoToChat(item.chatId)}
           className="text-xs font-semibold uppercase tracking-wider text-nexus-primary hover:text-nexus-accent flex items-center transition-colors"
         >
           View Context <ArrowRight size={12} className="ml-1" />
         </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Chat, Message } from '../types';
import { Send, ArrowLeft, Sparkles, MoreVertical, Paperclip } from 'lucide-react';
import { summarizeChat } from '../services/geminiService';

interface ChatInterfaceProps {
  chat: Chat;
  onBack: () => void;
  onSendMessage: (text: string) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
    // Reset summary when switching chats
    setSummary(null);
  }, [chat.messages, chat.id]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    onSendMessage(inputText);
    setInputText('');
  };

  const handleCatchMeUp = async () => {
    setIsSummarizing(true);
    const result = await summarizeChat(chat.messages);
    setSummary(result);
    setIsSummarizing(false);
  };

  return (
    <div className="flex flex-col h-full bg-white dark:bg-gray-900 relative">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b dark:border-gray-700 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full md:hidden">
            <ArrowLeft size={20} />
          </button>
          <div className="relative">
            {chat.isGroup ? (
              <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-nexus-primary to-nexus-accent flex items-center justify-center text-white font-bold">
                {chat.name[0]}
              </div>
            ) : (
              <img src={chat.participants[0].avatar} alt={chat.name} className="w-10 h-10 rounded-full object-cover" />
            )}
            <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white dark:border-gray-900"></div>
          </div>
          <div>
            <h3 className="font-bold dark:text-white">{chat.name}</h3>
            <span className="text-xs text-gray-500 dark:text-gray-400">
              {chat.isGroup ? `${chat.participants.length + 1} members` : 'Active now'}
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {chat.isGroup && (
             <button 
             onClick={handleCatchMeUp}
             disabled={isSummarizing}
             className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-nexus-primary to-nexus-accent text-white rounded-full text-xs font-bold shadow-lg hover:shadow-xl transition-all"
           >
             <Sparkles size={14} />
             {isSummarizing ? 'Thinking...' : 'Catch Me Up'}
           </button>
          )}
          <button className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <MoreVertical size={20} className="text-gray-600 dark:text-gray-300" />
          </button>
        </div>
      </div>

      {/* Summary Area */}
      {summary && (
        <div className="m-4 p-4 bg-nexus-primary/10 dark:bg-nexus-primary/20 border border-nexus-primary/20 rounded-xl">
           <div className="flex justify-between items-start mb-2">
              <h4 className="text-sm font-bold text-nexus-primary flex items-center gap-2">
                <Sparkles size={14} /> AI Summary
              </h4>
              <button onClick={() => setSummary(null)} className="text-xs text-gray-500 hover:text-gray-700 dark:hover:text-gray-300">Close</button>
           </div>
           <p className="text-sm text-gray-800 dark:text-gray-200 leading-relaxed">{summary}</p>
        </div>
      )}

      {/* Mobile Catch Up Button (Floating) */}
      {chat.isGroup && !summary && (
        <button 
          onClick={handleCatchMeUp}
          className="sm:hidden absolute top-20 right-4 z-20 bg-nexus-primary text-white p-2 rounded-full shadow-lg"
        >
          <Sparkles size={18} />
        </button>
      )}

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {chat.messages.map((msg) => {
          const isMe = msg.senderId === 'me';
          return (
            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
              {!isMe && chat.isGroup && (
                <div className="w-8 h-8 rounded-full bg-gray-300 mr-2 flex-shrink-0 flex items-center justify-center text-xs font-bold overflow-hidden">
                    {/* Placeholder avatar for group member */}
                     {chat.participants.find(p => p.id === msg.senderId)?.name[0] || '?'}
                </div>
              )}
              <div className={`max-w-[75%] lg:max-w-[60%]`}>
                {!isMe && chat.isGroup && (
                  <span className="text-xs text-gray-500 ml-1 mb-1 block">
                    {chat.participants.find(p => p.id === msg.senderId)?.name || 'Unknown'}
                  </span>
                )}
                <div 
                  className={`p-3 rounded-2xl text-sm leading-relaxed ${
                    isMe 
                      ? 'bg-nexus-primary text-white rounded-tr-none' 
                      : 'bg-gray-100 dark:bg-gray-800 dark:text-gray-200 rounded-tl-none'
                  }`}
                >
                  {msg.text}
                </div>
                {msg.isActionItem && (
                   <div className="mt-1 ml-1 text-[10px] text-nexus-accent font-bold uppercase tracking-widest flex items-center gap-1">
                      <Sparkles size={8} /> Action Detected
                   </div>
                )}
                <span className={`text-[10px] opacity-70 mt-1 block px-1 ${isMe ? 'text-right' : 'text-left'}`}>
                  {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white dark:bg-gray-900 border-t dark:border-gray-700">
        <div className="flex items-center gap-2 bg-gray-50 dark:bg-gray-800 rounded-full px-4 py-2 border border-gray-200 dark:border-gray-700 focus-within:border-nexus-primary focus-within:ring-1 focus-within:ring-nexus-primary transition-all">
          <button className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
            <Paperclip size={20} />
          </button>
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type a message..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm dark:text-white placeholder-gray-400"
          />
          <button 
            onClick={handleSend}
            disabled={!inputText.trim()}
            className={`p-2 rounded-full transition-colors ${
              inputText.trim() 
                ? 'bg-nexus-primary text-white hover:bg-blue-600' 
                : 'bg-gray-200 dark:bg-gray-700 text-gray-400 cursor-not-allowed'
            }`}
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType } from './types';
import { detectActionItem } from './services/geminiService';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { 
  Menu, Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare 
} from 'lucide-react';

// --- MOCK DATA ---
const CURRENT_USER: User = { id: 'me', name: 'Alex', avatar: 'https://picsum.photos/200' };

const MOCK_USERS: User[] = [
  { id: 'u1', name: 'Sarah Jen', avatar: 'https://picsum.photos/201' },
  { id: 'u2', name: 'Dev Team', avatar: 'https://picsum.photos/202' }, // Group
  { id: 'u3', name: 'Mike Ross', avatar: 'https://picsum.photos/203' },
];

const INITIAL_CHATS: Chat[] = [
  {
    id: 'c1',
    name: 'Sarah Jen',
    isGroup: false,
    priority: 'high',
    unreadCount: 2,
    participants: [MOCK_USERS[0]],
    messages: [
      { id: 'm1', senderId: 'u1', text: 'Hey Alex, did you see the designs?', timestamp: new Date(Date.now() - 1000 * 60 * 60) },
      { id: 'm2', senderId: 'me', text: 'Yes, looking good.', timestamp: new Date(Date.now() - 1000 * 60 * 30) },
      { id: 'm3', senderId: 'u1', text: 'Can we meet tomorrow at 10am to finalize?', timestamp: new Date(Date.now() - 1000 * 60 * 5) }
    ]
  },
  {
    id: 'c2',
    name: 'Product Launch',
    isGroup: true,
    priority: 'normal',
    unreadCount: 5,
    participants: [MOCK_USERS[0], MOCK_USERS[2]],
    messages: [
      { id: 'm4', senderId: 'u3', text: 'Backend is ready.', timestamp: new Date(Date.now() - 1000 * 60 * 120) },
      { id: 'm5', senderId: 'u1', text: 'Frontend needs a tweak on the home screen.', timestamp: new Date(Date.now() - 1000 * 60 * 100) },
      { id: 'm6', senderId: 'u3', text: 'Noted. Will fix by EOD.', timestamp: new Date(Date.now() - 1000 * 60 * 90) },
      { id: 'm7', senderId: 'me', text: 'Great work team.', timestamp: new Date(Date.now() - 1000 * 60 * 60) },
      { id: 'm8', senderId: 'u1', text: 'Don\'t forget the deploy checklist due Friday.', timestamp: new Date(Date.now() - 1000 * 60 * 10) }
    ]
  },
  {
    id: 'c3',
    name: 'Mike Ross',
    isGroup: false,
    priority: 'normal',
    unreadCount: 0,
    participants: [MOCK_USERS[2]],
    messages: [
      { id: 'm9', senderId: 'u3', text: 'Lunch?', timestamp: new Date(Date.now() - 1000 * 60 * 60 * 24) }
    ]
  }
];

export default function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);

  const [chats, setChats] = useState<Chat[]>(INITIAL_CHATS);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);

  // Toggle Dark Mode
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Initial scan for action items in mock data (simulating persistence)
  useEffect(() => {
    // Only run once on mount
    const scanExisting = async () => {
      // In a real app, these would come from the DB. 
      // Here we just manually seed one for demo purposes based on the mock data
      const demoAction: ActionItem = {
        id: 'ai_demo_1',
        chatId: 'c1',
        sourceMessageId: 'm3',
        title: 'Meet with Sarah',
        dueDateTime: 'Tomorrow at 10am',
        isCompleted: false
      };
      const demoAction2: ActionItem = {
        id: 'ai_demo_2',
        chatId: 'c2',
        sourceMessageId: 'm8',
        title: 'Deploy Checklist',
        dueDateTime: 'Friday',
        isCompleted: false
      };
      setActionItems([demoAction, demoAction2]);
    };
    scanExisting();
  }, []);

  const handleSendMessage = async (text: string) => {
    if (!selectedChatId) return;

    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: 'me',
      text,
      timestamp: new Date()
    };

    // Update Chat State
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // AI Analysis for Action Items
    // We analyze the user's outgoing message to set reminders for themselves
    const analysis = await detectActionItem(text);
    if (analysis.isAction) {
      const newAction: ActionItem = {
        id: Date.now().toString() + '_action',
        chatId: selectedChatId,
        sourceMessageId: newMessage.id,
        title: analysis.title || 'New Reminder',
        dueDateTime: analysis.dateTime || 'Unspecified time',
        isCompleted: false
      };

      // Mark message as action item
      setChats(prev => prev.map(c => {
         if(c.id === selectedChatId) {
           const updatedMsgs = c.messages.map(m => m.id === newMessage.id ? {...m, isActionItem: true} : m);
           return { ...c, messages: updatedMsgs };
         }
         return c;
      }));

      setActionItems(prev => [newAction, ...prev]);
    }
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const getFilteredChats = () => {
    switch (activeTab) {
      case 'priority':
        return chats.filter(c => c.priority === 'high' || c.unreadCount > 0);
      case 'groups':
        return chats.filter(c => c.isGroup);
      default:
        return chats;
    }
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDER ---
  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden ${darkMode ? 'dark' : ''}`}>

      {/* Mobile-first Layout Logic: If chat selected, hide inbox on mobile */}
      <div className={`flex-1 flex overflow-hidden relative`}>

        {/* SIDEBAR / INBOX VIEW */}
        <div className={`
          w-full md:w-[380px] lg:w-[420px] bg-white dark:bg-nexus-dark flex flex-col border-r dark:border-gray-800
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Top Bar */}
          <div className="p-4 flex justify-between items-center bg-white dark:bg-nexus-dark z-10">
            <h1 className="text-2xl font-bold tracking-tight dark:text-white flex items-center gap-2">
              <div className="w-8 h-8 bg-nexus-primary rounded-lg flex items-center justify-center text-white">N</div>
              Nexus
            </h1>
            <div className="flex gap-2">
              <button 
                onClick={() => setDarkMode(!darkMode)}
                className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors"
              >
                {darkMode ? <Sun size={20} /> : <Moon size={20} />}
              </button>
              <button className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                <Bell size={20} />
              </button>
              <div className="w-8 h-8 rounded-full bg-gray-200 overflow-hidden ml-2 border border-gray-100">
                <img src={CURRENT_USER.avatar} alt="Me" />
              </div>
            </div>
          </div>

          {/* Search */}
          <div className="px-4 pb-2">
            <div className="bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center px-3 py-2.5">
              <Search size={18} className="text-gray-400 mr-2" />
              <input 
                type="text" 
                placeholder="Search messages..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
          </div>

          {/* TRIAGE TABS */}
          <div className="flex px-4 mt-2 space-x-1 border-b dark:border-gray-800">
             <button 
               onClick={() => setActiveTab('priority')}
               className={`flex-1 pb-3 text-sm font-bold border-b-2 transition-colors flex justify-center items-center gap-1.5 ${activeTab === 'priority' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
             >
               <Star size={14} /> Priority
             </button>
             <button 
               onClick={() => setActiveTab('groups')}
               className={`flex-1 pb-3 text-sm font-bold border-b-2 transition-colors flex justify-center items-center gap-1.5 ${activeTab === 'groups' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
             >
               <MessageSquare size={14} /> Groups
             </button>
             <button 
               onClick={() => setActiveTab('actions')}
               className={`flex-1 pb-3 text-sm font-bold border-b-2 transition-colors flex justify-center items-center gap-1.5 ${activeTab === 'actions' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
             >
               <Zap size={14} /> Actions
               {actionItems.filter(i => !i.isCompleted).length > 0 && (
                 <span className="bg-nexus-primary text-white text-[10px] px-1.5 rounded-full">
                   {actionItems.filter(i => !i.isCompleted).length}
                 </span>
               )}
             </button>
          </div>

          {/* CONTENT LIST */}
          <div className="flex-1 overflow-y-auto p-4 space-y-2">

            {activeTab === 'actions' ? (
              // ACTION ITEMS VIEW
              <div className="space-y-4">
                 <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Pending</div>
                 {actionItems.filter(i => !i.isCompleted).length === 0 && (
                   <div className="text-center py-10 text-gray-400">
                     <CheckSquare size={48} className="mx-auto mb-2 opacity-20" />
                     <p>All caught up!</p>
                   </div>
                 )}
                 {actionItems.filter(i => !i.isCompleted).map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}

                 {actionItems.filter(i => i.isCompleted).length > 0 && (
                   <>
                     <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mt-6 mb-2">Completed</div>
                     {actionItems.filter(i => i.isCompleted).map(item => (
                       <ActionCard 
                        key={item.id} 
                        item={item} 
                        onComplete={toggleActionComplete} 
                        onGoToChat={(id) => setSelectedChatId(id)}
                       />
                     ))}
                   </>
                 )}
              </div>
            ) : (
              // CHATS VIEW (Priority or Groups)
              <>
                 {getFilteredChats().length === 0 && (
                   <div className="text-center py-10 text-gray-400 text-sm">
                     No chats found in this view.
                   </div>
                 )}
                 {getFilteredChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
                       onClick={() => setSelectedChatId(chat.id)}
                       className={`w-full flex items-start p-3 rounded-2xl transition-all duration-200 ${
                         selectedChatId === chat.id 
                           ? 'bg-nexus-primary text-white shadow-lg shadow-blue-500/30' 
                           : 'hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-100'
                       }`}
                     >
                       <div className="relative mr-3 flex-shrink-0">
                         {chat.isGroup ? (
                            <div className={`w-12 h-12 rounded-full flex items-center justify-center text-lg font-bold ${selectedChatId === chat.id ? 'bg-white/20' : 'bg-gray-200 dark:bg-gray-700'}`}>
                              {chat.name[0]}
                            </div>
                         ) : (
                            <img src={chat.participants[0].avatar} className="w-12 h-12 rounded-full object-cover" alt="" />
                         )}
                         {chat.unreadCount > 0 && selectedChatId !== chat.id && (
                           <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full border-2 border-white dark:border-nexus-dark flex items-center justify-center text-[10px] text-white font-bold">
                             {chat.unreadCount}
                           </span>
                         )}
                       </div>

                       <div className="flex-1 text-left min-w-0">
                         <div className="flex justify-between items-baseline mb-1">
                           <h3 className={`font-bold truncate ${selectedChatId === chat.id ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                             {chat.name}
                           </h3>
                           <span className={`text-[10px] ${selectedChatId === chat.id ? 'text-blue-100' : 'text-gray-400'}`}>
                             {lastMsg?.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                           </span>
                         </div>
                         <p className={`text-sm truncate ${selectedChatId === chat.id ? 'text-blue-50' : 'text-gray-500 dark:text-gray-400'}`}>
                           {chat.isGroup && lastMsg?.senderId !== 'me' && <span className="font-semibold">{chat.participants.find(p=>p.id === lastMsg.senderId)?.name.split(' ')[0]}: </span>}
                           {lastMsg?.text || 'No messages'}
                         </p>
                       </div>
                     </button>
                   );
                 })}
              </>
            )}
          </div>
        </div>

        {/* CHAT AREA */}
        <div className={`
          flex-1 bg-white dark:bg-gray-900
          ${!selectedChatId ? 'hidden md:flex items-center justify-center' : 'flex'}
        `}>
          {activeChat ? (
            <ChatInterface 
              chat={activeChat} 
              onBack={() => setSelectedChatId(null)}
              onSendMessage={handleSendMessage}
            />
          ) : (
            <div className="text-center opacity-30">
              <div className="w-24 h-24 bg-gray-200 dark:bg-gray-800 rounded-full mx-auto mb-4 flex items-center justify-center">
                 <MessageSquare size={48} />
              </div>
              <h2 className="text-xl font-bold dark:text-white">Select a conversation</h2>
              <p className="dark:text-gray-400">Choose from the Triage Inbox to start messaging</p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
}

import { createClient } from '@supabase/supabase-js';

// NOTE: In a real deployment, use process.env.REACT_APP_SUPABASE_URL, etc.
// For this demo context, we assume these are available or the user will fill them.
const SUPABASE_URL = process.env.SUPABASE_URL || 'https://your-project.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_ANON_KEY || 'your-anon-key';

export const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

export const getCurrentUser = async () => {
  const { data: { session }, error } = await supabase.auth.getSession();
  if (error || !session) return null;

  // Fetch profile details
  const { data: profile } = await supabase
    .from('profiles')
    .select('*')
    .eq('id', session.user.id)
    .single();

  return { ...session.user, ...profile };
};

export const fetchUserChats = async (userId: string) => {
  // Fetch chats where the user is a participant
  const { data: participations, error } = await supabase
    .from('chat_participants')
    .select('chat_id, chats(*)')
    .eq('user_id', userId);

  if (error || !participations) return [];

  // Format matches internal App types
  // Note: This is a simplification. In a real app, you'd join to get other participants' names/avatars.
  return participations.map((p: any) => ({
    id: p.chat_id,
    name: p.chats.name || 'Chat', 
    isGroup: p.chats.is_group,
    priority: 'normal',
    unreadCount: 0, // Logic for unread counts would require a separate table or read receipt logic
    participants: [], // Fetched separately or joined
    messages: [] 
  }));
};

export const fetchMessages = async (chatId: string) => {
  const { data, error } = await supabase
    .from('messages')
    .select('*')
    .eq('chat_id', chatId)
    .order('created_at', { ascending: true });

  if (error) return [];

  return data.map((m: any) => ({
    id: m.id,
    senderId: m.sender_id,
    text: m.content,
    timestamp: new Date(m.created_at),
    isActionItem: m.is_action_item
  }));
};

export const sendMessageToDb = async (chatId: string, senderId: string, text: string) => {
  const { data, error } = await supabase
    .from('messages')
    .insert([{ chat_id: chatId, sender_id: senderId, content: text }])
    .select();
  return { data, error };
};

export const searchUsers = async (query: string) => {
  const { data, error } = await supabase
    .from('profiles')
    .select('*')
    .ilike('full_name', `%${query}%`)
    .limit(5);
  return data || [];
};

export const createNewChat = async (currentUserId: string, otherUserId: string, otherUserName: string) => {
  // 1. Create Chat
  const { data: chatData, error: chatError } = await supabase
    .from('chats')
    .insert([{ is_group: false, name: otherUserName }])
    .select()
    .single();

  if (chatError) throw chatError;

  // 2. Add Participants
  const { error: partError } = await supabase
    .from('chat_participants')
    .insert([
      { chat_id: chatData.id, user_id: currentUserId },
      { chat_id: chatData.id, user_id: otherUserId }
    ]);

  if (partError) throw partError;
  return chatData;
};

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ArrowRight, Loader2 } from 'lucide-react';

export const AuthScreen = ({ onAuthSuccess }: { onAuthSuccess: () => void }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
      } else {
        // Sign Up
        const { data, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName } }
        });
        if (signUpError) throw signUpError;

        // Supabase trigger usually handles profile creation, but if not, we might need to insert manually here.
        // For this demo, assuming trigger exists or Auth metadata is enough.
      }
      onAuthSuccess();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
