import React, { useState } from 'react';
import { Search, UserPlus, X } from 'lucide-react';
import { searchUsers, createNewChat } from '../services/supabaseClient';

interface NewChatModalProps {
  currentUserId: string;
  onClose: () => void;
  onChatCreated: () => void;
}

export const NewChatModal: React.FC<NewChatModalProps> = ({ currentUserId, onClose, onChatCreated }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (val: string) => {
    setQuery(val);
    if (val.length > 2) {
      setLoading(true);
      const users = await searchUsers(val);
      // Filter out self
      setResults(users.filter((u: any) => u.id !== currentUserId));
      setLoading(false);
    } else {
      setResults([]);
    }
  };

  const startChat = async (userId: string, userName: string) => {
    try {
      setLoading(true);
      await createNewChat(currentUserId, userId, userName);
      onChatCreated();
      onClose();
    } catch (e) {
      console.error(e);
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white dark:bg-nexus-card w-full max-w-md rounded-2xl shadow-2xl border dark:border-gray-700 overflow-hidden">
        <div className="p-4 border-b dark:border-gray-700 flex justify-between items-center">
          <h2 className="font-bold text-lg dark:text-white">New Conversation</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <X size={20} className="dark:text-gray-400" />
          </button>
        </div>

        <div className="p-4">
          <div className="relative mb-4">
            <Search className="absolute left-3 top-3 text-gray-400" size={18} />
            <input 
              autoFocus
              type="text" 
              placeholder="Search people by name..." 
              value={query}
              onChange={(e) => handleSearch(e.target.value)}
              className="w-full bg-gray-100 dark:bg-gray-800 rounded-xl py-2.5 pl-10 pr-4 outline-none focus:ring-2 focus:ring-nexus-primary dark:text-white"
            />
          </div>

          <div className="min-h-[200px]">
            {loading ? (
              <div className="flex justify-center py-8 text-gray-400">Searching...</div>
            ) : results.length > 0 ? (
              <div className="space-y-2">
                {results.map(user => (
                  <button 
                    key={user.id}
                    onClick={() => startChat(user.id, user.full_name)}
                    className="w-full flex items-center gap-3 p-3 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-xl transition-colors text-left"
                  >
                    <div className="w-10 h-10 rounded-full bg-nexus-primary/20 text-nexus-primary flex items-center justify-center font-bold">
                      {user.full_name[0]}
                    </div>
                    <div>
                      <div className="font-bold dark:text-white">{user.full_name}</div>
                      <div className="text-xs text-gray-500">Click to message</div>
                    </div>
                    <UserPlus size={16} className="ml-auto text-gray-400" />
                  </button>
                ))}
              </div>
            ) : query.length > 2 ? (
              <div className="text-center py-8 text-gray-400">No users found.</div>
            ) : (
              <div className="text-center py-8 text-gray-400 text-sm">
                Type a name to find your friends.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType } from './types';
import { detectActionItem } from './services/geminiService';
import { supabase, getCurrentUser, fetchUserChats, fetchMessages, sendMessageToDb } from './services/supabaseClient';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { AuthScreen } from './components/AuthScreen';
import { NewChatModal } from './components/NewChatModal';
import { 
  Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare, Plus, LogOut
} from 'lucide-react';

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
  const [showNewChatModal, setShowNewChatModal] = useState(false);

  const [chats, setChats] = useState<Chat[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);

  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages in this chat
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: 'INSERT', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {
          const newMsg = payload.new;
          // Avoid duplication if we optimistically added it
          if (newMsg.sender_id === session.user.id) return; 

          const formattedMsg: Message = {
            id: newMsg.id,
            senderId: newMsg.sender_id,
            text: newMsg.content,
            timestamp: new Date(newMsg.created_at),
            isActionItem: newMsg.is_action_item
          };

          setChats(prev => prev.map(c => {
             if (c.id === selectedChatId) {
               return { ...c, messages: [...c.messages, formattedMsg] };
             }
             return c;
          }));
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date()
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text);

    // AI Analysis (Local for now, could be server-side function)
    const analysis = await detectActionItem(text);
    if (analysis.isAction) {
      const newAction: ActionItem = {
        id: Date.now().toString() + '_action',
        chatId: selectedChatId,
        sourceMessageId: tempId,
        title: analysis.title || 'New Reminder',
        dueDateTime: analysis.dateTime || 'Unspecified time',
        isCompleted: false
      };
      setActionItems(prev => [newAction, ...prev]);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const getFilteredChats = () => {
    if (!chats) return [];
    switch (activeTab) {
      case 'priority':
        return chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
      case 'groups':
        return chats.filter(c => c.isGroup);
      default:
        return chats;
    }
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-gray-50 dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-primary"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden ${darkMode ? 'dark' : ''}`}>
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      {/* Mobile-first Layout Logic */}
      <div className={`flex-1 flex overflow-hidden relative`}>

        {/* SIDEBAR */}
        <div className={`
          w-full md:w-[380px] lg:w-[420px] bg-white dark:bg-nexus-dark flex flex-col border-r dark:border-gray-800
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Top Bar */}
          <div className="p-4 flex justify-between items-center bg-white dark:bg-nexus-dark z-10">
            <h1 className="text-2xl font-bold tracking-tight dark:text-white flex items-center gap-2">
              <div className="w-8 h-8 bg-nexus-primary rounded-lg flex items-center justify-center text-white">N</div>
              Nexus
            </h1>
            <div className="flex gap-2">
              <button onClick={() => setShowNewChatModal(true)} className="p-2 text-nexus-primary hover:bg-nexus-primary/10 rounded-full transition-colors">
                <Plus size={20} />
              </button>
              <button onClick={() => setDarkMode(!darkMode)} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
                {darkMode ? <Sun size={20} /> : <Moon size={20} />}
              </button>
              <button onClick={handleLogout} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full">
                <LogOut size={20} />
              </button>
            </div>
          </div>

          {/* Search */}
          <div className="px-4 pb-2">
            <div className="bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center px-3 py-2.5">
              <Search size={18} className="text-gray-400 mr-2" />
              <input 
                type="text" 
                placeholder="Search messages..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
          </div>

          {/* TABS */}
          <div className="flex px-4 mt-2 space-x-1 border-b dark:border-gray-800">
             <button onClick={() => setActiveTab('priority')} className={`flex-1 pb-3 text-sm font-bold border-b-2 transition-colors flex justify-center items-center gap-1.5 ${activeTab === 'priority' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               <Star size={14} /> Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`flex-1 pb-3 text-sm font-bold border-b-2 transition-colors flex justify-center items-center gap-1.5 ${activeTab === 'groups' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               <MessageSquare size={14} /> Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`flex-1 pb-3 text-sm font-bold border-b-2 transition-colors flex justify-center items-center gap-1.5 ${activeTab === 'actions' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               <Zap size={14} /> Actions
             </button>
          </div>

          {/* CONTENT LIST */}
          <div className="flex-1 overflow-y-auto p-4 space-y-2">
            {activeTab === 'actions' ? (
              <div className="space-y-4">
                 {actionItems.length === 0 && (
                   <div className="text-center py-10 text-gray-400">
                     <CheckSquare size={48} className="mx-auto mb-2 opacity-20" />
                     <p>All caught up!</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <>
                 {getFilteredChats().length === 0 && (
                   <div className="text-center py-10 text-gray-400 text-sm">
                     No chats found. <br/> Click + to start a conversation.
                   </div>
                 )}
                 {getFilteredChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
                       onClick={() => setSelectedChatId(chat.id)}
                       className={`w-full flex items-start p-3 rounded-2xl transition-all duration-200 ${
                         selectedChatId === chat.id 
                           ? 'bg-nexus-primary text-white shadow-lg shadow-blue-500/30' 
                           : 'hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-100'
                       }`}
                     >
                       <div className="relative mr-3 flex-shrink-0">
                          <div className={`w-12 h-12 rounded-full flex items-center justify-center text-lg font-bold ${selectedChatId === chat.id ? 'bg-white/20' : 'bg-gray-200 dark:bg-gray-700'}`}>
                            {chat.name[0]}
                          </div>
                       </div>

                       <div className="flex-1 text-left min-w-0">
                         <div className="flex justify-between items-baseline mb-1">
                           <h3 className={`font-bold truncate ${selectedChatId === chat.id ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                             {chat.name}
                           </h3>
                           <span className={`text-[10px] ${selectedChatId === chat.id ? 'text-blue-100' : 'text-gray-400'}`}>
                             {lastMsg?.timestamp ? new Date(lastMsg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                           </span>
                         </div>
                         <p className={`text-sm truncate ${selectedChatId === chat.id ? 'text-blue-50' : 'text-gray-500 dark:text-gray-400'}`}>
                           {lastMsg?.text || 'No messages yet'}
                         </p>
                       </div>
                     </button>
                   );
                 })}
              </>
            )}
          </div>
        </div>

        {/* CHAT AREA */}
        <div className={`
          flex-1 bg-white dark:bg-gray-900
          ${!selectedChatId ? 'hidden md:flex items-center justify-center' : 'flex'}
        `}>
          {activeChat ? (
            <ChatInterface 
              chat={activeChat} 
              onBack={() => setSelectedChatId(null)}
              onSendMessage={handleSendMessage}
            />
          ) : (
            <div className="text-center opacity-30">
              <div className="w-24 h-24 bg-gray-200 dark:bg-gray-800 rounded-full mx-auto mb-4 flex items-center justify-center">
                 <MessageSquare size={48} />
              </div>
              <h2 className="text-xl font-bold dark:text-white">Select a conversation</h2>
              <p className="dark:text-gray-400">Choose from the Triage Inbox or start a new chat</p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
}

