// --- MOCK SUPABASE CLIENT ---
// This allows the app to function fully in the browser without a real backend.
// It uses localStorage for the DB and BroadcastChannel for Realtime events.

const USERS_KEY = 'nexus_users';
const CHATS_KEY = 'nexus_chats';
const MESSAGES_KEY = 'nexus_messages';
const SESSION_KEY = 'nexus_session';
const PARTICIPANTS_KEY = 'nexus_chat_participants';

const broadcast = new BroadcastChannel('nexus_realtime');

// --- SEED DATA ---
const seedData = () => {
  if (!localStorage.getItem(USERS_KEY)) {
    const mockUsers = [
      { id: 'u1', email: 'sarah@nexus.com', phone: '5550101', full_name: 'Sarah Jen', password: '123' },
      { id: 'u2', email: 'mike@nexus.com', phone: '5550102', full_name: 'Mike Ross', password: '123' },
      { id: 'u3', email: 'dev@nexus.com', phone: '5550103', full_name: 'Dev Team', password: '123' },
    ];
    localStorage.setItem(USERS_KEY, JSON.stringify(mockUsers));
  }
};
seedData();

// --- HELPERS ---
const getStore = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const setStore = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// --- MOCK SUPABASE OBJECT ---
export const supabase = {
  auth: {
    getSession: async () => {
      const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
      return { data: { session: sessionUser ? { user: sessionUser } : null }, error: null };
    },
    signInWithPassword: async ({ email, password }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      // Allow login via Email OR Phone if we wanted, but sticking to email for credential simplicity
      // For now, keeping email as the unique login identifier
      const user = users.find((u: any) => u.email === email && u.password === password);
      if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        // Notify other tabs or components
        window.dispatchEvent(new Event('storage')); 
        return { data: { user, session: { user } }, error: null };
      }
      return { data: null, error: { message: 'Invalid credentials' } };
    },
    signUp: async ({ email, password, options }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      if (users.find((u: any) => u.email === email)) {
        return { data: null, error: { message: 'User already exists' } };
      }
      const newUser = {
        id: 'u_' + Date.now(),
        email,
        password,
        phone: options?.data?.phone || '',
        full_name: options?.data?.full_name || email.split('@')[0]
      };
      users.push(newUser);
      setStore(USERS_KEY, users);
      localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
      return { data: { user: newUser, session: { user: newUser } }, error: null };
    },
    signOut: async () => {
      localStorage.removeItem(SESSION_KEY);
      return { error: null };
    },
    onAuthStateChange: (callback: any) => {
      // Simple subscription
      const handler = () => {
        const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
        callback('SIGNED_IN', sessionUser ? { user: sessionUser } : null);
      };
      window.addEventListener('storage', handler);
      return { data: { subscription: { unsubscribe: () => window.removeEventListener('storage', handler) } } };
    }
  },
  channel: (channelName: string) => {
    return {
      on: (type: string, filter: any, callback: any) => {
        const handler = (event: MessageEvent) => {
          const { table, new: record, type: eventType } = event.data;
          // Filter logic for realtime events
          if (type === 'postgres_changes' && 
              filter.event === eventType && 
              filter.table === table) {

             // Check custom filter string (e.g. "chat_id=eq.123")
             if (filter.filter) {
               const [key, val] = filter.filter.split('=eq.');
               if (String(record[key]) !== String(val)) return;
             }
             callback({ new: record });
          }
        };
        broadcast.addEventListener('message', handler);
        return {
          subscribe: () => {} // Mock subscribe
        };
      }
    };
  },
  removeChannel: (channel: any) => {
    // Clean up if needed (broadcast listeners usually persistent in this simple mock)
  }
};

// --- SERVICE FUNCTIONS ---

export const getCurrentUser = async () => {
  const { data } = await supabase.auth.getSession();
  return data.session?.user || null;
};

export const fetchUserChats = async (userId: string) => {
  await delay(200);
  const participants = getStore(PARTICIPANTS_KEY);
  const allChats = getStore(CHATS_KEY);

  const myChatIds = participants
    .filter((p: any) => p.user_id === userId)
    .map((p: any) => p.chat_id);

  return allChats
    .filter((c: any) => myChatIds.includes(c.id))
    .map((c: any) => ({
      ...c,
      isGroup: c.is_group,
      unreadCount: 0,
      participants: [],
      messages: []
    }));
};

export const fetchMessages = async (chatId: string) => {
  await delay(200);
  const allMessages = getStore(MESSAGES_KEY);
  return allMessages
    .filter((m: any) => m.chat_id === chatId)
    .sort((a: any, b: any) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
    .map((m: any) => ({
      id: m.id,
      senderId: m.sender_id, // Return camelCase for UI, but internal is snake_case
      text: m.content,
      timestamp: new Date(m.created_at),
      isActionItem: m.is_action_item
    }));
};

export const sendMessageToDb = async (chatId: string, senderId: string, text: string) => {
  const allMessages = getStore(MESSAGES_KEY);
  const newMessage = {
    id: 'msg_' + Date.now(),
    chat_id: chatId,
    sender_id: senderId,
    content: text,
    created_at: new Date().toISOString(),
    is_action_item: false // In real app, AI could run on backend
  };

  allMessages.push(newMessage);
  setStore(MESSAGES_KEY, allMessages);

  // Emit Realtime Event
  broadcast.postMessage({
    type: 'INSERT',
    table: 'messages',
    new: newMessage
  });

  return { data: [newMessage], error: null };
};

export const searchUsers = async (query: string) => {
  await delay(300);
  const users = getStore(USERS_KEY);
  const q = query.toLowerCase();

  return users.filter((u: any) => 
    u.full_name.toLowerCase().includes(q) || 
    u.email.toLowerCase().includes(q) ||
    (u.phone && u.phone.includes(q)) // Search by phone number
  ).slice(0, 5); // Limit results
};

export const createGhostUser = async (identifier: string) => {
  const users = getStore(USERS_KEY);
  const isEmail = identifier.includes('@');

  // Create a placeholder user
  const newUser = {
    id: 'u_' + Date.now(),
    email: isEmail ? identifier : '',
    phone: !isEmail ? identifier : '',
    full_name: isEmail ? identifier.split('@')[0] : identifier,
    password: '123', 
    is_ghost: true 
  };

  users.push(newUser);
  setStore(USERS_KEY, users);
  return newUser;
};

export const createNewChat = async (currentUserId: string, otherUserId: string, otherUserName: string) => {
  const chats = getStore(CHATS_KEY);
  const participants = getStore(PARTICIPANTS_KEY);

  // Create Chat
  const newChat = {
    id: 'c_' + Date.now(),
    name: otherUserName,
    is_group: false,
    created_at: new Date().toISOString()
  };
  chats.push(newChat);
  setStore(CHATS_KEY, chats);

  // Add Participants
  participants.push({ chat_id: newChat.id, user_id: currentUserId });
  participants.push({ chat_id: newChat.id, user_id: otherUserId });
  setStore(PARTICIPANTS_KEY, participants);

  return newChat;
};

import React, { useState } from 'react';
import { Search, UserPlus, X, Send } from 'lucide-react';
import { searchUsers, createNewChat, createGhostUser } from '../services/supabaseClient';

interface NewChatModalProps {
  currentUserId: string;
  onClose: () => void;
  onChatCreated: () => void;
}

export const NewChatModal: React.FC<NewChatModalProps> = ({ currentUserId, onClose, onChatCreated }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (val: string) => {
    setQuery(val);
    if (val.length > 2) {
      setLoading(true);
      const users = await searchUsers(val);
      // Filter out self
      setResults(users.filter((u: any) => u.id !== currentUserId));
      setLoading(false);
    } else {
      setResults([]);
    }
  };

  const startChat = async (userId: string, userName: string) => {
    try {
      setLoading(true);
      await createNewChat(currentUserId, userId, userName);
      onChatCreated();
      onClose();
    } catch (e) {
      console.error(e);
      setLoading(false);
    }
  };

  const handleInviteAndChat = async () => {
    try {
      setLoading(true);
      // Create a ghost user for this phone/email
      const newUser = await createGhostUser(query);
      await createNewChat(currentUserId, newUser.id, newUser.full_name);
      onChatCreated();
      onClose();
    } catch (e) {
      console.error(e);
      setLoading(false);
    }
  };

  const isQueryValidContact = query.length > 3 && (query.includes('@') || /^\+?[\d\s-]{4,}$/.test(query));

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white dark:bg-nexus-card w-full max-w-md rounded-2xl shadow-2xl border dark:border-gray-700 overflow-hidden">
        <div className="p-4 border-b dark:border-gray-700 flex justify-between items-center">
          <h2 className="font-bold text-lg dark:text-white">New Conversation</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <X size={20} className="dark:text-gray-400" />
          </button>
        </div>

        <div className="p-4">
          <div className="relative mb-4">
            <Search className="absolute left-3 top-3 text-gray-400" size={18} />
            <input 
              autoFocus
              type="text" 
              placeholder="Search by name, email, or phone..." 
              value={query}
              onChange={(e) => handleSearch(e.target.value)}
              className="w-full bg-gray-100 dark:bg-gray-800 rounded-xl py-2.5 pl-10 pr-4 outline-none focus:ring-2 focus:ring-nexus-primary dark:text-white"
            />
          </div>

          <div className="min-h-[200px]">
            {loading ? (
              <div className="flex justify-center py-8 text-gray-400">Processing...</div>
            ) : results.length > 0 ? (
              <div className="space-y-2">
                {results.map(user => (
                  <button 
                    key={user.id}
                    onClick={() => startChat(user.id, user.full_name)}
                    className="w-full flex items-center gap-3 p-3 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-xl transition-colors text-left"
                  >
                    <div className="w-10 h-10 rounded-full bg-nexus-primary/20 text-nexus-primary flex items-center justify-center font-bold">
                      {user.full_name[0]}
                    </div>
                    <div>
                      <div className="font-bold dark:text-white">{user.full_name}</div>
                      <div className="text-xs text-gray-500">
                         {user.phone ? `Mobile: ${user.phone}` : user.email}
                      </div>
                    </div>
                    <UserPlus size={16} className="ml-auto text-gray-400" />
                  </button>
                ))}
              </div>
            ) : query.length > 2 ? (
               <div className="flex flex-col items-center justify-center py-8 text-center space-y-4">
                  <p className="text-gray-400">User not found on Nexus.</p>

                  {isQueryValidContact && (
                    <button 
                      onClick={handleInviteAndChat}
                      className="bg-nexus-primary/10 hover:bg-nexus-primary/20 text-nexus-primary px-6 py-3 rounded-xl font-bold flex items-center gap-2 transition-colors"
                    >
                      <Send size={18} />
                      Invite & Chat with "{query}"
                    </button>
                  )}
                  {isQueryValidContact && (
                     <p className="text-xs text-gray-400 max-w-[200px]">
                       They will receive an invite to join. You can start messaging immediately.
                     </p>
                  )}
               </div>
            ) : (
              <div className="text-center py-8 text-gray-400 text-sm">
                Type a name, email or number to find friends.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType } from './types';
import { detectActionItem } from './services/geminiService';
import { supabase, getCurrentUser, fetchUserChats, fetchMessages, sendMessageToDb } from './services/supabaseClient';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { AuthScreen } from './components/AuthScreen';
import { NewChatModal } from './components/NewChatModal';
import { 
  Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare, Plus, LogOut,
  Users
} from 'lucide-react';

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
  const [showNewChatModal, setShowNewChatModal] = useState(false);

  const [chats, setChats] = useState<Chat[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);

  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages in this chat
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: 'INSERT', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {
          const newMsg = payload.new;
          // Avoid duplication if we optimistically added it
          if (newMsg.sender_id === session.user.id) return; 

          const formattedMsg: Message = {
            id: newMsg.id,
            senderId: newMsg.sender_id,
            text: newMsg.content,
            timestamp: new Date(newMsg.created_at),
            isActionItem: newMsg.is_action_item
          };

          setChats(prev => prev.map(c => {
             if (c.id === selectedChatId) {
               return { ...c, messages: [...c.messages, formattedMsg] };
             }
             return c;
          }));
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date()
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text);

    // AI Analysis (Local for now, could be server-side function)
    const analysis = await detectActionItem(text);
    if (analysis.isAction) {
      const newAction: ActionItem = {
        id: Date.now().toString() + '_action',
        chatId: selectedChatId,
        sourceMessageId: tempId,
        title: analysis.title || 'New Reminder',
        dueDateTime: analysis.dateTime || 'Unspecified time',
        isCompleted: false
      };
      setActionItems(prev => [newAction, ...prev]);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const getFilteredChats = () => {
    if (!chats) return [];
    switch (activeTab) {
      case 'priority':
        return chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
      case 'groups':
        return chats.filter(c => c.isGroup);
      default:
        return chats;
    }
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-gray-50 dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-primary"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden bg-white dark:bg-nexus-dark ${darkMode ? 'dark' : ''}`}>
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* === SIDEBAR / MOBILE LIST VIEW === */}
        <div className={`
          flex flex-col h-full bg-white dark:bg-nexus-dark border-r dark:border-gray-800 transition-all duration-300
          w-full md:w-[380px] lg:w-[420px] 
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* HEADER */}
          <div className="px-6 py-5 flex justify-between items-center bg-white dark:bg-nexus-dark z-10 sticky top-0">
            <h1 className="text-2xl font-bold tracking-tight dark:text-white flex items-center gap-2">
              <span className="w-8 h-8 bg-gradient-to-br from-nexus-primary to-blue-600 rounded-xl flex items-center justify-center text-white text-lg shadow-blue-500/30 shadow-lg">N</span>
              <span>Nexus</span>
            </h1>
            <div className="flex items-center gap-1">
              <button onClick={() => setShowNewChatModal(true)} className="p-2.5 text-nexus-primary hover:bg-nexus-primary/10 rounded-full transition-colors">
                <Plus size={22} />
              </button>
              <button onClick={() => setDarkMode(!darkMode)} className="p-2.5 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                {darkMode ? <Sun size={22} /> : <Moon size={22} />}
              </button>
              <button onClick={handleLogout} className="p-2.5 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors">
                <LogOut size={22} />
              </button>
            </div>
          </div>

          {/* SEARCH */}
          <div className="px-6 pb-4">
            <div className="bg-gray-100 dark:bg-gray-800/50 rounded-2xl flex items-center px-4 py-3 transition-all focus-within:ring-2 focus-within:ring-nexus-primary/50">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text" 
                placeholder="Search conversations..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
          </div>

          {/* DESKTOP TABS (Hidden on Mobile) */}
          <div className="hidden md:flex px-6 space-x-6 border-b dark:border-gray-800 mb-2">
             <button onClick={() => setActiveTab('priority')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'priority' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'groups' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'actions' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Actions
             </button>
          </div>

          {/* SCROLLABLE LIST AREA */}
          <div className="flex-1 overflow-y-auto px-4 pb-24 md:pb-4 space-y-2 no-scrollbar">
            {activeTab === 'actions' ? (
              <div className="space-y-3 pt-2">
                 {actionItems.length === 0 && (
                   <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                     <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                       <CheckSquare size={32} className="opacity-40" />
                     </div>
                     <p>All caught up! No pending actions.</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <div className="space-y-1 pt-2">
                 {getFilteredChats().length === 0 && (
                   <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center">
                     <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                       <MessageSquare size={32} className="opacity-40" />
                     </div>
                     <span>No chats in {activeTab}.</span>
                     <button onClick={() => setShowNewChatModal(true)} className="mt-2 text-nexus-primary font-bold">Start a chat</button>
                   </div>
                 )}
                 {getFilteredChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
