// --- MOCK SUPABASE CLIENT ---
// This allows the app to function fully in the browser without a real backend.
// It uses localStorage for the DB and BroadcastChannel for Realtime events.

const USERS_KEY = 'nexus_users';
const CHATS_KEY = 'nexus_chats';
const MESSAGES_KEY = 'nexus_messages';
const SESSION_KEY = 'nexus_session';
const PARTICIPANTS_KEY = 'nexus_chat_participants';

const broadcast = new BroadcastChannel('nexus_realtime');

// --- SEED DATA ---
const seedData = () => {
  if (!localStorage.getItem(USERS_KEY)) {
    const mockUsers = [
      { id: 'u1', email: 'sarah@nexus.com', phone: '5550101', full_name: 'Sarah Jen', password: '123' },
      { id: 'u2', email: 'mike@nexus.com', phone: '5550102', full_name: 'Mike Ross', password: '123' },
      { id: 'u3', email: 'dev@nexus.com', phone: '5550103', full_name: 'Dev Team', password: '123' },
    ];
    localStorage.setItem(USERS_KEY, JSON.stringify(mockUsers));
  }
};
seedData();

// --- HELPERS ---
const getStore = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const setStore = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// --- MOCK SUPABASE OBJECT ---
export const supabase = {
  auth: {
    getSession: async () => {
      const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
      return { data: { session: sessionUser ? { user: sessionUser } : null }, error: null };
    },
    signInWithPassword: async ({ email, password }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      // Allow login via Email OR Phone if we wanted, but sticking to email for credential simplicity
      // For now, keeping email as the unique login identifier
      const user = users.find((u: any) => u.email === email && u.password === password);
      if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        // Notify other tabs or components
        window.dispatchEvent(new Event('storage')); 
        return { data: { user, session: { user } }, error: null };
      }
      return { data: null, error: { message: 'Invalid credentials' } };
    },
    signUp: async ({ email, password, options }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      if (users.find((u: any) => u.email === email)) {
        return { data: null, error: { message: 'User already exists' } };
      }
      const newUser = {
        id: 'u_' + Date.now(),
        email,
        password,
        phone: options?.data?.phone || '',
        full_name: options?.data?.full_name || email.split('@')[0]
      };
      users.push(newUser);
      setStore(USERS_KEY, users);
      localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
      return { data: { user: newUser, session: { user: newUser } }, error: null };
    },
    signOut: async () => {
      localStorage.removeItem(SESSION_KEY);
      return { error: null };
    },
    onAuthStateChange: (callback: any) => {
      // Simple subscription
      const handler = () => {
        const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
        callback('SIGNED_IN', sessionUser ? { user: sessionUser } : null);
      };
      window.addEventListener('storage', handler);
      return { data: { subscription: { unsubscribe: () => window.removeEventListener('storage', handler) } } };
    }
  },
  channel: (channelName: string) => {
    return {
      on: (type: string, filter: any, callback: any) => {
        const handler = (event: MessageEvent) => {
          const { table, new: record, type: eventType } = event.data;
          // Filter logic for realtime events
          if (type === 'postgres_changes' && 
              filter.event === eventType && 
              filter.table === table) {

             // Check custom filter string (e.g. "chat_id=eq.123")
             if (filter.filter) {
               const [key, val] = filter.filter.split('=eq.');
               if (String(record[key]) !== String(val)) return;
             }
             callback({ new: record });
          }
        };
        broadcast.addEventListener('message', handler);
        return {
          subscribe: () => {} // Mock subscribe
        };
      }
    };
  },
  removeChannel: (channel: any) => {
    // Clean up if needed (broadcast listeners usually persistent in this simple mock)
  }
};

// --- SERVICE FUNCTIONS ---

export const getCurrentUser = async () => {
  const { data } = await supabase.auth.getSession();
  return data.session?.user || null;
};

export const fetchUserChats = async (userId: string) => {
  await delay(200);
  const participants = getStore(PARTICIPANTS_KEY);
  const allChats = getStore(CHATS_KEY);

  const myChatIds = participants
    .filter((p: any) => p.user_id === userId)
    .map((p: any) => p.chat_id);

  return allChats
    .filter((c: any) => myChatIds.includes(c.id))
    .map((c: any) => ({
      ...c,
      isGroup: c.is_group,
      unreadCount: 0,
      participants: [],
      messages: []
    }));
};

export const fetchMessages = async (chatId: string) => {
  await delay(200);
  const allMessages = getStore(MESSAGES_KEY);
  return allMessages
    .filter((m: any) => m.chat_id === chatId)
    .sort((a: any, b: any) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
    .map((m: any) => ({
      id: m.id,
      senderId: m.sender_id, // Return camelCase for UI, but internal is snake_case
      text: m.content,
      timestamp: new Date(m.created_at),
      isActionItem: m.is_action_item
    }));
};

export const sendMessageToDb = async (chatId: string, senderId: string, text: string) => {
  const allMessages = getStore(MESSAGES_KEY);
  const newMessage = {
    id: 'msg_' + Date.now(),
    chat_id: chatId,
    sender_id: senderId,
    content: text,
    created_at: new Date().toISOString(),
    is_action_item: false // In real app, AI could run on backend
  };

  allMessages.push(newMessage);
  setStore(MESSAGES_KEY, allMessages);

  // Emit Realtime Event
  broadcast.postMessage({
    type: 'INSERT',
    table: 'messages',
    new: newMessage
  });

  return { data: [newMessage], error: null };
};

export const searchUsers = async (query: string) => {
  await delay(300);
  const users = getStore(USERS_KEY);
  const q = query.toLowerCase();

  return users.filter((u: any) => 
    u.full_name.toLowerCase().includes(q) || 
    u.email.toLowerCase().includes(q) ||
    (u.phone && u.phone.includes(q)) // Search by phone number
  ).slice(0, 5); // Limit results
};

export const createGhostUser = async (identifier: string) => {
  const users = getStore(USERS_KEY);
  const isEmail = identifier.includes('@');

  // Create a placeholder user
  const newUser = {
    id: 'u_' + Date.now(),
    email: isEmail ? identifier : '',
    phone: !isEmail ? identifier : '',
    full_name: isEmail ? identifier.split('@')[0] : identifier,
    password: '123', 
    is_ghost: true 
  };

  users.push(newUser);
  setStore(USERS_KEY, users);
  return newUser;
};

export const createNewChat = async (currentUserId: string, otherUserId: string, otherUserName: string) => {
  const chats = getStore(CHATS_KEY);
  const participants = getStore(PARTICIPANTS_KEY);

  // Create Chat
  const newChat = {
    id: 'c_' + Date.now(),
    name: otherUserName,
    is_group: false,
    created_at: new Date().toISOString()
  };
  chats.push(newChat);
  setStore(CHATS_KEY, chats);

  // Add Participants
  participants.push({ chat_id: newChat.id, user_id: currentUserId });
  participants.push({ chat_id: newChat.id, user_id: otherUserId });
  setStore(PARTICIPANTS_KEY, participants);

  return newChat;
};

// --- TYPING INDICATOR REALTIME HELPERS ---
export const sendTypingEvent = (chatId: string, userId: string, isTyping: boolean) => {
  broadcast.postMessage({
    type: 'TYPING',
    chatId,
    userId,
    isTyping
  });
};

export const subscribeToTypingEvents = (chatId: string, callback: (userId: string, isTyping: boolean) => void) => {
  const handler = (event: MessageEvent) => {
    const data = event.data;
    if (data.type === 'TYPING' && data.chatId === chatId) {
      callback(data.userId, data.isTyping);
    }
  };
  broadcast.addEventListener('message', handler);
  return () => broadcast.removeEventListener('message', handler);
};

