export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [currentUserId, setCurrentUserId] = useState<string>('');

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    getCurrentUser().then(u => u && setCurrentUserId(u.id));
  }, []);

  useEffect(() => {
    scrollToBottom();
    setSummary(null);
    setTypingUsers(new Set()); // Reset typing status on chat change

    // Subscribe to typing events for this chat
    const unsubscribe = subscribeToTypingEvents(chat.id, (userId, isTyping) => {
      // Don't show typing for self
      if (userId === currentUserId) return;

      setTypingUsers(prev => {
        const next = new Set(prev);
        if (isTyping) {
          next.add(userId);
        } else {
          next.delete(userId);
        }
        return next;
      });
      // Scroll to show indicator if at bottom
      setTimeout(scrollToBottom, 100);
    });

    return () => {
      unsubscribe();
    };
  }, [chat.id, currentUserId]);

  // Effect to auto-scroll when messages change
  useEffect(() => {
    scrollToBottom();
  }, [chat.messages]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputText(e.target.value);

    if (currentUserId) {
      // Broadcast "I am typing"
      sendTypingEvent(chat.id, currentUserId, true);

      // Clear existing timeout
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);

      // Set timeout to stop typing after 2 seconds of inactivity
      typingTimeoutRef.current = setTimeout(() => {
        sendTypingEvent(chat.id, currentUserId, false);
      }, 2000);
    }
  };

  const handleSend = () => {
    if (!inputText.trim()) return;

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }

    onSendMessage(inputText);
    setInputText('');
  };

  const handleCatchMeUp = async () => {
    setIsSummarizing(true);
    const result = await summarizeChat(chat.messages);
    setSummary(result);
    setIsSummarizing(false);
  };

  const isSomeoneTyping = typingUsers.size > 0;

  return (
    <div className="flex flex-col h-full w-full bg-[#f2f4f7] dark:bg-[#0b141a] relative">

      {/* HEADER */}
      <div className="flex items-center justify-between px-4 py-3 bg-white/80 dark:bg-nexus-card/90 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800 sticky top-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full md:hidden text-nexus-primary transition-colors">
            <ArrowLeft size={24} />
          </button>

          <div className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity">
            <div className="relative">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold shadow-sm ${chat.isGroup ? 'bg-gradient-to-tr from-nexus-primary to-nexus-accent' : 'bg-gradient-to-tr from-gray-400 to-gray-500'}`}>
                {chat.name[0]}
              </div>
              <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white dark:border-nexus-card"></div>
            </div>
            <div>
              <h3 className="font-bold text-base dark:text-white leading-tight">{chat.name}</h3>
              <p className="text-xs text-nexus-primary font-medium">
                {isSomeoneTyping ? 'Typing...' : 'Online'}
              </p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
           <button className="p-2 text-nexus-primary bg-nexus-primary/5 hover:bg-nexus-primary/10 rounded-full transition-colors hidden sm:block">
             <Phone size={20} />
           </button>
           <button className="p-2 text-nexus-primary bg-nexus-primary/5 hover:bg-nexus-primary/10 rounded-full transition-colors hidden sm:block">
             <Video size={20} />
           </button>

           {chat.isGroup && (
            <button 
              onClick={handleCatchMeUp}
              disabled={isSummarizing}
              className="flex items-center gap-1.5 px-3 py-1.5 bg-gradient-to-r from-nexus-accent to-purple-600 text-white rounded-full text-xs font-bold shadow-lg shadow-purple-500/20 hover:shadow-purple-500/40 transition-all transform hover:scale-105"
            >
              <Sparkles size={14} className={isSummarizing ? "animate-spin" : ""} />
              {isSummarizing ? 'Thinking...' : 'Catch Me Up'}
            </button>
           )}

           <button className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
             <MoreVertical size={20} />
           </button>
        </div>
      </div>

      {/* SUMMARY CARD */}
      {summary && (
        <div className="mx-4 mt-4 p-4 bg-gradient-to-r from-nexus-accent/10 to-nexus-primary/10 border border-nexus-accent/20 rounded-2xl animate-fade-in-down">
          <div className="flex items-start gap-3">
            <div className="p-2 bg-white dark:bg-nexus-card rounded-lg shadow-sm text-nexus-accent">
               <Sparkles size={18} />
            </div>
            <div>
              <h4 className="text-xs font-bold uppercase text-nexus-accent mb-1 tracking-wider">AI Summary</h4>
              <p className="text-sm text-gray-700 dark:text-gray-200 leading-relaxed">{summary}</p>
            </div>
            <button onClick={() => setSummary(null)} className="ml-auto text-gray-400 hover:text-gray-600">×</button>
          </div>
        </div>
      )}

      {/* MESSAGES AREA */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 sm:p-6 no-scrollbar">
        {chat.messages.map((msg, idx) => {
          const isMe = msg.senderId === 'me';
          const showAvatar = !isMe && (idx === 0 || chat.messages[idx - 1].senderId !== msg.senderId);

          return (
            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} group`}>
               {!isMe && (
                 <div className={`w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-1 ${showAvatar ? 'opacity-100' : 'opacity-0'}`}>
                   {chat.name[0]}
                 </div>
               )}

               <div className={`max-w-[75%] md:max-w-[60%] relative shadow-sm ${
                 isMe 
                  ? 'bg-nexus-primary text-white rounded-2xl rounded-tr-sm' 
                  : 'bg-white dark:bg-nexus-card dark:text-gray-100 rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800'
               }`}>
                  <div className="px-4 py-2 text-[15px] leading-relaxed whitespace-pre-wrap">
                    {msg.text}
                  </div>
                  <div className={`px-2 pb-1 flex justify-end items-center gap-1 text-[10px] ${isMe ? 'text-blue-100' : 'text-gray-400'}`}>
                    <span>{new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                    {isMe && <CheckCheck size={14} className="text-blue-200" />}
                  </div>
               </div>
            </div>
          );
        })}

        {/* TYPING INDICATOR BUBBLE */}
        {isSomeoneTyping && (
          <div className="flex justify-start animate-fade-in-up">
            <div className="w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-1 opacity-100">
              {chat.name[0]}
            </div>
            <div className="bg-white dark:bg-nexus-card rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800 px-4 py-3 shadow-sm">
              <div className="flex items-center gap-1 h-3">
                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
              </div>
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* INPUT AREA */}
      <div className="p-3 sm:p-4 bg-white dark:bg-nexus-dark border-t border-gray-100 dark:border-gray-800">
        <div className="flex items-center gap-2 max-w-4xl mx-auto bg-gray-100 dark:bg-gray-800/80 p-1.5 rounded-[24px] border border-transparent focus-within:border-nexus-primary/30 focus-within:ring-2 focus-within:ring-nexus-primary/10 transition-all">
          <button className="p-2.5 text-gray-500 hover:text-nexus-primary hover:bg-white dark:hover:bg-gray-700 rounded-full transition-colors">
            <Paperclip size={20} />
          </button>

          <input
            type="text"
            value={inputText}
            onChange={handleInputChange}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type a message..."
            className="flex-1 bg-transparent border-none outline-none text-gray-800 dark:text-white placeholder-gray-500 px-2 py-2"
          />

          <button 
            onClick={handleSend}
            disabled={!inputText.trim()}
            className={`p-3 rounded-full transition-all duration-300 transform ${
              inputText.trim() 
                ? 'bg-nexus-primary text-white shadow-lg hover:scale-105 active:scale-95' 
                : 'bg-gray-200 dark:bg-gray-700 text-gray-400'
            }`}
          >
            <Send size={18} className={inputText.trim() ? "translate-x-0.5" : ""} />
          </button>
        </div>
      </div>
    </div>
  );
};

export interface User {
  id: string;
  name: string;
  avatar: string;
}

export interface Message {
  id: string;
  senderId: string;
  text: string;
  timestamp: Date;
  isActionItem?: boolean;
  reactions?: Record<string, string[]>; // emoji -> array of user IDs
}

export interface Chat {
  id: string;
  name: string;
  isGroup: boolean;
  priority: 'high' | 'normal';
  unreadCount: number;
  participants: User[];
  messages: Message[];
  lastMessage?: string;
  lastMessageTime?: Date;
  created_at?: string;
}

export interface ActionItem {
  id: string;
  sourceMessageId: string;
  chatId: string;
  title: string; // Extracted action
  dueDateTime: string; // Extracted date/time
  isCompleted: boolean;
}

export type TabType = 'priority' | 'groups' | 'actions';

// --- MOCK SUPABASE CLIENT ---
// This allows the app to function fully in the browser without a real backend.
// It uses localStorage for the DB and BroadcastChannel for Realtime events.

const USERS_KEY = 'nexus_users';
const CHATS_KEY = 'nexus_chats';
const MESSAGES_KEY = 'nexus_messages';
const SESSION_KEY = 'nexus_session';
const PARTICIPANTS_KEY = 'nexus_chat_participants';

const broadcast = new BroadcastChannel('nexus_realtime');

// --- SEED DATA ---
const seedData = () => {
  if (!localStorage.getItem(USERS_KEY)) {
    const mockUsers = [
      { id: 'u1', email: 'sarah@nexus.com', phone: '5550101', full_name: 'Sarah Jen', password: '123' },
      { id: 'u2', email: 'mike@nexus.com', phone: '5550102', full_name: 'Mike Ross', password: '123' },
      { id: 'u3', email: 'dev@nexus.com', phone: '5550103', full_name: 'Dev Team', password: '123' },
    ];
    localStorage.setItem(USERS_KEY, JSON.stringify(mockUsers));
  }
};
seedData();

// --- HELPERS ---
const getStore = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const setStore = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// --- MOCK SUPABASE OBJECT ---
export const supabase = {
  auth: {
    getSession: async () => {
      const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
      return { data: { session: sessionUser ? { user: sessionUser } : null }, error: null };
    },
    signInWithPassword: async ({ email, password }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      // Allow login via Email OR Phone if we wanted, but sticking to email for credential simplicity
      // For now, keeping email as the unique login identifier
      const user = users.find((u: any) => u.email === email && u.password === password);
      if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        // Notify other tabs or components
        window.dispatchEvent(new Event('storage')); 
        return { data: { user, session: { user } }, error: null };
      }
      return { data: null, error: { message: 'Invalid credentials' } };
    },
    signUp: async ({ email, password, options }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      if (users.find((u: any) => u.email === email)) {
        return { data: null, error: { message: 'User already exists' } };
      }
      const newUser = {
        id: 'u_' + Date.now(),
        email,
        password,
        phone: options?.data?.phone || '',
        full_name: options?.data?.full_name || email.split('@')[0]
      };
      users.push(newUser);
      setStore(USERS_KEY, users);
      localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
      return { data: { user: newUser, session: { user: newUser } }, error: null };
    },
    signOut: async () => {
      localStorage.removeItem(SESSION_KEY);
      return { error: null };
    },
    onAuthStateChange: (callback: any) => {
      // Simple subscription
      const handler = () => {
        const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
        callback('SIGNED_IN', sessionUser ? { user: sessionUser } : null);
      };
      window.addEventListener('storage', handler);
      return { data: { subscription: { unsubscribe: () => window.removeEventListener('storage', handler) } } };
    }
  },
  channel: (channelName: string) => {
    return {
      on: (type: string, filter: any, callback: any) => {
        const handler = (event: MessageEvent) => {
          const { table, new: record, type: eventType } = event.data;
          // Filter logic for realtime events
          if (type === 'postgres_changes' && 
              filter.event === eventType && 
              filter.table === table) {

             // Check custom filter string (e.g. "chat_id=eq.123")
             if (filter.filter) {
               const [key, val] = filter.filter.split('=eq.');
               if (String(record[key]) !== String(val)) return;
             }
             callback({ new: record });
          } else if (type === 'postgres_changes' && filter.event === '*') {
             // Handle wildcard event listener
             if (filter.table === table) {
               if (filter.filter) {
                 const [key, val] = filter.filter.split('=eq.');
                 if (String(record[key]) !== String(val)) return;
               }
               callback({ new: record, eventType });
             }
          }
        };
        broadcast.addEventListener('message', handler);
        return {
          subscribe: () => {} // Mock subscribe
        };
      }
    };
  },
  removeChannel: (channel: any) => {
    // Clean up if needed (broadcast listeners usually persistent in this simple mock)
  }
};

// --- SERVICE FUNCTIONS ---

export const getCurrentUser = async () => {
  const { data } = await supabase.auth.getSession();
  return data.session?.user || null;
};

export const fetchUserChats = async (userId: string) => {
  await delay(200);
  const participants = getStore(PARTICIPANTS_KEY);
  const allChats = getStore(CHATS_KEY);
  const allUsers = getStore(USERS_KEY);

  const myChatIds = participants
    .filter((p: any) => p.user_id === userId)
    .map((p: any) => p.chat_id);

  return allChats
    .filter((c: any) => myChatIds.includes(c.id))
    .map((c: any) => {
      // Find other participants for this chat
      const chatParticipants = participants
        .filter((p: any) => p.chat_id === c.id)
        .map((p: any) => {
           const u = allUsers.find((user: any) => user.id === p.user_id);
           return u ? { id: u.id, name: u.full_name, avatar: '' } : null;
        })
        .filter(Boolean);

      return {
        ...c,
        isGroup: c.is_group,
        unreadCount: 0,
        participants: chatParticipants,
        messages: []
      };
    });
};

export const fetchMessages = async (chatId: string) => {
  await delay(200);
  const allMessages = getStore(MESSAGES_KEY);
  return allMessages
    .filter((m: any) => m.chat_id === chatId)
    .sort((a: any, b: any) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
    .map((m: any) => ({
      id: m.id,
      senderId: m.sender_id, // Return camelCase for UI, but internal is snake_case
      text: m.content,
      timestamp: new Date(m.created_at),
      isActionItem: m.is_action_item,
      reactions: m.reactions || {}
    }));
};

export const sendMessageToDb = async (chatId: string, senderId: string, text: string) => {
  const allMessages = getStore(MESSAGES_KEY);
  const newMessage = {
    id: 'msg_' + Date.now(),
    chat_id: chatId,
    sender_id: senderId,
    content: text,
    created_at: new Date().toISOString(),
    is_action_item: false,
    reactions: {}
  };

  allMessages.push(newMessage);
  setStore(MESSAGES_KEY, allMessages);

  // Emit Realtime Event
  broadcast.postMessage({
    type: 'INSERT',
    table: 'messages',
    new: newMessage
  });

  return { data: [newMessage], error: null };
};

export const toggleReaction = async (chatId: string, messageId: string, userId: string, emoji: string) => {
  const allMessages = getStore(MESSAGES_KEY);
  const msgIndex = allMessages.findIndex((m: any) => m.id === messageId);

  if (msgIndex === -1) return;

  const msg = allMessages[msgIndex];
  if (!msg.reactions) msg.reactions = {};

  const userList = msg.reactions[emoji] || [];
  if (userList.includes(userId)) {
    // Remove reaction
    msg.reactions[emoji] = userList.filter((id: string) => id !== userId);
    if (msg.reactions[emoji].length === 0) delete msg.reactions[emoji];
  } else {
    // Add reaction
    msg.reactions[emoji] = [...userList, userId];
  }

  allMessages[msgIndex] = msg;
  setStore(MESSAGES_KEY, allMessages);

  // Emit Realtime Event
  broadcast.postMessage({
    type: 'UPDATE',
    table: 'messages',
    new: msg
  });
};

export const searchUsers = async (query: string) => {
  await delay(300);
  const users = getStore(USERS_KEY);
  const q = query.toLowerCase();

  return users.filter((u: any) => 
    u.full_name.toLowerCase().includes(q) || 
    u.email.toLowerCase().includes(q) ||
    (u.phone && u.phone.includes(q)) // Search by phone number
  ).slice(0, 5); // Limit results
};

export const createGhostUser = async (identifier: string) => {
  const users = getStore(USERS_KEY);
  const isEmail = identifier.includes('@');

  // Create a placeholder user
  const newUser = {
    id: 'u_' + Date.now(),
    email: isEmail ? identifier : '',
    phone: !isEmail ? identifier : '',
    full_name: isEmail ? identifier.split('@')[0] : identifier,
    password: '123', 
    is_ghost: true 
  };

  users.push(newUser);
  setStore(USERS_KEY, users);
  return newUser;
};

export const createNewChat = async (currentUserId: string, otherUserId: string, otherUserName: string) => {
  const chats = getStore(CHATS_KEY);
  const participants = getStore(PARTICIPANTS_KEY);

  // Create Chat
  const newChat = {
    id: 'c_' + Date.now(),
    name: otherUserName,
    is_group: false,
    created_at: new Date().toISOString()
  };
  chats.push(newChat);
  setStore(CHATS_KEY, chats);

  // Add Participants
  participants.push({ chat_id: newChat.id, user_id: currentUserId });
  participants.push({ chat_id: newChat.id, user_id: otherUserId });
  setStore(PARTICIPANTS_KEY, participants);

  return newChat;
};

// --- TYPING INDICATOR REALTIME HELPERS ---
export const sendTypingEvent = (chatId: string, userId: string, isTyping: boolean) => {
  broadcast.postMessage({
    type: 'TYPING',
    chatId,
    userId,
    isTyping
  });
};

export const subscribeToTypingEvents = (chatId: string, callback: (userId: string, isTyping: boolean) => void) => {
  const handler = (event: MessageEvent) => {
    const data = event.data;
    if (data.type === 'TYPING' && data.chatId === chatId) {
      callback(data.userId, data.isTyping);
    }
  };
  broadcast.addEventListener('message', handler);
  return () => broadcast.removeEventListener('message', handler);
};

