              {muted ? <BellOff size={20} /> : <Bell size={20} />}
              <span>Mute Notifications</span>
            </div>
            <div className={`w-10 h-5 rounded-full relative transition-colors ${muted ? 'bg-nexus-primary' : 'bg-gray-300 dark:bg-gray-600'}`}>
               <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${muted ? 'left-6' : 'left-1'}`}></div>
            </div>
          </button>
        </div>

        {/* Participants */}
        <div className="mb-8">
           <div className="flex items-center justify-between mb-3">
             <h4 className="text-xs font-bold text-gray-400 uppercase">Participants ({displayParticipants.length})</h4>
