import React, { useState, useEffect } from 'react';
import { X, Send, Search } from 'lucide-react';
import { Chat } from '../types';
import { fetchUserChats, getCurrentUser, sendMessageToDb } from '../services/supabaseClient';

interface ForwardModalProps {
  messageText: string;
  onClose: () => void;
  onForwardSuccess: () => void;
}

export const ForwardModal: React.FC<ForwardModalProps> = ({ messageText, onClose, onForwardSuccess }) => {
  const [chats, setChats] = useState<Chat[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentUserId, setCurrentUserId] = useState('');
  const [sendingTo, setSendingTo] = useState<string | null>(null);

  useEffect(() => {
    const load = async () => {
      const user = await getCurrentUser();
      if (user) {
        setCurrentUserId(user.id);
        const myChats = await fetchUserChats(user.id);
        setChats(myChats);
      }
      setLoading(false);
    };
    load();
  }, []);

  const handleForward = async (chatId: string) => {
    if (sendingTo) return;
    setSendingTo(chatId);
    try {
      await sendMessageToDb(chatId, currentUserId, messageText);
      onForwardSuccess();
    } catch (e) {
      console.error(e);
      setSendingTo(null);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white dark:bg-nexus-card w-full max-w-md rounded-2xl shadow-2xl border dark:border-gray-700 flex flex-col max-h-[80vh]">
        <div className="p-4 border-b dark:border-gray-700 flex justify-between items-center bg-white dark:bg-nexus-card rounded-t-2xl">
          <h2 className="font-bold text-lg dark:text-white">Forward Message</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <X size={20} className="dark:text-gray-400" />
          </button>
        </div>

        <div className="p-3 bg-gray-50 dark:bg-gray-900 border-b dark:border-gray-800">
           <div className="text-xs font-bold text-gray-400 mb-1 uppercase">Message Preview</div>
           <div className="bg-white dark:bg-gray-800 p-3 rounded-lg text-sm text-gray-700 dark:text-gray-300 italic truncate border dark:border-gray-700">
             "{messageText}"
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2">
           {loading ? (
             <div className="text-center py-8 text-gray-400">Loading chats...</div>
           ) : (
             <div className="space-y-1">
               {chats.map(chat => (
                 <button 
                   key={chat.id}
                   disabled={!!sendingTo}
                   onClick={() => handleForward(chat.id)}
                   className="w-full flex items-center justify-between p-3 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl transition-colors group text-left"
                 >
                   <div className="flex items-center gap-3 overflow-hidden">
                     <div className="w-10 h-10 rounded-full bg-nexus-primary/20 text-nexus-primary flex-shrink-0 flex items-center justify-center font-bold">
                       {chat.name[0]}
                     </div>
                     <span className="font-medium dark:text-white truncate">{chat.name}</span>
                   </div>

                   <div className={`px-4 py-1.5 rounded-full text-xs font-bold flex items-center gap-1 transition-all ${
                     sendingTo === chat.id 
                       ? 'bg-nexus-success text-white' 
                       : 'bg-nexus-primary/10 text-nexus-primary group-hover:bg-nexus-primary group-hover:text-white'
                   }`}>
                     {sendingTo === chat.id ? 'Sent!' : 'Send'}
                     {sendingTo !== chat.id && <Send size={12} />}
                   </div>
                 </button>
               ))}
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Chat, Message } from '../types';
import { Send, ArrowLeft, Sparkles, MoreVertical, Paperclip, CheckCheck, Phone, Video, Smile, Share, CornerUpRight } from 'lucide-react';
import { summarizeChat } from '../services/geminiService';
import { sendTypingEvent, subscribeToTypingEvents, getCurrentUser, toggleReaction } from '../services/supabaseClient';
import { ChatInfoSidebar } from './ChatInfoSidebar';
import { ForwardModal } from './ForwardModal';

interface ChatInterfaceProps {
  chat: Chat;
  onBack: () => void;
  onSendMessage: (text: string) => void;
}

const REACTION_EMOJIS = ['👍', '❤️', '😂', '😮', '😢', '🔥'];

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [currentUserId, setCurrentUserId] = useState<string>('');

  // New State
  const [showInfoSidebar, setShowInfoSidebar] = useState(false);
  const [forwardingMessage, setForwardingMessage] = useState<string | null>(null);
  const [activeReactionMessageId, setActiveReactionMessageId] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    getCurrentUser().then(u => u && setCurrentUserId(u.id));
  }, []);

  useEffect(() => {
    scrollToBottom();
    setSummary(null);
    setShowInfoSidebar(false);
    setTypingUsers(new Set()); 

    const unsubscribe = subscribeToTypingEvents(chat.id, (userId, isTyping) => {
      if (userId === currentUserId) return;

      setTypingUsers(prev => {
        const next = new Set(prev);
        if (isTyping) {
          next.add(userId);
        } else {
          next.delete(userId);
        }
        return next;
      });
      setTimeout(scrollToBottom, 100);
    });

    return () => {
      unsubscribe();
    };
  }, [chat.id, currentUserId]);

  useEffect(() => {
    scrollToBottom();
  }, [chat.messages]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputText(e.target.value);

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, true);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        sendTypingEvent(chat.id, currentUserId, false);
      }, 2000);
    }
  };

  const handleSend = () => {
    if (!inputText.trim()) return;
    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }
    onSendMessage(inputText);
    setInputText('');
  };

  const handleCatchMeUp = async () => {
    setIsSummarizing(true);
    const result = await summarizeChat(chat.messages);
    setSummary(result);
    setIsSummarizing(false);
  };

  const onReactionClick = async (msgId: string, emoji: string) => {
    await toggleReaction(chat.id, msgId, currentUserId, emoji);
    setActiveReactionMessageId(null);
  };

  const isSomeoneTyping = typingUsers.size > 0;

  return (
    <div className="flex flex-row h-full w-full overflow-hidden relative">
      <div className="flex-1 flex flex-col h-full bg-[#f2f4f7] dark:bg-[#0b141a] relative min-w-0">

        {/* HEADER */}
        <div className="flex items-center justify-between px-4 py-3 bg-white/80 dark:bg-nexus-card/90 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800 sticky top-0 z-20 shadow-sm">
          <div className="flex items-center gap-3">
            <button onClick={onBack} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full md:hidden text-nexus-primary transition-colors">
              <ArrowLeft size={24} />
            </button>

            <div className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => setShowInfoSidebar(!showInfoSidebar)}>
              <div className="relative">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold shadow-sm ${chat.isGroup ? 'bg-gradient-to-tr from-nexus-primary to-nexus-accent' : 'bg-gradient-to-tr from-gray-400 to-gray-500'}`}>
                  {chat.name[0]}
                </div>
                <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white dark:border-nexus-card"></div>
              </div>
              <div>
                <h3 className="font-bold text-base dark:text-white leading-tight">{chat.name}</h3>
                <p className="text-xs text-nexus-primary font-medium">
                  {isSomeoneTyping ? 'Typing...' : 'Online'}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 md:gap-2">
            <button className="p-2 text-nexus-primary bg-nexus-primary/5 hover:bg-nexus-primary/10 rounded-full transition-colors hidden sm:block">
              <Phone size={20} />
            </button>
            <button className="p-2 text-nexus-primary bg-nexus-primary/5 hover:bg-nexus-primary/10 rounded-full transition-colors hidden sm:block">
              <Video size={20} />
            </button>

            {chat.isGroup && (
              <button 
                onClick={handleCatchMeUp}
                disabled={isSummarizing}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-gradient-to-r from-nexus-accent to-purple-600 text-white rounded-full text-xs font-bold shadow-lg shadow-purple-500/20 hover:shadow-purple-500/40 transition-all transform hover:scale-105"
              >
                <Sparkles size={14} className={isSummarizing ? "animate-spin" : ""} />
                {isSummarizing ? 'Thinking...' : 'Catch Me Up'}
              </button>
            )}

            <button 
              onClick={() => setShowInfoSidebar(!showInfoSidebar)}
              className={`p-2 rounded-full transition-colors ${showInfoSidebar ? 'bg-nexus-primary text-white' : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700'}`}
            >
              <MoreVertical size={20} />
            </button>
          </div>
        </div>

        {/* SUMMARY CARD */}
        {summary && (
          <div className="mx-4 mt-4 p-4 bg-gradient-to-r from-nexus-accent/10 to-nexus-primary/10 border border-nexus-accent/20 rounded-2xl animate-fade-in-down">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-white dark:bg-nexus-card rounded-lg shadow-sm text-nexus-accent">
                <Sparkles size={18} />
              </div>
              <div>
                <h4 className="text-xs font-bold uppercase text-nexus-accent mb-1 tracking-wider">AI Summary</h4>
                <p className="text-sm text-gray-700 dark:text-gray-200 leading-relaxed">{summary}</p>
              </div>
              <button onClick={() => setSummary(null)} className="ml-auto text-gray-400 hover:text-gray-600">×</button>
            </div>
          </div>
        )}

        {/* MESSAGES AREA */}
        <div 
          className="flex-1 overflow-y-auto p-4 space-y-4 sm:p-6 no-scrollbar"
          onClick={() => setActiveReactionMessageId(null)}
        >
          {chat.messages.map((msg, idx) => {
            const isMe = msg.senderId === 'me';
            const showAvatar = !isMe && (idx === 0 || chat.messages[idx - 1].senderId !== msg.senderId);

            return (
              <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} group relative mb-2`}>
                <div className={`flex ${isMe ? 'justify-end' : 'justify-start'} max-w-full`}>
                  {!isMe && (
                    <div className={`w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-6 ${showAvatar ? 'opacity-100' : 'opacity-0'}`}>
                      {chat.name[0]}
                    </div>
                  )}

                  <div className="relative group/bubble">
                    {/* Message Bubble */}
                    <div className={`relative shadow-sm max-w-[85vw] md:max-w-[500px] ${
                      isMe 
                        ? 'bg-nexus-primary text-white rounded-2xl rounded-tr-sm' 
                        : 'bg-white dark:bg-nexus-card dark:text-gray-100 rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800'
                    }`}>
                        <div className="px-4 py-2 text-[15px] leading-relaxed whitespace-pre-wrap break-words">
                          {msg.text}
                        </div>
                        <div className={`px-2 pb-1 flex justify-end items-center gap-1 text-[10px] ${isMe ? 'text-blue-100' : 'text-gray-400'}`}>
                          <span>{new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                          {isMe && <CheckCheck size={14} className="text-blue-200" />}
                        </div>
                    </div>

                    {/* Reactions Display */}
                    {msg.reactions && Object.keys(msg.reactions).length > 0 && (
                      <div className={`absolute -bottom-3 ${isMe ? 'right-0' : 'left-0'} flex gap-1 z-10`}>
                        {Object.entries(msg.reactions).map(([emoji, users]) => (
                          <div key={emoji} className="bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-full px-1.5 py-0.5 text-[10px] shadow-sm flex items-center gap-0.5 scale-90">
                            <span>{emoji}</span>
                            {users.length > 1 && <span className="text-gray-500 font-bold">{users.length}</span>}
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Action Buttons (Hover) */}
                    <div className={`absolute -top-8 ${isMe ? 'right-0' : 'left-0'} flex items-center gap-1 opacity-0 group-hover/bubble:opacity-100 transition-opacity bg-white/90 dark:bg-gray-800/90 rounded-full px-2 py-1 shadow-sm backdrop-blur-sm`}>
                       <button 
                         onClick={(e) => { e.stopPropagation(); setActiveReactionMessageId(activeReactionMessageId === msg.id ? null : msg.id); }}
                         className="p-1.5 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-gray-500"
                         title="Add Reaction"
                       >
                         <Smile size={14} />
                       </button>
                       <button 
                         onClick={(e) => { e.stopPropagation(); setForwardingMessage(msg.text); }}
                         className="p-1.5 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-gray-500"
                         title="Forward Message"
                       >
                         <Share size={14} />
                       </button>
                    </div>

                    {/* Reaction Picker Popover */}
                    {activeReactionMessageId === msg.id && (
                      <div className={`absolute -top-12 ${isMe ? 'right-0' : 'left-0'} bg-white dark:bg-nexus-card shadow-xl rounded-full p-1 flex gap-1 animate-fade-in-up z-20 border dark:border-gray-700`}>
                        {REACTION_EMOJIS.map(emoji => (
                          <button
                            key={emoji}
                            onClick={(e) => { e.stopPropagation(); onReactionClick(msg.id, emoji); }}
                            className="w-8 h-8 flex items-center justify-center hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-lg transition-transform hover:scale-125"
                          >
                            {emoji}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}

          {/* TYPING INDICATOR */}
          {isSomeoneTyping && (
            <div className="flex justify-start animate-fade-in-up">
              <div className="w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-1 opacity-100">
                {chat.name[0]}
              </div>
              <div className="bg-white dark:bg-nexus-card rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800 px-4 py-3 shadow-sm">
                <div className="flex items-center gap-1 h-3">
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                </div>
