            <input
              type="text"
              value={inputText}
              onChange={handleInputChange}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type a message..."
              className="flex-1 bg-transparent border-none outline-none text-gray-800 dark:text-white placeholder-gray-500 px-2 py-2"
            />

            <button 
              onClick={handleSend}
              disabled={!inputText.trim()}
              className={`p-3 rounded-full transition-all duration-300 transform ${
                inputText.trim() 
                  ? 'bg-nexus-primary text-white shadow-lg hover:scale-105 active:scale-95' 
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-400'
              }`}
            >
              <Send size={18} className={inputText.trim() ? "translate-x-0.5" : ""} />
            </button>
          </div>
        </div>
      </div>

      {/* RIGHT SIDEBAR (SLIDEOUT) */}
      {showInfoSidebar && (
        <ChatInfoSidebar 
          chat={chat} 
          onClose={() => setShowInfoSidebar(false)} 
          onLeave={() => {
            // Mock leave logic
            setShowInfoSidebar(false);
            onBack();
          }}
        />
      )}

      {/* FORWARD MODAL */}
      {forwardingMessage && (
        <ForwardModal 
          messageText={forwardingMessage} 
          onClose={() => setForwardingMessage(null)}
          onForwardSuccess={() => {
             setForwardingMessage(null);
             // Optional: Show toast
          }}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType } from './types';
import { detectActionItem } from './services/geminiService';
import { supabase, getCurrentUser, fetchUserChats, fetchMessages, sendMessageToDb } from './services/supabaseClient';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { AuthScreen } from './components/AuthScreen';
import { NewChatModal } from './components/NewChatModal';
import { 
  Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare, Plus, LogOut,
  Users
} from 'lucide-react';

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
  const [showNewChatModal, setShowNewChatModal] = useState(false);

  const [chats, setChats] = useState<Chat[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);

  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages (INSERT) and updates (UPDATE - for reactions)
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {

          if (payload.eventType === 'INSERT') {
            const newMsg = payload.new;
            if (newMsg.sender_id === session.user.id) return; // Skip own inserts if handled optimistically

            const formattedMsg: Message = {
              id: newMsg.id,
              senderId: newMsg.sender_id,
              text: newMsg.content,
              timestamp: new Date(newMsg.created_at),
              isActionItem: newMsg.is_action_item,
              reactions: newMsg.reactions
            };

            setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return { ...c, messages: [...c.messages, formattedMsg] };
               }
               return c;
            }));
          } 
          else if (payload.eventType === 'UPDATE') {
             const updatedMsg = payload.new;
             setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return {
                   ...c,
                   messages: c.messages.map(m => m.id === updatedMsg.id ? {
                     ...m,
                     reactions: updatedMsg.reactions
                   } : m)
                 };
               }
               return c;
             }));
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date()
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text);

    // AI Analysis (Local for now, could be server-side function)
    const analysis = await detectActionItem(text);
    if (analysis.isAction) {
      const newAction: ActionItem = {
        id: Date.now().toString() + '_action',
        chatId: selectedChatId,
        sourceMessageId: tempId,
        title: analysis.title || 'New Reminder',
        dueDateTime: analysis.dateTime || 'Unspecified time',
        isCompleted: false
      };
      setActionItems(prev => [newAction, ...prev]);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const getFilteredChats = () => {
    if (!chats) return [];
    switch (activeTab) {
      case 'priority':
        return chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
      case 'groups':
        return chats.filter(c => c.isGroup);
      default:
        return chats;
    }
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-gray-50 dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-primary"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden bg-white dark:bg-nexus-dark ${darkMode ? 'dark' : ''}`}>
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* === SIDEBAR / MOBILE LIST VIEW === */}
        <div className={`
          flex flex-col h-full bg-white dark:bg-nexus-dark border-r dark:border-gray-800 transition-all duration-300
          w-full md:w-[380px] lg:w-[420px] 
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* HEADER */}
          <div className="px-6 py-5 flex justify-between items-center bg-white dark:bg-nexus-dark z-10 sticky top-0">
            <h1 className="text-2xl font-bold tracking-tight dark:text-white flex items-center gap-2">
              <span className="w-8 h-8 bg-gradient-to-br from-nexus-primary to-blue-600 rounded-xl flex items-center justify-center text-white text-lg shadow-blue-500/30 shadow-lg">N</span>
              <span>Nexus</span>
            </h1>
            <div className="flex items-center gap-1">
              <button onClick={() => setShowNewChatModal(true)} className="p-2.5 text-nexus-primary hover:bg-nexus-primary/10 rounded-full transition-colors">
                <Plus size={22} />
              </button>
              <button onClick={() => setDarkMode(!darkMode)} className="p-2.5 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                {darkMode ? <Sun size={22} /> : <Moon size={22} />}
              </button>
              <button onClick={handleLogout} className="p-2.5 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors">
                <LogOut size={22} />
              </button>
            </div>
          </div>

          {/* SEARCH */}
          <div className="px-6 pb-4">
            <div className="bg-gray-100 dark:bg-gray-800/50 rounded-2xl flex items-center px-4 py-3 transition-all focus-within:ring-2 focus-within:ring-nexus-primary/50">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text" 
                placeholder="Search conversations..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
          </div>

          {/* DESKTOP TABS (Hidden on Mobile) */}
          <div className="hidden md:flex px-6 space-x-6 border-b dark:border-gray-800 mb-2">
             <button onClick={() => setActiveTab('priority')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'priority' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'groups' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'actions' ? 'border-nexus-primary text-nexus-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Actions
             </button>
          </div>

          {/* SCROLLABLE LIST AREA */}
          <div className="flex-1 overflow-y-auto px-4 pb-24 md:pb-4 space-y-2 no-scrollbar">
            {activeTab === 'actions' ? (
              <div className="space-y-3 pt-2">
                 {actionItems.length === 0 && (
                   <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                     <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                       <CheckSquare size={32} className="opacity-40" />
                     </div>
                     <p>All caught up! No pending actions.</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <div className="space-y-1 pt-2">
                 {getFilteredChats().length === 0 && (
                   <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center">
                     <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                       <MessageSquare size={32} className="opacity-40" />
                     </div>
                     <span>No chats in {activeTab}.</span>
                     <button onClick={() => setShowNewChatModal(true)} className="mt-2 text-nexus-primary font-bold">Start a chat</button>
                   </div>
                 )}
                 {getFilteredChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
                       onClick={() => setSelectedChatId(chat.id)}
                       className={`w-full flex items-start p-4 rounded-2xl transition-all duration-200 group ${
                         selectedChatId === chat.id 
                           ? 'bg-nexus-primary text-white shadow-lg shadow-blue-500/20' 
                           : 'hover:bg-gray-50 dark:hover:bg-gray-800/50'
                       }`}
                     >
                       <div className="relative mr-4 flex-shrink-0">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-bold transition-colors ${
                            selectedChatId === chat.id 
                              ? 'bg-white/20 text-white' 
                              : 'bg-gradient-to-br from-gray-100 to-gray-200 dark:from-gray-800 dark:to-gray-700 text-gray-600 dark:text-gray-300'
                          }`}>
                            {chat.name[0]}
                          </div>
                          {chat.isGroup && (
                            <div className="absolute -bottom-1 -right-1 bg-white dark:bg-nexus-dark rounded-full p-0.5">
                              <div className="bg-nexus-accent text-white rounded-full p-0.5">
                                <Users size={10} />
                              </div>
                            </div>
                          )}
                       </div>

                       <div className="flex-1 text-left min-w-0 py-0.5">
                         <div className="flex justify-between items-center mb-1">
                           <h3 className={`font-bold truncate text-[15px] ${selectedChatId === chat.id ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                             {chat.name}
                           </h3>
                           <span className={`text-[11px] font-medium ${selectedChatId === chat.id ? 'text-blue-100' : 'text-gray-400 group-hover:text-gray-500'}`}>
                             {lastMsg?.timestamp ? new Date(lastMsg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                           </span>
                         </div>
                         <p className={`text-[13px] truncate leading-relaxed ${selectedChatId === chat.id ? 'text-blue-50' : 'text-gray-500 dark:text-gray-400'}`}>
                           {lastMsg?.senderId === 'me' && <span className="opacity-70">You: </span>}
                           {lastMsg?.text || <span className="italic opacity-60">Start the conversation</span>}
                         </p>
                       </div>
                     </button>
                   );
                 })}
              </div>
            )}
          </div>

          {/* MOBILE BOTTOM NAVIGATION */}
          <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-nexus-dark border-t dark:border-gray-800 pb-safe z-30 flex justify-around items-center h-20 px-2 shadow-[0_-5px_10px_rgba(0,0,0,0.02)]">
            <button 
              onClick={() => setActiveTab('priority')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'priority' ? 'text-nexus-primary' : 'text-gray-400'}`}
            >
              <Star size={24} fill={activeTab === 'priority' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Priority</span>
            </button>
            <button 
              onClick={() => setActiveTab('groups')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'groups' ? 'text-nexus-primary' : 'text-gray-400'}`}
            >
              <Users size={24} fill={activeTab === 'groups' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Groups</span>
            </button>
            <button 
              onClick={() => setActiveTab('actions')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'actions' ? 'text-nexus-primary' : 'text-gray-400'}`}
            >
              <div className="relative">
                <Zap size={24} fill={activeTab === 'actions' ? "currentColor" : "none"} />
                {actionItems.some(i => !i.isCompleted) && (
                  <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white dark:border-nexus-dark"></span>
                )}
              </div>
              <span className="text-[10px] font-bold">Actions</span>
            </button>
          </div>
        </div>

        {/* === CHAT AREA === */}
        <div className={`
          flex-1 bg-gray-50/50 dark:bg-gray-900/50 relative
          ${!selectedChatId ? 'hidden md:flex items-center justify-center' : 'flex w-full absolute inset-0 md:static z-20'}
        `}>
          {activeChat ? (
            <ChatInterface 
              chat={activeChat} 
              onBack={() => setSelectedChatId(null)}
              onSendMessage={handleSendMessage}
            />
          ) : (
            <div className="text-center opacity-40 max-w-sm px-6">
              <div className="w-32 h-32 bg-gray-100 dark:bg-gray-800 rounded-[2rem] mx-auto mb-8 flex items-center justify-center rotate-3 transform transition-transform hover:rotate-6">
                 <MessageSquare size={64} className="text-gray-400" />
              </div>
              <h2 className="text-3xl font-bold dark:text-white mb-3">Nexus Web</h2>
              <p className="dark:text-gray-400 text-lg leading-relaxed">
                Select a conversation from the sidebar to start messaging. 
                <br />Experience the future of triage.
              </p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Chat, Message } from '../types';
import { Send, ArrowLeft, Sparkles, MoreVertical, Paperclip, CheckCheck, Phone, Video, Smile, Share, CornerUpRight } from 'lucide-react';
import { summarizeChat } from '../services/geminiService';
import { sendTypingEvent, subscribeToTypingEvents, getCurrentUser, toggleReaction } from '../services/supabaseClient';
import { ChatInfoSidebar } from './ChatInfoSidebar';
import { ForwardModal } from './ForwardModal';

interface ChatInterfaceProps {
  chat: Chat;
  onBack: () => void;
  onSendMessage: (text: string) => void;
}

const REACTION_EMOJIS = ['👍', '❤️', '😂', '😮', '😢', '🔥'];

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [currentUserId, setCurrentUserId] = useState<string>('');

  // New State
  const [showInfoSidebar, setShowInfoSidebar] = useState(false);
  const [forwardingMessage, setForwardingMessage] = useState<string | null>(null);
  const [activeReactionMessageId, setActiveReactionMessageId] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    getCurrentUser().then(u => u && setCurrentUserId(u.id));
  }, []);

  useEffect(() => {
    scrollToBottom();
    setSummary(null);
    setShowInfoSidebar(false);
    setTypingUsers(new Set()); 

    const unsubscribe = subscribeToTypingEvents(chat.id, (userId, isTyping) => {
      if (userId === currentUserId) return;

      setTypingUsers(prev => {
        const next = new Set(prev);
        if (isTyping) {
          next.add(userId);
        } else {
          next.delete(userId);
        }
        return next;
      });
      setTimeout(scrollToBottom, 100);
    });

    return () => {
      unsubscribe();
    };
  }, [chat.id, currentUserId]);

  useEffect(() => {
    scrollToBottom();
  }, [chat.messages]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputText(e.target.value);

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, true);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        sendTypingEvent(chat.id, currentUserId, false);
      }, 2000);
    }
  };

  const handleSend = () => {
    if (!inputText.trim()) return;
    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }
    onSendMessage(inputText);
    setInputText('');
  };

  const handleCatchMeUp = async () => {
    setIsSummarizing(true);
    const result = await summarizeChat(chat.messages);
    setSummary(result);
    setIsSummarizing(false);
  };

  const onReactionClick = async (msgId: string, emoji: string) => {
    await toggleReaction(chat.id, msgId, currentUserId, emoji);
    setActiveReactionMessageId(null);
  };

  const isSomeoneTyping = typingUsers.size > 0;

  return (
    <div className="flex flex-row h-full w-full overflow-hidden relative">
      <div className="flex-1 flex flex-col h-full bg-[#f2f4f7] dark:bg-[#0b141a] relative min-w-0">

        {/* HEADER */}
        <div className="flex items-center justify-between px-4 py-3 bg-white/80 dark:bg-nexus-card/90 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800 sticky top-0 z-20 shadow-sm">
          <div className="flex items-center gap-3">
            <button onClick={onBack} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full md:hidden text-nexus-primary transition-colors">
              <ArrowLeft size={24} />
            </button>

            <div className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => setShowInfoSidebar(!showInfoSidebar)}>
              <div className="relative">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold shadow-sm ${chat.isGroup ? 'bg-gradient-to-tr from-nexus-primary to-nexus-accent' : 'bg-gradient-to-tr from-gray-400 to-gray-500'}`}>
                  {chat.name[0]}
                </div>
                <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white dark:border-nexus-card"></div>
              </div>
              <div>
                <h3 className="font-bold text-base dark:text-white leading-tight">{chat.name}</h3>
                <p className="text-xs text-nexus-primary font-medium">
                  {isSomeoneTyping ? 'Typing...' : 'Online'}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 md:gap-2">
            <button className="p-2 text-nexus-primary bg-nexus-primary/5 hover:bg-nexus-primary/10 rounded-full transition-colors hidden sm:block">
              <Phone size={20} />
            </button>
            <button className="p-2 text-nexus-primary bg-nexus-primary/5 hover:bg-nexus-primary/10 rounded-full transition-colors hidden sm:block">
              <Video size={20} />
            </button>

            {chat.isGroup && (
              <button 
                onClick={handleCatchMeUp}
                disabled={isSummarizing}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-gradient-to-r from-nexus-accent to-purple-600 text-white rounded-full text-xs font-bold shadow-lg shadow-purple-500/20 hover:shadow-purple-500/40 transition-all transform hover:scale-105"
              >
                <Sparkles size={14} className={isSummarizing ? "animate-spin" : ""} />
                {isSummarizing ? 'Thinking...' : 'Catch Me Up'}
              </button>
            )}

            <button 
              onClick={() => setShowInfoSidebar(!showInfoSidebar)}
              className={`p-2 rounded-full transition-colors ${showInfoSidebar ? 'bg-nexus-primary text-white' : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700'}`}
            >
              <MoreVertical size={20} />
            </button>
          </div>
        </div>

        {/* SUMMARY CARD */}
        {summary && (
          <div className="mx-4 mt-4 p-4 bg-gradient-to-r from-nexus-accent/10 to-nexus-primary/10 border border-nexus-accent/20 rounded-2xl animate-fade-in-down">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-white dark:bg-nexus-card rounded-lg shadow-sm text-nexus-accent">
                <Sparkles size={18} />
              </div>
              <div>
                <h4 className="text-xs font-bold uppercase text-nexus-accent mb-1 tracking-wider">AI Summary</h4>
                <p className="text-sm text-gray-700 dark:text-gray-200 leading-relaxed">{summary}</p>
              </div>
              <button onClick={() => setSummary(null)} className="ml-auto text-gray-400 hover:text-gray-600">×</button>
            </div>
          </div>
        )}

        {/* MESSAGES AREA */}
        <div 
          className="flex-1 overflow-y-auto p-4 space-y-4 sm:p-6 no-scrollbar"
          onClick={() => setActiveReactionMessageId(null)}
        >
          {chat.messages.map((msg, idx) => {
            const isMe = msg.senderId === 'me';
            const showAvatar = !isMe && (idx === 0 || chat.messages[idx - 1].senderId !== msg.senderId);

            return (
              <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} group relative mb-2`}>
                <div className={`flex ${isMe ? 'justify-end' : 'justify-start'} max-w-full`}>
                  {!isMe && (
                    <div className={`w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-6 ${showAvatar ? 'opacity-100' : 'opacity-0'}`}>
                      {chat.name[0]}
                    </div>
                  )}

                  <div className="relative group/bubble">
                    {/* Message Bubble */}
                    <div className={`relative shadow-sm max-w-[85vw] md:max-w-[500px] ${
                      isMe 
                        ? 'bg-nexus-primary text-white rounded-2xl rounded-tr-sm' 
                        : 'bg-white dark:bg-nexus-card dark:text-gray-100 rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800'
                    }`}>
                        <div className="px-4 py-2 text-[15px] leading-relaxed whitespace-pre-wrap break-words">
                          {msg.text}
                        </div>
                        <div className={`px-2 pb-1 flex justify-end items-center gap-1 text-[10px] ${isMe ? 'text-blue-100' : 'text-gray-400'}`}>
                          <span>{new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                          {isMe && <CheckCheck size={14} className="text-blue-200" />}
                        </div>
                    </div>

                    {/* Reactions Display */}
                    {msg.reactions && Object.keys(msg.reactions).length > 0 && (
                      <div className={`absolute -bottom-3 ${isMe ? 'right-0' : 'left-0'} flex gap-1 z-10`}>
                        {Object.entries(msg.reactions).map(([emoji, users]) => (
                          <div key={emoji} className="bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-full px-1.5 py-0.5 text-[10px] shadow-sm flex items-center gap-0.5 scale-90">
                            <span>{emoji}</span>
                            {(users as string[]).length > 1 && <span className="text-gray-500 font-bold">{(users as string[]).length}</span>}
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Action Buttons (Hover) */}
                    <div className={`absolute -top-8 ${isMe ? 'right-0' : 'left-0'} flex items-center gap-1 opacity-0 group-hover/bubble:opacity-100 transition-opacity bg-white/90 dark:bg-gray-800/90 rounded-full px-2 py-1 shadow-sm backdrop-blur-sm`}>
                       <button 
                         onClick={(e) => { e.stopPropagation(); setActiveReactionMessageId(activeReactionMessageId === msg.id ? null : msg.id); }}
                         className="p-1.5 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-gray-500"
                         title="Add Reaction"
                       >
                         <Smile size={14} />
                       </button>
                       <button 
                         onClick={(e) => { e.stopPropagation(); setForwardingMessage(msg.text); }}
                         className="p-1.5 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-gray-500"
                         title="Forward Message"
                       >
                         <Share size={14} />
                       </button>
                    </div>

                    {/* Reaction Picker Popover */}
                    {activeReactionMessageId === msg.id && (
                      <div className={`absolute -top-12 ${isMe ? 'right-0' : 'left-0'} bg-white dark:bg-nexus-card shadow-xl rounded-full p-1 flex gap-1 animate-fade-in-up z-20 border dark:border-gray-700`}>
                        {REACTION_EMOJIS.map(emoji => (
                          <button
                            key={emoji}
                            onClick={(e) => { e.stopPropagation(); onReactionClick(msg.id, emoji); }}
                            className="w-8 h-8 flex items-center justify-center hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-lg transition-transform hover:scale-125"
                          >
                            {emoji}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}

          {/* TYPING INDICATOR */}
          {isSomeoneTyping && (
            <div className="flex justify-start animate-fade-in-up">
              <div className="w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-1 opacity-100">
                {chat.name[0]}
              </div>
