// This allows the app to function fully in the browser without a real backend.
// It uses localStorage for the DB and BroadcastChannel for Realtime events.

const USERS_KEY = 'nexus_users';
const CHATS_KEY = 'nexus_chats';
const MESSAGES_KEY = 'nexus_messages';
const SESSION_KEY = 'nexus_session';
const PARTICIPANTS_KEY = 'nexus_chat_participants';

const broadcast = new BroadcastChannel('nexus_realtime');

// --- SEED DATA ---
