            <h1 className="text-2xl font-bold tracking-tight dark:text-white flex items-center gap-2 relative">
              <span className="w-8 h-8 bg-gradient-to-br from-nexus-primary to-blue-600 rounded-xl flex items-center justify-center text-white text-lg shadow-blue-500/30 shadow-lg">N</span>
              <span>Nexus</span>

              {/* STATUS INDICATOR/SELECTOR */}
              <div className="relative ml-1">
                 <button onClick={() => setShowStatusMenu(!showStatusMenu)} className="w-3 h-3 rounded-full bg-nexus-success ring-2 ring-white dark:ring-nexus-dark hover:scale-125 transition-transform"></button>
                 {showStatusMenu && (
                   <div className="absolute top-6 left-0 w-32 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-50 animate-fade-in-down">
                      <button onClick={() => handleStatusChange('online')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
