import { GoogleGenAI, Type } from "@google/genai";
import { Message } from "../types";

// Initialize the API client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = 'gemini-3-flash-preview';

/**
 * Summarizes a list of messages using Gemini.
 */
export const summarizeChat = async (messages: Message[]): Promise<string> => {
  if (messages.length === 0) return "No messages to summarize.";

  const transcript = messages
    .map(m => `${m.senderId === 'me' ? 'Me' : 'Them'}: ${m.text}`)
    .join('\n');

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `You are a helpful assistant for a messaging app called Nexus. 
      Summarize the following chat conversation into a concise paragraph (max 3 sentences), highlighting key points and decisions.

      Transcript:
      ${transcript}`,
    });

    return response.text || "Could not generate summary.";
  } catch (error) {
    console.error("Gemini Summarize Error:", error);
    return "Unable to summarize at this time.";
  }
};

/**
 * Analyzes a message to see if it contains an action item (date/time/location/recurrence).
 */
export const detectActionItem = async (text: string): Promise<{ isAction: boolean; title?: string; dateTime?: string; recurrence?: string; location?: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Analyze the following message for action items. Look for intent to perform a task or attend an event.
      Extract the Date/Time, Recurrence (e.g., 'every week'), and Location if present.

      Examples:
      - "Meeting at Starbucks tomorrow at 9am" -> isAction: true, title: "Meeting", dateTime: "Tomorrow 9am", location: "Starbucks"
      - "Gym every Monday morning" -> isAction: true, title: "Gym", dateTime: "Monday morning", recurrence: "Weekly"

      Message: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isAction: { type: Type.BOOLEAN, description: "True if the message contains a scheduled task or reminder." },
            title: { type: Type.STRING, description: "A short title for the action item." },
            dateTime: { type: Type.STRING, description: "The extracted date/time string." },
            recurrence: { type: Type.STRING, description: "Any recurrence pattern (e.g. 'Daily', 'Weekly')." },
            location: { type: Type.STRING, description: "Physical location or link." }
          },
          required: ["isAction"]
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return { isAction: false };
  } catch (error) {
    console.error("Gemini Action Detection Error:", error);
    return { isAction: false };
  }
};

// --- MOCK SUPABASE CLIENT ---
// This allows the app to function fully in the browser without a real backend.
// It uses localStorage for the DB and BroadcastChannel for Realtime events.

const USERS_KEY = 'nexus_users';
const CHATS_KEY = 'nexus_chats';
const MESSAGES_KEY = 'nexus_messages';
const SESSION_KEY = 'nexus_session';
const PARTICIPANTS_KEY = 'nexus_chat_participants';

const broadcast = new BroadcastChannel('nexus_realtime');

// --- SEED DATA ---
const seedData = () => {
  if (!localStorage.getItem(USERS_KEY)) {
    const mockUsers = [
      { id: 'u1', email: 'sarah@nexus.com', phone: '5550101', full_name: 'Sarah Jen', password: '123', status: 'online', statusMessage: 'Focusing' },
      { id: 'u2', email: 'mike@nexus.com', phone: '5550102', full_name: 'Mike Ross', password: '123', status: 'busy', statusMessage: 'In a meeting' },
      { id: 'u3', email: 'dev@nexus.com', phone: '5550103', full_name: 'Dev Team', password: '123', status: 'away', statusMessage: 'Lunch' },
    ];
    localStorage.setItem(USERS_KEY, JSON.stringify(mockUsers));
  }
};
seedData();

// --- HELPERS ---
const getStore = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const setStore = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// --- MOCK SUPABASE OBJECT ---
export const supabase = {
  auth: {
    getSession: async () => {
      const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
      return { data: { session: sessionUser ? { user: sessionUser } : null }, error: null };
    },
    signInWithPassword: async ({ email, password }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      const user = users.find((u: any) => u.email === email && u.password === password);
      if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        window.dispatchEvent(new Event('storage')); 
        return { data: { user, session: { user } }, error: null };
      }
      return { data: null, error: { message: 'Invalid credentials' } };
    },
    signUp: async ({ email, password, options }: any) => {
      await delay(500);
      const users = getStore(USERS_KEY);
      if (users.find((u: any) => u.email === email)) {
        return { data: null, error: { message: 'User already exists' } };
      }
      const newUser = {
        id: 'u_' + Date.now(),
        email,
        password,
        phone: options?.data?.phone || '',
        full_name: options?.data?.full_name || email.split('@')[0],
        status: 'online',
        statusMessage: ''
      };
      users.push(newUser);
      setStore(USERS_KEY, users);
      localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
      return { data: { user: newUser, session: { user: newUser } }, error: null };
    },
    signOut: async () => {
      localStorage.removeItem(SESSION_KEY);
      return { error: null };
    },
    onAuthStateChange: (callback: any) => {
      const handler = () => {
        const sessionUser = JSON.parse(localStorage.getItem(SESSION_KEY) || 'null');
        callback('SIGNED_IN', sessionUser ? { user: sessionUser } : null);
      };
      window.addEventListener('storage', handler);
      return { data: { subscription: { unsubscribe: () => window.removeEventListener('storage', handler) } } };
    }
  },
  channel: (channelName: string) => {
    return {
      on: (type: string, filter: any, callback: any) => {
        const handler = (event: MessageEvent) => {
          const { table, new: record, type: eventType } = event.data;
          if (type === 'postgres_changes' && 
              filter.event === eventType && 
              filter.table === table) {
             if (filter.filter) {
               const [key, val] = filter.filter.split('=eq.');
               if (String(record[key]) !== String(val)) return;
             }
             callback({ new: record });
          } else if (type === 'postgres_changes' && filter.event === '*') {
             if (filter.table === table) {
               if (filter.filter) {
                 const [key, val] = filter.filter.split('=eq.');
                 if (String(record[key]) !== String(val)) return;
               }
               callback({ new: record, eventType });
             }
          }
        };
        broadcast.addEventListener('message', handler);
        return {
          subscribe: () => {} 
        };
      }
    };
  },
  removeChannel: (channel: any) => {
  }
};

