          {isSearching ? (
             <div className="flex-1 flex items-center gap-2 animate-fade-in-down">
               <button onClick={() => { setIsSearching(false); setSearchQuery(''); }} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
                 <ArrowLeft size={20} className="text-gray-500" />
               </button>
               <div className="flex-1 relative">
                 <input 
                   autoFocus
