import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ArrowRight, Loader2 } from 'lucide-react';

export const AuthScreen = ({ onAuthSuccess }: { onAuthSuccess: () => void }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
      } else {
        // Sign Up
        const { data, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, phone: phone } }
        });
        if (signUpError) throw signUpError;
      }
      onAuthSuccess();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-nexus-slate dark:bg-nexus-dark p-4">
      <div className="w-full max-w-md bg-white dark:bg-nexus-card p-8 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-800">
        <div className="text-center mb-8">
          <div className="w-12 h-12 bg-nexus-midnight rounded-xl flex items-center justify-center text-white text-xl font-bold mx-auto mb-4">N</div>
          <h1 className="text-3xl font-bold text-nexus-midnight dark:text-white mb-2">Nexus</h1>
          <p className="text-gray-500 dark:text-gray-400">
            {isLogin ? 'Welcome back, ready to triage?' : 'Join the future of messaging.'}
          </p>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 text-sm rounded-lg">
            {error}
          </div>
        )}

        <form onSubmit={handleAuth} className="space-y-4">
          {!isLogin && (
            <>
              <div>
                <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Full Name</label>
                <input 
                  type="text" 
                  required 
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  className="w-full p-3 rounded-xl bg-gray-50 dark:bg-gray-800 border-none focus:ring-2 focus:ring-nexus-mint dark:text-white transition-all"
                  placeholder="John Doe"
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Phone Number</label>
                <input 
                  type="tel" 
                  required 
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full p-3 rounded-xl bg-gray-50 dark:bg-gray-800 border-none focus:ring-2 focus:ring-nexus-mint dark:text-white transition-all"
                  placeholder="+1 (555) 000-0000"
                />
              </div>
            </>
          )}

          <div>
            <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Email Address</label>
            <input 
              type="email" 
              required 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full p-3 rounded-xl bg-gray-50 dark:bg-gray-800 border-none focus:ring-2 focus:ring-nexus-mint dark:text-white transition-all"
              placeholder="you@example.com"
            />
          </div>

          <div>
            <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Password</label>
            <input 
              type="password" 
              required 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full p-3 rounded-xl bg-gray-50 dark:bg-gray-800 border-none focus:ring-2 focus:ring-nexus-mint dark:text-white transition-all"
              placeholder="••••••••"
            />
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full py-4 bg-nexus-mint hover:bg-green-400 text-nexus-midnight font-bold rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-nexus-mint/30"
          >
            {loading ? <Loader2 className="animate-spin" /> : (isLogin ? 'Sign In' : 'Create Account')}
            {!loading && <ArrowRight size={18} />}
          </button>
        </form>

        <div className="mt-6 text-center">
          <button 
            onClick={() => setIsLogin(!isLogin)}
            className="text-sm text-gray-500 hover:text-nexus-midnight dark:hover:text-white transition-colors"
          >
            {isLogin ? "Don't have an account? Sign up" : "Already have an account? Sign in"}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Search, UserPlus, X, Send, Mail, MessageSquare } from 'lucide-react';
import { searchUsers, createNewChat, createGhostUser, sendInvite } from '../services/supabaseClient';

interface NewChatModalProps {
  currentUserId: string;
  onClose: () => void;
  onChatCreated: () => void;
}

export const NewChatModal: React.FC<NewChatModalProps> = ({ currentUserId, onClose, onChatCreated }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [inviteSent, setInviteSent] = useState(false);

  const handleSearch = async (val: string) => {
    setQuery(val);
    setInviteSent(false); // Reset if typing
    if (val.length > 2) {
      setLoading(true);
      const users = await searchUsers(val);
      // Filter out self
      setResults(users.filter((u: any) => u.id !== currentUserId));
      setLoading(false);
    } else {
      setResults([]);
    }
  };

  const startChat = async (userId: string, userName: string) => {
    try {
      setLoading(true);
      await createNewChat(currentUserId, userId, userName);
      onChatCreated();
      onClose();
    } catch (e) {
      console.error(e);
      setLoading(false);
    }
  };

  const handleInvite = async (type: 'sms' | 'email') => {
    setLoading(true);
    await sendInvite(type, query);

    // Create ghost user immediately so they can start chatting
    const newUser = await createGhostUser(query);
    await createNewChat(currentUserId, newUser.id, newUser.full_name);

    setLoading(false);
    setInviteSent(true);

    setTimeout(() => {
        onChatCreated();
        onClose();
    }, 2000);
  };

  const isEmail = query.includes('@');
  const isPhone = /^\+?[\d\s-]{4,}$/.test(query);
  const isQueryValidContact = query.length > 3 && (isEmail || isPhone);

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white dark:bg-nexus-card w-full max-w-md rounded-2xl shadow-2xl border dark:border-gray-700 overflow-hidden">
        <div className="p-4 border-b dark:border-gray-700 flex justify-between items-center">
          <h2 className="font-bold text-lg dark:text-white">New Conversation</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <X size={20} className="dark:text-gray-400" />
          </button>
        </div>

        <div className="p-4">
          <div className="relative mb-4">
            <Search className="absolute left-3 top-3 text-gray-400" size={18} />
            <input 
              autoFocus
              type="text" 
              placeholder="Name, Phone or Email..." 
              value={query}
              onChange={(e) => handleSearch(e.target.value)}
              className="w-full bg-nexus-slate dark:bg-gray-800 rounded-xl py-2.5 pl-10 pr-4 outline-none focus:ring-2 focus:ring-nexus-mint dark:text-white"
            />
          </div>

          <div className="min-h-[200px]">
            {loading ? (
              <div className="flex justify-center py-8 text-gray-400">Processing...</div>
            ) : inviteSent ? (
              <div className="flex flex-col items-center justify-center py-8 text-center animate-fade-in-up">
                  <div className="w-16 h-16 bg-green-100 dark:bg-green-900/20 rounded-full flex items-center justify-center text-nexus-mint mb-3">
                      <Send size={32} />
                  </div>
                  <h3 className="font-bold text-lg dark:text-white">Invite Sent!</h3>
                  <p className="text-gray-500 text-sm mt-1">Chat created. They will see it when they join.</p>
              </div>
            ) : results.length > 0 ? (
              <div className="space-y-2">
                {results.map(user => (
                  <button 
                    key={user.id}
                    onClick={() => startChat(user.id, user.full_name)}
                    className="w-full flex items-center gap-3 p-3 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-xl transition-colors text-left"
                  >
                    <div className="w-10 h-10 rounded-full bg-nexus-midnight/10 text-nexus-midnight dark:bg-gray-700 dark:text-white flex items-center justify-center font-bold">
                      {user.full_name[0]}
                    </div>
                    <div>
                      <div className="font-bold dark:text-white">{user.full_name}</div>
                      <div className="text-xs text-gray-500">
                         {user.phone ? `${user.phone}` : user.email}
                      </div>
                    </div>
                    <UserPlus size={16} className="ml-auto text-gray-400" />
                  </button>
                ))}
              </div>
            ) : query.length > 2 ? (
               <div className="flex flex-col items-center justify-center py-4 text-center space-y-4">
                  <p className="text-gray-400">User not found on Nexus.</p>

                  {isQueryValidContact && (
                    <div className="w-full space-y-2 bg-gray-50 dark:bg-gray-800/50 p-4 rounded-xl border border-dashed dark:border-gray-700">
                      <p className="text-sm font-bold dark:text-white mb-2">Invite them to connect:</p>

                      {isPhone && (
                        <button 
                          onClick={() => handleInvite('sms')}
                          className="w-full bg-nexus-mint text-nexus-midnight p-3 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-green-400 transition-colors"
                        >
                          <MessageSquare size={18} />
                          Invite via SMS
                        </button>
                      )}

                      {isEmail && (
                         <button 
                          onClick={() => handleInvite('email')}
                          className="w-full bg-white dark:bg-gray-700 text-gray-900 dark:text-white border dark:border-gray-600 p-3 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-gray-50 dark:hover:bg-gray-600 transition-colors"
                        >
                          <Mail size={18} />
                          Invite via Email
                        </button>
                      )}
                    </div>
                  )}
               </div>
            ) : (
              <div className="text-center py-8 text-gray-400 text-sm">
                Enter a number or email to find friends or invite them.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Mic, MicOff, Video, VideoOff, PhoneOff, Maximize2, Minimize2 } from 'lucide-react';

interface CallOverlayProps {
  partnerName: string;
  isVideo: boolean;
  onEndCall: () => void;
}

export const CallOverlay: React.FC<CallOverlayProps> = ({ partnerName, isVideo, onEndCall }) => {
  const [duration, setDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [isCamOff, setIsCamOff] = useState(!isVideo);
  const [isMinimized, setIsMinimized] = useState(false);
  const [status, setStatus] = useState<'calling' | 'connected'>('calling');

  useEffect(() => {
    // Simulate connection after 2 seconds
    const timer = setTimeout(() => {
      setStatus('connected');
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    let interval: any;
    if (status === 'connected') {
      interval = setInterval(() => {
        setDuration(d => d + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [status]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (isMinimized) {
    return (
      <div className="fixed bottom-4 right-4 z-50 w-64 bg-nexus-midnight/80 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 flex items-center justify-between cursor-pointer animate-fade-in-up">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-nexus-midnight to-nexus-mint flex items-center justify-center text-white font-bold">
            {partnerName[0]}
          </div>
          <div>
            <div className="text-white text-sm font-bold">{partnerName}</div>
            <div className="text-nexus-mint text-xs font-mono">{status === 'calling' ? 'Calling...' : formatTime(duration)}</div>
          </div>
        </div>
        <div className="flex gap-2">
           <button onClick={() => setIsMinimized(false)} className="p-2 hover:bg-white/10 rounded-full text-white">
             <Maximize2 size={16} />
           </button>
           <button onClick={onEndCall} className="p-2 bg-nexus-coral hover:bg-red-600 rounded-full text-white">
             <PhoneOff size={16} />
           </button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex flex-col items-center justify-center bg-gray-900 overflow-hidden">
      {/* Background Ambience */}
      <div className="absolute inset-0 bg-gradient-to-br from-nexus-midnight via-[#0f172a] to-black"></div>

      {/* Animated Glows */}
      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-nexus-midnight/40 rounded-full blur-[100px] animate-pulse"></div>
      <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-nexus-mint/20 rounded-full blur-[100px] animate-pulse [animation-delay:2s]"></div>

      {/* Main Content */}
      <div className="relative z-10 flex flex-col items-center w-full max-w-md px-6">

        {/* Top Controls */}
        <div className="absolute top-12 right-6">
           <button onClick={() => setIsMinimized(true)} className="p-3 bg-white/5 hover:bg-white/10 backdrop-blur-md rounded-full text-white transition-all">
             <Minimize2 size={24} />
           </button>
        </div>

        {/* User Visual */}
        <div className="relative mb-12">
           {/* Ringing Rings */}
           {status === 'calling' && (
             <>
               <div className="absolute inset-0 border-2 border-nexus-mint/30 rounded-full animate-ping [animation-duration:2s]"></div>
               <div className="absolute inset-0 border-2 border-nexus-mint/20 rounded-full animate-ping [animation-delay:0.5s] [animation-duration:2s]"></div>
             </>
           )}

           <div className="w-40 h-40 rounded-full bg-gradient-to-br from-nexus-midnight to-nexus-mint/50 p-1 shadow-[0_0_50px_rgba(42,245,152,0.3)] relative overflow-hidden">
             {/* If video on, show camera placeholder, else show avatar */}
             {(!isCamOff && isVideo) ? (
                <div className="w-full h-full rounded-full bg-gray-800 flex items-center justify-center overflow-hidden">
                   {/* Mock Camera Feed */}
                   <div className="w-full h-full bg-gray-700 animate-pulse flex items-center justify-center text-gray-500">
                      Camera Active
                   </div>
                </div>
             ) : (
                <div className="w-full h-full rounded-full bg-gray-900 flex items-center justify-center text-5xl font-bold text-white">
                  {partnerName[0]}
                </div>
             )}
           </div>
        </div>

        {/* Info */}
        <div className="text-center mb-16">
          <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">{partnerName}</h2>
          <p className="text-nexus-mint font-medium tracking-widest uppercase text-sm">
             {status === 'calling' ? 'Establishing Connection...' : formatTime(duration)}
          </p>
        </div>

        {/* Controls - Glassmorphism Dock */}
