                     <div className="absolute inset-0 bg-black/40 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                        <Camera className="text-white" size={24} />
                     </div>
                  </div>
                  <div>
                    <h4 className="font-bold text-nexus-midnight dark:text-white text-lg">Profile Photo</h4>
                    <p className="text-sm text-gray-500 mb-2">Click to change your avatar</p>
                    <div className="flex gap-2">
                       <button className="text-xs font-bold text-nexus-midnight dark:text-nexus-mint hover:underline">Upload</button>
                       <span className="text-gray-300">|</span>
                       <button className="text-xs font-bold text-nexus-coral hover:underline">Remove</button>
                    </div>
                  </div>
                </div>

                {/* Form Fields */}
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold uppercase text-gray-400 mb-1">Display Name</label>
                    <input 
                      type="text" 
                      value={formData.full_name}
                      onChange={(e) => setFormData({...formData, full_name: e.target.value})}
                      className="w-full bg-gray-100 dark:bg-gray-800 border-none rounded-xl p-3 dark:text-white focus:ring-2 focus:ring-nexus-mint outline-none"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold uppercase text-gray-400 mb-1">Status / Bio</label>
                    <input 
                      type="text" 
                      value={formData.statusMessage}
                      onChange={(e) => setFormData({...formData, statusMessage: e.target.value})}
                      className="w-full bg-gray-100 dark:bg-gray-800 border-none rounded-xl p-3 dark:text-white focus:ring-2 focus:ring-nexus-mint outline-none"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold uppercase text-gray-400 mb-1">Email</label>
                    <input 
                      type="email" 
                      disabled
                      value={formData.email}
                      className="w-full bg-gray-100 dark:bg-gray-800 border-none rounded-xl p-3 text-gray-500 cursor-not-allowed"
                    />
                  </div>
                </div>

                <div className="pt-4">
                  <button 
                    onClick={handleSave}
                    disabled={saving}
                    className="px-6 py-3 bg-nexus-midnight text-white dark:bg-nexus-mint dark:text-nexus-midnight font-bold rounded-xl shadow-lg hover:opacity-90 transition-all flex items-center gap-2"
                  >
                    {saving ? 'Saving...' : 'Save Changes'}
                    {!saving && <Check size={18} />}
                  </button>
                </div>
              </div>
            )}

            {/* --- APPEARANCE TAB --- */}
            {activeTab === 'appearance' && (
              <div className="max-w-md space-y-6 animate-fade-in-up">
                 <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl border dark:border-gray-700">
                    <div className="flex items-center gap-4">
                       <div className="w-10 h-10 rounded-full bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 flex items-center justify-center">
                          <Moon size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-nexus-midnight dark:text-white">Dark Mode</h4>
                         <p className="text-sm text-gray-500">Easier on the eyes at night</p>
                       </div>
                    </div>

                    <button 
                      onClick={toggleDarkMode}
                      className={`w-12 h-7 rounded-full relative transition-colors ${isDarkMode ? 'bg-nexus-mint' : 'bg-gray-300'}`}
                    >
                      <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-6' : 'translate-x-1'}`}></div>
                    </button>
                 </div>

                 <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl border dark:border-gray-700 opacity-60 cursor-not-allowed">
                    <div className="flex items-center gap-4">
                       <div className="w-10 h-10 rounded-full bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-300 flex items-center justify-center">
                          <Smartphone size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-nexus-midnight dark:text-white">Compact Mode</h4>
                         <p className="text-sm text-gray-500">Show more messages at once</p>
                       </div>
                    </div>
                    <div className="w-12 h-7 rounded-full bg-gray-300 relative"><div className="absolute top-1 left-1 w-5 h-5 bg-white rounded-full"></div></div>
                 </div>
              </div>
            )}

             {/* --- NOTIFICATIONS TAB --- */}
             {activeTab === 'notifications' && (
              <div className="max-w-md space-y-6 animate-fade-in-up">
                 <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl border dark:border-gray-700">
                    <div className="flex items-center gap-4">
                       <div className="w-10 h-10 rounded-full bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-300 flex items-center justify-center">
                          <Bell size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-nexus-midnight dark:text-white">Do Not Disturb</h4>
                         <p className="text-sm text-gray-500">Pause all notifications</p>
                       </div>
                    </div>
                    <button 
                      onClick={() => setDnd(!dnd)}
                      className={`w-12 h-7 rounded-full relative transition-colors ${dnd ? 'bg-nexus-mint' : 'bg-gray-300'}`}
                    >
                      <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-transform ${dnd ? 'translate-x-6' : 'translate-x-1'}`}></div>
                    </button>
                 </div>
              </div>
            )}

            {/* --- PRIVACY TAB --- */}
            {activeTab === 'privacy' && (
              <div className="max-w-md space-y-6 animate-fade-in-up">
                 <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl border dark:border-gray-700">
                    <div className="flex items-center gap-4">
                       <div className="w-10 h-10 rounded-full bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-300 flex items-center justify-center">
                          <Shield size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-nexus-midnight dark:text-white">Read Receipts</h4>
                         <p className="text-sm text-gray-500">Let others see when you've read messages</p>
                       </div>
                    </div>
                    <button 
                      onClick={() => setReadReceipts(!readReceipts)}
                      className={`w-12 h-7 rounded-full relative transition-colors ${readReceipts ? 'bg-nexus-mint' : 'bg-gray-300'}`}
                    >
                      <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-transform ${readReceipts ? 'translate-x-6' : 'translate-x-1'}`}></div>
                    </button>
                 </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType, SortOption, CallSession } from './types';
import { detectActionItem } from './services/geminiService';
import { supabase, getCurrentUser, fetchUserChats, fetchMessages, sendMessageToDb, toggleChatPin, updateUserStatus } from './services/supabaseClient';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { AuthScreen } from './components/AuthScreen';
import { NewChatModal } from './components/NewChatModal';
import { CallOverlay } from './components/CallOverlay';
import { SettingsModal } from './components/SettingsModal';
import { 
  Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare, Plus, LogOut,
  Users, Pin, ChevronDown, Clock, Activity, Circle, Settings
} from 'lucide-react';

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [sortOption, setSortOption] = useState<SortOption>('time');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
  const [showNewChatModal, setShowNewChatModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showStatusMenu, setShowStatusMenu] = useState(false);
  const [showSortMenu, setShowSortMenu] = useState(false);

  const [chats, setChats] = useState<Chat[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);
  const [activeCall, setActiveCall] = useState<CallSession | null>(null);

  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user) setCurrentUser(session.user);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session?.user) setCurrentUser(session.user);
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages (INSERT) and updates (UPDATE - for reactions)
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {

          if (payload.eventType === 'INSERT') {
            const newMsg = payload.new;
            if (newMsg.sender_id === session.user.id) return; // Skip own inserts if handled optimistically

            const formattedMsg: Message = {
              id: newMsg.id,
              senderId: newMsg.sender_id,
              text: newMsg.content,
              timestamp: new Date(newMsg.created_at),
              isActionItem: newMsg.is_action_item,
              reactions: newMsg.reactions,
              scheduledFor: newMsg.scheduled_for ? new Date(newMsg.scheduled_for) : undefined,
              status: newMsg.status
            };

            setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return { ...c, messages: [...c.messages, formattedMsg] };
               }
               return c;
            }));
          } 
          else if (payload.eventType === 'UPDATE') {
             const updatedMsg = payload.new;
             setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return {
                   ...c,
                   messages: c.messages.map(m => m.id === updatedMsg.id ? {
                     ...m,
                     reactions: updatedMsg.reactions
                   } : m)
                 };
               }
               return c;
             }));
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string, scheduledDate?: Date) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date(),
      scheduledFor: scheduledDate,
      status: scheduledDate ? 'scheduled' : 'sent'
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text, scheduledDate);

    // AI Analysis (Local for now, could be server-side function)
    if (!scheduledDate) {
      const analysis = await detectActionItem(text);
      if (analysis.isAction) {
        const newAction: ActionItem = {
          id: Date.now().toString() + '_action',
          chatId: selectedChatId,
          sourceMessageId: tempId,
          title: analysis.title || 'New Reminder',
          dueDateTime: analysis.dateTime || 'Unspecified time',
          recurrence: analysis.recurrence,
          location: analysis.location,
          isCompleted: false
        };
        setActionItems(prev => [newAction, ...prev]);
      }
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
    setShowSettingsModal(false);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const handlePinChat = async (e: React.MouseEvent, chatId: string, currentPinned: boolean) => {
    e.stopPropagation();
    // Optimistic Update
    setChats(prev => prev.map(c => c.id === chatId ? { ...c, isPinned: !currentPinned } : c));
    await toggleChatPin(chatId, !currentPinned);
  };

  const handleStatusChange = async (status: string) => {
    if (!session?.user) return;
    const msg = status === 'busy' ? 'In a meeting' : '';
    await updateUserStatus(session.user.id, status, msg);
    // Refresh user obj logic here if needed
    setShowStatusMenu(false);
  };

  const getFilteredAndSortedChats = () => {
    if (!chats) return [];

    // 1. Filter Tab
    let filtered = chats;
    if (activeTab === 'priority') {
      filtered = chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
    } else if (activeTab === 'groups') {
      filtered = chats.filter(c => c.isGroup);
    }

    // 2. Sort Logic
    return filtered.sort((a, b) => {
      // Pinned always on top
      if (a.isPinned && !b.isPinned) return -1;
      if (!a.isPinned && b.isPinned) return 1;

      // Sort Option
      if (sortOption === 'time') {
         const timeA = a.messages.length > 0 ? new Date(a.messages[a.messages.length-1].timestamp).getTime() : 0;
         const timeB = b.messages.length > 0 ? new Date(b.messages[b.messages.length-1].timestamp).getTime() : 0;
         return timeB - timeA;
      } else if (sortOption === 'unread') {
         return (b.unreadCount || 0) - (a.unreadCount || 0);
      } else if (sortOption === 'alpha') {
         return a.name.localeCompare(b.name);
      }
      return 0;
    });
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-nexus-slate dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-mint"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden bg-nexus-slate dark:bg-nexus-dark ${darkMode ? 'dark' : ''}`}>
      {/* GLOBAL MODALS */}
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          user={currentUser}
          onClose={() => setShowSettingsModal(false)}
          onUpdate={async () => {
             const user = await getCurrentUser();
             setCurrentUser(user);
          }}
          isDarkMode={darkMode}
          toggleDarkMode={() => setDarkMode(!darkMode)}
          onLogout={handleLogout}
        />
      )}

      {activeCall && (
        <CallOverlay 
          partnerName={activeCall.partnerName}
          isVideo={activeCall.isVideo}
          onEndCall={() => setActiveCall(null)}
        />
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* === SIDEBAR / MOBILE LIST VIEW === */}
        <div className={`
          flex flex-col h-full bg-nexus-slate dark:bg-nexus-dark border-r dark:border-gray-800 transition-all duration-300
          w-full md:w-[380px] lg:w-[420px] 
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* HEADER */}
          <div className="px-6 py-5 flex justify-between items-center bg-nexus-slate dark:bg-nexus-dark z-10 sticky top-0">
            <h1 className="text-2xl font-bold tracking-tight text-nexus-midnight dark:text-white flex items-center gap-2 relative">
              <span className="w-8 h-8 bg-nexus-midnight rounded-xl flex items-center justify-center text-white text-lg shadow-lg">N</span>
              <span>Nexus</span>

              {/* STATUS INDICATOR/SELECTOR */}
              <div className="relative ml-1">
                 <button onClick={() => setShowStatusMenu(!showStatusMenu)} className="w-3 h-3 rounded-full bg-nexus-mint ring-2 ring-white dark:ring-nexus-dark hover:scale-125 transition-transform"></button>
                 {showStatusMenu && (
                   <div className="absolute top-6 left-0 w-32 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-50 animate-fade-in-down">
                      <button onClick={() => handleStatusChange('online')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-500"></span> Online
                      </button>
                      <button onClick={() => handleStatusChange('away')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-yellow-500"></span> Away
                      </button>
                      <button onClick={() => handleStatusChange('busy')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-red-500"></span> Busy
                      </button>
                   </div>
                 )}
              </div>
            </h1>

            <div className="flex items-center gap-1">
              <button onClick={() => setShowNewChatModal(true)} className="p-2.5 text-nexus-mint hover:bg-nexus-mint/10 rounded-full transition-colors">
                <Plus size={22} />
              </button>
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2.5 text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-gray-200 dark:hover:bg-gray-800 rounded-full transition-colors"
              >
                <Settings size={22} />
              </button>
            </div>
          </div>

          {/* SEARCH & SORT */}
          <div className="px-6 pb-4 flex gap-2">
            <div className="bg-white dark:bg-nexus-card rounded-2xl flex-1 flex items-center px-4 py-3 transition-all focus-within:ring-2 focus-within:ring-nexus-mint/50 shadow-sm border border-transparent dark:border-gray-800">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text" 
                placeholder="Search..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
            <div className="relative">
              <button 
                onClick={() => setShowSortMenu(!showSortMenu)} 
                className={`h-full aspect-square flex items-center justify-center rounded-2xl transition-colors shadow-sm ${showSortMenu ? 'bg-nexus-mint text-nexus-midnight' : 'bg-white dark:bg-nexus-card text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              >
                <Filter size={18} />
              </button>
              {showSortMenu && (
                <div className="absolute top-12 right-0 w-40 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-40 animate-fade-in-down">
                    <button onClick={() => { setSortOption('time'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'time' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Recent {sortOption === 'time' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('unread'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'unread' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Unread {sortOption === 'unread' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('alpha'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'alpha' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      A-Z {sortOption === 'alpha' && <CheckSquare size={14} />}
                    </button>
                </div>
              )}
            </div>
          </div>

          {/* DESKTOP TABS (Hidden on Mobile) */}
          <div className="hidden md:flex px-6 space-x-6 border-b dark:border-gray-800 mb-2">
             <button onClick={() => setActiveTab('priority')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'priority' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'groups' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'actions' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Actions
             </button>
          </div>

          {/* SCROLLABLE LIST AREA */}
          <div className="flex-1 overflow-y-auto px-4 pb-24 md:pb-4 space-y-2 no-scrollbar">
            {activeTab === 'actions' ? (
              <div className="space-y-3 pt-2">
                 {actionItems.length === 0 && (
                   <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <CheckSquare size={32} className="opacity-40" />
                     </div>
                     <p>All caught up! No pending actions.</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <div className="space-y-1 pt-2">
                 {getFilteredAndSortedChats().length === 0 && (
                   <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <MessageSquare size={32} className="opacity-40" />
                     </div>
                     <span>No chats in {activeTab}.</span>
                     <button onClick={() => setShowNewChatModal(true)} className="mt-2 text-nexus-mint font-bold hover:underline">Start a chat</button>
                   </div>
                 )}
                 {getFilteredAndSortedChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
