interface SettingsModalProps {
  user: any;
  onClose: () => void;
  onUpdate: () => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  onLogout: () => void;
}

type SettingsTab = 'account' | 'appearance' | 'notifications' | 'privacy' | 'data';

