  const HelpView = () => (
     <div className="animate-fade-in-up">
        <ListItem icon={HelpCircle} label="Help Center" onClick={() => {}} colorClass="bg-blue-100 text-blue-600" />
        <ListItem icon={FileText} label="Terms and Privacy Policy" onClick={() => {}} colorClass="bg-gray-100 text-gray-600" />
        <ListItem icon={User} label="App Info" subLabel="Nexus v2.0.4" onClick={() => {}} colorClass="bg-gray-100 text-gray-600" />
     </div>
  );

  // --- RENDER ---

  const renderView = () => {
    switch (currentView) {
      case 'profile': return <ProfileView />;
      case 'chats': return <ChatsView />;
      case 'notifications': return <NotificationsView />;
      case 'storage': return <StorageView />;
      case 'privacy': return <PrivacyView />;
      case 'help': return <HelpView />;
      default: return <MainView />;
    }
  };

  const getTitle = () => {
    switch (currentView) {
      case 'profile': return 'Profile';
      case 'chats': return 'Chats';
      case 'notifications': return 'Notifications';
      case 'storage': return 'Storage and Data';
      case 'privacy': return 'Privacy';
      case 'help': return 'Help';
      default: return 'Settings';
    }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-0 md:p-6">
      <div className="bg-white dark:bg-nexus-card w-full h-full md:h-[85vh] md:max-w-2xl md:rounded-2xl shadow-2xl border-none md:border dark:border-gray-700 flex flex-col overflow-hidden animate-fade-in-up">
        <Header title={getTitle()} showBack={currentView !== 'main'} />
        <div className="flex-1 overflow-y-auto bg-white dark:bg-nexus-card relative no-scrollbar">
           {renderView()}
        </div>
      </div>
    </div>
  );
};

export interface User {
  id: string;
  name: string;
  full_name?: string;
  avatar: string;
  email?: string;
  phone?: string;
  status?: 'online' | 'away' | 'busy' | 'offline';
  statusMessage?: string;
  preferences?: {
    dmSound?: string;
    groupSound?: string;
    mediaAutoDownload?: 'wifi' | 'cellular' | 'never';
    imageQuality?: 'standard' | 'high';
    theme?: 'light' | 'dark' | 'system';
    enterIsSend?: boolean;
    readReceipts?: boolean;
    wallpaper?: string;
  };
}

export interface Message {
  id: string;
  senderId: string;
  text: string;
  timestamp: Date;
  isActionItem?: boolean;
  reactions?: Record<string, string[]>; // emoji -> array of user IDs
  scheduledFor?: Date;
  status?: 'sent' | 'delivered' | 'read' | 'scheduled';
}

export interface Chat {
  id: string;
  name: string;
  isGroup: boolean;
  priority: 'high' | 'normal';
  unreadCount: number;
  participants: User[];
  messages: Message[];
  lastMessage?: string;
  lastMessageTime?: Date;
  created_at?: string;
  isPinned?: boolean;
  notificationSound?: string;
}

export interface ActionItem {
  id: string;
  sourceMessageId: string;
  chatId: string;
  title: string;
  dueDateTime: string;
  recurrence?: string; // New: e.g., "Weekly on Mondays"
  location?: string;   // New: e.g., "Conference Room B"
  isCompleted: boolean;
}

export type TabType = 'priority' | 'groups' | 'actions';

export type SortOption = 'time' | 'unread' | 'alpha';

export interface CallSession {
  isActive: boolean;
  isIncoming: boolean;
  isVideo: boolean;
  partnerName: string;
  partnerAvatar?: string;
  status: 'ringing' | 'connected' | 'ended';
}

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType, SortOption, CallSession } from './types';
import { detectActionItem } from './services/geminiService';
import { supabase, getCurrentUser, fetchUserChats, fetchMessages, sendMessageToDb, toggleChatPin, updateUserStatus, updateUserProfile } from './services/supabaseClient';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { AuthScreen } from './components/AuthScreen';
import { NewChatModal } from './components/NewChatModal';
import { CallOverlay } from './components/CallOverlay';
import { SettingsModal } from './components/SettingsModal';
import { 
  Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare, Plus, LogOut,
  Users, Pin, ChevronDown, Clock, Activity, Circle, Settings
} from 'lucide-react';

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [sortOption, setSortOption] = useState<SortOption>('time');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
  const [showNewChatModal, setShowNewChatModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showStatusMenu, setShowStatusMenu] = useState(false);
  const [showSortMenu, setShowSortMenu] = useState(false);

  const [chats, setChats] = useState<Chat[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);
  const [activeCall, setActiveCall] = useState<CallSession | null>(null);

  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user) {
        setCurrentUser(session.user);
        // Apply theme preference if it exists
        if (session.user.preferences?.theme === 'dark') {
          setDarkMode(true);
        }
      }
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session?.user) {
        setCurrentUser(session.user);
        if (session.user.preferences?.theme === 'dark') {
           setDarkMode(true);
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages (INSERT) and updates (UPDATE - for reactions)
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {

          if (payload.eventType === 'INSERT') {
            const newMsg = payload.new;
            if (newMsg.sender_id === session.user.id) return; // Skip own inserts if handled optimistically

            const formattedMsg: Message = {
              id: newMsg.id,
              senderId: newMsg.sender_id,
              text: newMsg.content,
              timestamp: new Date(newMsg.created_at),
              isActionItem: newMsg.is_action_item,
              reactions: newMsg.reactions,
              scheduledFor: newMsg.scheduled_for ? new Date(newMsg.scheduled_for) : undefined,
              status: newMsg.status
            };

            setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return { ...c, messages: [...c.messages, formattedMsg] };
               }
               return c;
            }));
          } 
          else if (payload.eventType === 'UPDATE') {
             const updatedMsg = payload.new;
             setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return {
                   ...c,
                   messages: c.messages.map(m => m.id === updatedMsg.id ? {
                     ...m,
                     reactions: updatedMsg.reactions
                   } : m)
                 };
               }
               return c;
             }));
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode and Persist
  const handleToggleDarkMode = async () => {
    const newMode = !darkMode;
    setDarkMode(newMode);

    // Persist to user preferences
    if (session?.user?.id) {
       await updateUserProfile(session.user.id, {
         preferences: { 
           ...currentUser?.preferences, 
           theme: newMode ? 'dark' : 'light' 
         }
       });
       // Update local user state to reflect change
       setCurrentUser((prev: any) => ({
         ...prev,
         preferences: { ...prev.preferences, theme: newMode ? 'dark' : 'light' }
       }));
    }
  };

  // Apply Dark Mode class to HTML
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string, scheduledDate?: Date) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date(),
      scheduledFor: scheduledDate,
      status: scheduledDate ? 'scheduled' : 'sent'
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text, scheduledDate);

    // AI Analysis (Local for now, could be server-side function)
    if (!scheduledDate) {
      const analysis = await detectActionItem(text);
      if (analysis.isAction) {
        const newAction: ActionItem = {
          id: Date.now().toString() + '_action',
          chatId: selectedChatId,
          sourceMessageId: tempId,
          title: analysis.title || 'New Reminder',
          dueDateTime: analysis.dateTime || 'Unspecified time',
          recurrence: analysis.recurrence,
          location: analysis.location,
          isCompleted: false
        };
        setActionItems(prev => [newAction, ...prev]);
      }
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
    setShowSettingsModal(false);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const handlePinChat = async (e: React.MouseEvent, chatId: string, currentPinned: boolean) => {
    e.stopPropagation();
    // Optimistic Update
    setChats(prev => prev.map(c => c.id === chatId ? { ...c, isPinned: !currentPinned } : c));
    await toggleChatPin(chatId, !currentPinned);
  };

  const handleStatusChange = async (status: string) => {
    if (!session?.user) return;
    const msg = status === 'busy' ? 'In a meeting' : '';
    await updateUserStatus(session.user.id, status, msg);
    setCurrentUser((prev: any) => ({ ...prev, status: status, statusMessage: msg }));
    setShowStatusMenu(false);
  };

  const getFilteredAndSortedChats = () => {
    if (!chats) return [];

    // 1. Filter Tab
    let filtered = chats;
    if (activeTab === 'priority') {
      filtered = chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
    } else if (activeTab === 'groups') {
      filtered = chats.filter(c => c.isGroup);
    }

    // 2. Sort Logic
    return filtered.sort((a, b) => {
      // Pinned always on top
      if (a.isPinned && !b.isPinned) return -1;
      if (!a.isPinned && b.isPinned) return 1;

      // Sort Option
      if (sortOption === 'time') {
         const timeA = a.messages.length > 0 ? new Date(a.messages[a.messages.length-1].timestamp).getTime() : 0;
         const timeB = b.messages.length > 0 ? new Date(b.messages[b.messages.length-1].timestamp).getTime() : 0;
         return timeB - timeA;
      } else if (sortOption === 'unread') {
         return (b.unreadCount || 0) - (a.unreadCount || 0);
      } else if (sortOption === 'alpha') {
         return a.name.localeCompare(b.name);
      }
      return 0;
    });
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-nexus-slate dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-mint"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden bg-nexus-slate dark:bg-nexus-dark ${darkMode ? 'dark' : ''}`}>
      {/* GLOBAL MODALS */}
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          user={currentUser}
          onClose={() => setShowSettingsModal(false)}
          onUpdate={async () => {
             const user = await getCurrentUser();
             setCurrentUser(user);
          }}
          isDarkMode={darkMode}
          toggleDarkMode={handleToggleDarkMode}
          onLogout={handleLogout}
        />
      )}

      {activeCall && (
        <CallOverlay 
          partnerName={activeCall.partnerName}
          isVideo={activeCall.isVideo}
          onEndCall={() => setActiveCall(null)}
        />
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* === SIDEBAR / MOBILE LIST VIEW === */}
        <div className={`
          flex flex-col h-full bg-nexus-slate dark:bg-nexus-dark border-r dark:border-gray-800 transition-all duration-300
          w-full md:w-[380px] lg:w-[420px] 
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* HEADER */}
          <div className="px-6 py-5 flex justify-between items-center bg-nexus-slate dark:bg-nexus-dark z-10 sticky top-0">
            <h1 className="text-2xl font-bold tracking-tight text-nexus-midnight dark:text-white flex items-center gap-2 relative">
              <span className="w-8 h-8 bg-nexus-midnight rounded-xl flex items-center justify-center text-white text-lg shadow-lg">N</span>
              <span>Nexus</span>

              {/* STATUS INDICATOR/SELECTOR */}
              <div className="relative ml-1">
                 <button onClick={() => setShowStatusMenu(!showStatusMenu)} className={`w-3 h-3 rounded-full ring-2 ring-white dark:ring-nexus-dark hover:scale-125 transition-transform ${currentUser?.status === 'online' ? 'bg-green-500' : currentUser?.status === 'busy' ? 'bg-red-500' : 'bg-yellow-500'}`}></button>
                 {showStatusMenu && (
                   <div className="absolute top-6 left-0 w-32 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-50 animate-fade-in-down">
                      <button onClick={() => handleStatusChange('online')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-500"></span> Online
                      </button>
                      <button onClick={() => handleStatusChange('away')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-yellow-500"></span> Away
                      </button>
                      <button onClick={() => handleStatusChange('busy')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-red-500"></span> Busy
                      </button>
                   </div>
                 )}
              </div>
            </h1>

            <div className="flex items-center gap-1">
              <button onClick={() => setShowNewChatModal(true)} className="p-2.5 text-nexus-mint hover:bg-nexus-mint/10 rounded-full transition-colors">
                <Plus size={22} />
              </button>
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2.5 text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-gray-200 dark:hover:bg-gray-800 rounded-full transition-colors"
              >
                <Settings size={22} />
              </button>
            </div>
          </div>

          {/* SEARCH & SORT */}
          <div className="px-6 pb-4 flex gap-2">
            <div className="bg-white dark:bg-nexus-card rounded-2xl flex-1 flex items-center px-4 py-3 transition-all focus-within:ring-2 focus-within:ring-nexus-mint/50 shadow-sm border border-transparent dark:border-gray-800">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text" 
                placeholder="Search..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
            <div className="relative">
              <button 
                onClick={() => setShowSortMenu(!showSortMenu)} 
                className={`h-full aspect-square flex items-center justify-center rounded-2xl transition-colors shadow-sm ${showSortMenu ? 'bg-nexus-mint text-nexus-midnight' : 'bg-white dark:bg-nexus-card text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              >
                <Filter size={18} />
              </button>
              {showSortMenu && (
                <div className="absolute top-12 right-0 w-40 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-40 animate-fade-in-down">
                    <button onClick={() => { setSortOption('time'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'time' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Recent {sortOption === 'time' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('unread'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'unread' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Unread {sortOption === 'unread' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('alpha'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'alpha' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      A-Z {sortOption === 'alpha' && <CheckSquare size={14} />}
                    </button>
                </div>
              )}
            </div>
          </div>

          {/* DESKTOP TABS (Hidden on Mobile) */}
          <div className="hidden md:flex px-6 space-x-6 border-b dark:border-gray-800 mb-2">
             <button onClick={() => setActiveTab('priority')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'priority' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'groups' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'actions' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Actions
             </button>
          </div>

          {/* SCROLLABLE LIST AREA */}
          <div className="flex-1 overflow-y-auto px-4 pb-24 md:pb-4 space-y-2 no-scrollbar">
            {activeTab === 'actions' ? (
              <div className="space-y-3 pt-2">
                 {actionItems.length === 0 && (
                   <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <CheckSquare size={32} className="opacity-40" />
                     </div>
                     <p>All caught up! No pending actions.</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <div className="space-y-1 pt-2">
                 {getFilteredAndSortedChats().length === 0 && (
                   <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <MessageSquare size={32} className="opacity-40" />
                     </div>
                     <span>No chats in {activeTab}.</span>
                     <button onClick={() => setShowNewChatModal(true)} className="mt-2 text-nexus-mint font-bold hover:underline">Start a chat</button>
                   </div>
                 )}
                 {getFilteredAndSortedChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
                       onClick={() => setSelectedChatId(chat.id)}
                       className={`w-full flex items-start p-4 rounded-2xl transition-all duration-200 group relative border border-transparent ${
                         selectedChatId === chat.id 
                           ? 'bg-nexus-midnight text-white shadow-xl shadow-nexus-midnight/20' 
                           : 'hover:bg-white dark:hover:bg-nexus-card hover:border-gray-100 dark:hover:border-gray-800'
                       }`}
                     >
                       <div className="relative mr-4 flex-shrink-0">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-bold transition-colors ${
                            selectedChatId === chat.id 
                              ? 'bg-white/20 text-white' 
                              : 'bg-white dark:bg-nexus-card text-nexus-midnight dark:text-gray-300 shadow-sm'
                          }`}>
                            {chat.name[0]}
                          </div>
                          {chat.isGroup && (
                            <div className="absolute -bottom-1 -right-1 bg-nexus-slate dark:bg-nexus-dark rounded-full p-0.5">
                              <div className="bg-nexus-mint text-nexus-midnight rounded-full p-0.5">
                                <Users size={10} />
                              </div>
                            </div>
                          )}
                          {chat.isPinned && (
                            <div className="absolute -top-1 -left-1 bg-nexus-slate dark:bg-nexus-dark rounded-full p-0.5">
                               <div className="bg-white dark:bg-nexus-card text-gray-400 p-0.5 rounded-full shadow-sm">
                                <Pin size={8} fill="currentColor" />
                               </div>
                            </div>
                          )}
                       </div>

                       <div className="flex-1 text-left min-w-0 py-0.5">
                         <div className="flex justify-between items-center mb-1">
                           <h3 className={`font-bold truncate text-[15px] ${selectedChatId === chat.id ? 'text-white' : 'text-nexus-midnight dark:text-white'}`}>
                             {chat.name}
                           </h3>
                           <div className="flex items-center gap-1">
                              {chat.isPinned && <Pin size={10} className={`${selectedChatId === chat.id ? 'text-nexus-mint' : 'text-gray-400'} rotate-45`} fill="currentColor" />}
                              <span className={`text-[11px] font-medium ${selectedChatId === chat.id ? 'text-gray-300' : 'text-gray-400 group-hover:text-gray-500'}`}>
                                {lastMsg?.timestamp ? new Date(lastMsg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                              </span>
                           </div>
                         </div>
                         <p className={`text-[13px] truncate leading-relaxed ${selectedChatId === chat.id ? 'text-gray-300' : 'text-gray-500 dark:text-gray-400'}`}>
                           {lastMsg?.senderId === 'me' && <span className="opacity-70">You: </span>}
                           {lastMsg?.text || <span className="italic opacity-60">Start the conversation</span>}
                         </p>
                       </div>

                       {/* Hover Action: Pin */}
                       <div className="absolute right-2 bottom-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <div 
                            onClick={(e) => handlePinChat(e, chat.id, !!chat.isPinned)}
                            className={`p-1.5 rounded-full hover:bg-black/10 dark:hover:bg-white/10 ${selectedChatId === chat.id ? 'text-white' : 'text-gray-400'}`}
                            title={chat.isPinned ? "Unpin" : "Pin"}
                          >
                            <Pin size={14} fill={chat.isPinned ? "currentColor" : "none"} />
                          </div>
                       </div>
                     </button>
                   );
                 })}
              </div>
            )}
          </div>

          {/* MOBILE BOTTOM NAVIGATION */}
          <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-nexus-dark border-t dark:border-gray-800 pb-safe z-30 flex justify-around items-center h-20 px-2 shadow-[0_-5px_10px_rgba(0,0,0,0.02)]">
            <button 
              onClick={() => setActiveTab('priority')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'priority' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <Star size={24} fill={activeTab === 'priority' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Priority</span>
            </button>
            <button 
              onClick={() => setActiveTab('groups')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'groups' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <Users size={24} fill={activeTab === 'groups' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Groups</span>
            </button>
            <button 
              onClick={() => setActiveTab('actions')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'actions' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <div className="relative">
                <Zap size={24} fill={activeTab === 'actions' ? "currentColor" : "none"} />
                {actionItems.some(i => !i.isCompleted) && (
                  <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-nexus-coral rounded-full border-2 border-white dark:border-nexus-dark"></span>
                )}
              </div>
              <span className="text-[10px] font-bold">Actions</span>
            </button>
          </div>
        </div>

        {/* === CHAT AREA === */}
        <div className={`
          flex-1 bg-white/50 dark:bg-black/20 relative
          ${!selectedChatId ? 'hidden md:flex items-center justify-center' : 'flex w-full absolute inset-0 md:static z-20'}
        `}>
          {activeChat ? (
            <ChatInterface 
              chat={activeChat} 
              onBack={() => setSelectedChatId(null)}
              onSendMessage={handleSendMessage}
              onCallStart={(isVideo) => setActiveCall({
                isActive: true,
                isIncoming: false,
                isVideo,
                partnerName: activeChat.name,
                status: 'ringing'
              })}
            />
          ) : (
            <div className="text-center opacity-40 max-w-sm px-6">
              <div className="w-32 h-32 bg-white dark:bg-nexus-card rounded-[2rem] mx-auto mb-8 flex items-center justify-center rotate-3 transform transition-transform hover:rotate-6 shadow-sm">
                 <MessageSquare size={64} className="text-nexus-midnight dark:text-gray-400" />
              </div>
              <h2 className="text-3xl font-bold text-nexus-midnight dark:text-white mb-3">Nexus Web</h2>
              <p className="text-gray-500 dark:text-gray-400 text-lg leading-relaxed">
                Select a conversation from the sidebar to start messaging. 
                <br />Experience the future of triage.
              </p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  X, User, Bell, Moon, Camera, LogOut, ChevronRight, 
  ArrowLeft, Lock, Database, HelpCircle, FileText, 
  Smartphone, Sun, Check, Image as ImageIcon, Wifi, Volume2, HardDrive
} from 'lucide-react';
import { updateUserProfile } from '../services/supabaseClient';

interface SettingsModalProps {
  user: any;
  onClose: () => void;
  onUpdate: () => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  onLogout: () => void;
}

type SettingsView = 'main' | 'profile' | 'chats' | 'notifications' | 'storage' | 'help' | 'privacy';

const NOTIFICATION_SOUNDS = [
  { id: 'default', name: 'Default (Chime)' },
  { id: 'pop', name: 'Pop' },
  { id: 'tweet', name: 'Bird Tweet' },
  { id: 'subtle', name: 'Subtle Pulse' },
];

const SectionTitle = ({ children }: { children: React.ReactNode }) => (
  <div className="px-4 py-3 text-sm font-bold text-nexus-mint uppercase tracking-wider bg-gray-50/50 dark:bg-black/20">
    {children}
  </div>
);

const ListItem = ({ 
  icon: Icon, 
  label, 
  subLabel, 
  onClick, 
  colorClass = "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300",
  rightElement,
  danger = false
}: any) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 p-4 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors border-b border-gray-50 dark:border-gray-800/50 last:border-0 text-left group`}
  >
    {Icon && (
      <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${colorClass}`}>
        <Icon size={20} />
      </div>
    )}
    <div className="flex-1 min-w-0">
      <div className={`font-medium text-base ${danger ? 'text-nexus-coral' : 'text-nexus-midnight dark:text-white'}`}>
        {label}
      </div>
      {subLabel && <div className="text-sm text-gray-500 truncate">{subLabel}</div>}
    </div>
    {rightElement ? rightElement : <ChevronRight size={18} className="text-gray-300 dark:text-gray-600" />}
  </button>
);

export const SettingsModal: React.FC<SettingsModalProps> = ({ 
  user, onClose, onUpdate, isDarkMode, toggleDarkMode, onLogout 
}) => {
  const [currentView, setCurrentView] = useState<SettingsView>('main');

  // Local State for Form Data
  const [formData, setFormData] = useState({
    full_name: user?.full_name || '',
    email: user?.email || '',
    statusMessage: user?.statusMessage || '',
  });

  // Local State for Preferences
  const [preferences, setPreferences] = useState({
      dmSound: user?.preferences?.dmSound || 'default',
      groupSound: user?.preferences?.groupSound || 'default',
      mediaAutoDownload: user?.preferences?.mediaAutoDownload || 'wifi',
      imageQuality: user?.preferences?.imageQuality || 'standard',
      enterIsSend: user?.preferences?.enterIsSend || false,
      readReceipts: user?.preferences?.readReceipts ?? true,
      wallpaper: user?.preferences?.wallpaper || 'default',
  });

  const [saving, setSaving] = useState(false);

  // Generic Save Helper
  const saveChanges = async (newData: any, newPreferences: any) => {
    setSaving(true);
    try {
      await updateUserProfile(user.id, {
          ...newData,
          preferences: newPreferences
      });
      onUpdate(); // Refresh parent state
      setTimeout(() => setSaving(false), 300);
    } catch (e) {
      console.error("Save failed", e);
      setSaving(false);
    }
  };

  // Handler for text input blur (Auto-Save)
  const handleBlur = () => {
    saveChanges(formData, preferences);
  };

  // Handler for immediate preference toggle
  const updatePreference = (key: string, value: any) => {
    const newPrefs = { ...preferences, [key]: value };
    setPreferences(newPrefs);
    saveChanges(formData, newPrefs);
  };

  // --- REUSABLE COMPONENTS ---

  const Header = ({ title, showBack = false }: { title: string, showBack?: boolean }) => (
    <div className="flex items-center px-4 py-3 md:px-6 md:py-4 border-b border-gray-100 dark:border-gray-800 bg-white dark:bg-nexus-card sticky top-0 z-10">
      <div className="flex items-center gap-3 flex-1">
        {showBack && (
          <button 
            onClick={() => {
              // Ensure we save any pending text changes when navigating back
              if (currentView === 'profile') saveChanges(formData, preferences);
              setCurrentView('main');
            }} 
            className="p-1.5 -ml-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 text-nexus-midnight dark:text-white transition-colors"
          >
            <ArrowLeft size={20} />
          </button>
        )}
        <h2 className="text-xl font-bold text-nexus-midnight dark:text-white">{title}</h2>
      </div>
      {!showBack && (
        <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-500">
          <X size={20} />
        </button>
      )}
    </div>
  );

  // --- VIEWS ---

  const MainView = () => (
    <div className="animate-fade-in-up">
      {/* Profile Card */}
      <div 
        onClick={() => setCurrentView('profile')}
        className="flex items-center gap-4 p-4 md:p-6 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors border-b border-gray-100 dark:border-gray-800"
      >
        <div className="w-16 h-16 rounded-full bg-nexus-midnight flex items-center justify-center text-2xl font-bold text-white shadow-md overflow-hidden border-2 border-white dark:border-gray-700">
           {formData.full_name[0] || '?'}
        </div>
        <div className="flex-1">
           <h3 className="text-lg font-bold text-nexus-midnight dark:text-white">{formData.full_name}</h3>
           <p className="text-gray-500 text-sm line-clamp-1">{formData.statusMessage || "No status set"}</p>
        </div>
        <div className="p-2 bg-nexus-slate dark:bg-gray-800 rounded-full text-nexus-mint">
           <User size={20} />
        </div>
      </div>

      <div className="py-2">
        <ListItem 
          icon={Lock} 
          label="Privacy" 
          subLabel="Block contacts, disappearing messages" 
          colorClass="bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-300"
          onClick={() => setCurrentView('privacy')}
        />
        <ListItem 
          icon={User} 
          label="Chats" 
          subLabel="Theme, wallpapers, chat history" 
          colorClass="bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-300"
          onClick={() => setCurrentView('chats')}
        />
        <ListItem 
          icon={Bell} 
          label="Notifications" 
          subLabel="Message, group & call tones" 
          colorClass="bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-300"
          onClick={() => setCurrentView('notifications')}
        />
        <ListItem 
          icon={Database} 
          label="Storage and Data" 
          subLabel="Network usage, auto-download" 
          colorClass="bg-yellow-100 text-yellow-600 dark:bg-yellow-900/30 dark:text-yellow-300"
          onClick={() => setCurrentView('storage')}
        />
        <ListItem 
          icon={HelpCircle} 
          label="Help" 
          subLabel="Help center, contact us, privacy policy" 
          colorClass="bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300"
          onClick={() => setCurrentView('help')}
        />
      </div>

      <div className="mt-4 px-4">
        <button 
          onClick={onLogout}
          className="w-full py-3 flex items-center justify-center gap-2 text-nexus-coral font-bold bg-nexus-coral/10 hover:bg-nexus-coral/20 rounded-xl transition-colors"
        >
          <LogOut size={18} /> Log Out
        </button>
        <div className="text-center mt-4 pb-4">
          <p className="text-xs text-gray-400">Nexus for Web</p>
          <p className="text-xs text-gray-300">Version 2.0.4</p>
        </div>
      </div>
    </div>
  );

  const ProfileView = () => (
    <div className="animate-fade-in-up pb-20">
      <div className="flex flex-col items-center py-8 bg-gray-50 dark:bg-black/20 border-b border-gray-100 dark:border-gray-800">
        <div className="relative group cursor-pointer mb-4">
           <div className="w-32 h-32 rounded-full bg-nexus-midnight flex items-center justify-center text-5xl font-bold text-white shadow-xl overflow-hidden border-4 border-white dark:border-gray-800">
              {formData.full_name[0] || '?'}
           </div>
           {/* Mock File Input */}
           <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" title="Upload Photo" />
           <div className="absolute inset-0 bg-black/40 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
              <Camera className="text-white" size={32} />
           </div>
        </div>
        <p className="text-sm text-gray-500">Tap to change profile photo</p>
      </div>

      <div className="p-4 space-y-6">
        <div>
          <label className="block text-xs font-bold uppercase text-nexus-mint mb-2">Your Name</label>
          <div className="flex items-center gap-3 border-b border-gray-200 dark:border-gray-700 pb-2 focus-within:border-nexus-mint transition-colors">
             <User size={20} className="text-gray-400" />
             <input 
               type="text" 
               value={formData.full_name}
               onChange={(e) => setFormData({...formData, full_name: e.target.value})}
               onBlur={handleBlur}
               className="flex-1 bg-transparent border-none outline-none text-nexus-midnight dark:text-white font-medium"
             />
             <div className={`text-nexus-mint transition-opacity ${saving ? 'opacity-100' : 'opacity-0'}`}><Check size={18} /></div>
          </div>
          <p className="text-xs text-gray-400 mt-2">This name will be visible to your Nexus contacts.</p>
        </div>

        <div>
          <label className="block text-xs font-bold uppercase text-nexus-mint mb-2">About</label>
          <div className="flex items-center gap-3 border-b border-gray-200 dark:border-gray-700 pb-2 focus-within:border-nexus-mint transition-colors">
             <FileText size={20} className="text-gray-400" />
             <input 
               type="text" 
               value={formData.statusMessage}
               onChange={(e) => setFormData({...formData, statusMessage: e.target.value})}
               onBlur={handleBlur}
               maxLength={140}
               className="flex-1 bg-transparent border-none outline-none text-nexus-midnight dark:text-white font-medium"
             />
             <span className={`text-xs ${formData.statusMessage.length > 130 ? 'text-nexus-coral' : 'text-gray-400'}`}>
               {140 - formData.statusMessage.length}
             </span>
          </div>
        </div>

        <div>
           <label className="block text-xs font-bold uppercase text-nexus-mint mb-2">Email</label>
           <div className="flex items-center gap-3 border-b border-gray-200 dark:border-gray-700 pb-2 opacity-50">
             <div className="text-gray-400 text-sm">{formData.email}</div>
           </div>
        </div>
      </div>
    </div>
  );

  const ChatsView = () => (
    <div className="animate-fade-in-up">
       <SectionTitle>Display</SectionTitle>
       <ListItem 
         icon={isDarkMode ? Moon : Sun} 
         label="Theme" 
         subLabel={isDarkMode ? "Dark" : "Light"}
         onClick={toggleDarkMode}
         colorClass="bg-indigo-100 text-indigo-600 dark:bg-indigo-900/30 dark:text-indigo-300"
         rightElement={
            <div className={`w-12 h-6 rounded-full relative transition-colors ${isDarkMode ? 'bg-nexus-mint' : 'bg-gray-300 dark:bg-gray-600'}`}>
              <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-7' : 'translate-x-1'}`}></div>
            </div>
         }
       />
       <ListItem 
         icon={ImageIcon} 
         label="Wallpaper" 
         subLabel={preferences.wallpaper === 'default' ? "Default" : "Custom"}
         colorClass="bg-pink-100 text-pink-600 dark:bg-pink-900/30 dark:text-pink-300"
         onClick={() => {
             const next = preferences.wallpaper === 'default' ? 'custom' : 'default';
             updatePreference('wallpaper', next);
         }}
       />

       <SectionTitle>Chat Settings</SectionTitle>
       <ListItem 
         icon={Smartphone} 
         label="Enter is Send" 
         subLabel="Enter key will send your message" 
         colorClass="bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300"
         onClick={() => updatePreference('enterIsSend', !preferences.enterIsSend)}
         rightElement={
            <div className={`w-12 h-6 rounded-full relative transition-colors ${preferences.enterIsSend ? 'bg-nexus-mint' : 'bg-gray-300 dark:bg-gray-600'}`}>
              <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-transform ${preferences.enterIsSend ? 'translate-x-7' : 'translate-x-1'}`}></div>
            </div>
         }
       />
    </div>
  );

  const NotificationsView = () => (
    <div className="animate-fade-in-up pb-20">
      <SectionTitle>Messages</SectionTitle>
      <div className="px-4 py-3 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center">
        <div>
           <div className="font-medium text-nexus-midnight dark:text-white">Notification Tone</div>
           <div className="text-sm text-gray-500">Select sound for incoming messages</div>
        </div>
        <select 
          value={preferences.dmSound}
          onChange={(e) => updatePreference('dmSound', e.target.value)}
          className="bg-gray-100 dark:bg-gray-800 border-none rounded-lg p-2 text-sm outline-none dark:text-white"
        >
            {NOTIFICATION_SOUNDS.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
        </select>
      </div>

      <SectionTitle>Groups</SectionTitle>
      <div className="px-4 py-3 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center">
        <div>
           <div className="font-medium text-nexus-midnight dark:text-white">Notification Tone</div>
           <div className="text-sm text-gray-500">Select sound for group messages</div>
        </div>
        <select 
          value={preferences.groupSound}
          onChange={(e) => updatePreference('groupSound', e.target.value)}
          className="bg-gray-100 dark:bg-gray-800 border-none rounded-lg p-2 text-sm outline-none dark:text-white"
        >
            {NOTIFICATION_SOUNDS.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
        </select>
      </div>
    </div>
  );

  const StorageView = () => (
    <div className="animate-fade-in-up pb-20">
      <SectionTitle>Storage</SectionTitle>
      <ListItem 
         icon={HardDrive} 
         label="Manage Storage" 
         subLabel="2.4 GB used" 
         colorClass="bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-300"
         onClick={() => {}}
         rightElement={<div className="h-1 w-12 bg-blue-200 rounded-full overflow-hidden"><div className="h-full w-1/2 bg-blue-500"></div></div>}
      />

      <SectionTitle>Media Auto-Download</SectionTitle>
      <div className="p-4 border-b border-gray-100 dark:border-gray-800">
         <div className="flex gap-2 bg-gray-100 dark:bg-gray-800 p-1 rounded-lg">
            {['wifi', 'cellular', 'never'].map((opt) => (
               <button 
                 key={opt}
                 onClick={() => updatePreference('mediaAutoDownload', opt)}
                 className={`flex-1 py-2 text-xs font-bold capitalize rounded-md transition-all ${
                    preferences.mediaAutoDownload === opt 
                    ? 'bg-white dark:bg-gray-700 shadow text-nexus-midnight dark:text-white' 
                    : 'text-gray-500'
                 }`}
               >
                 {opt === 'wifi' ? 'Wi-Fi' : opt}
               </button>
            ))}
         </div>
         <p className="text-xs text-gray-400 mt-2">Voice messages are always automatically downloaded.</p>
      </div>

      <SectionTitle>Media Upload Quality</SectionTitle>
      <div className="px-4 py-3 flex justify-between items-center">
        <div>
           <div className="font-medium text-nexus-midnight dark:text-white">Photo Quality</div>
           <div className="text-sm text-gray-500">Best quality (larger size)</div>
        </div>
        <select 
          value={preferences.imageQuality}
          onChange={(e) => updatePreference('imageQuality', e.target.value)}
          className="bg-gray-100 dark:bg-gray-800 border-none rounded-lg p-2 text-sm outline-none dark:text-white"
        >
           <option value="standard">Data Saver</option>
           <option value="high">Best Quality</option>
        </select>
      </div>
    </div>
  );

  const PrivacyView = () => (
    <div className="animate-fade-in-up pb-20">
      <SectionTitle>Privacy</SectionTitle>
       <ListItem 
         icon={User} 
         label="Last Seen & Online" 
         subLabel="Everyone" 
         colorClass="bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300"
         onClick={() => {}}
       />
       <ListItem 
         icon={ImageIcon} 
         label="Profile Photo" 
         subLabel="Everyone" 
         colorClass="bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300"
         onClick={() => {}}
       />
       <ListItem 
         icon={FileText} 
         label="About" 
         subLabel="Everyone" 
         colorClass="bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300"
         onClick={() => {}}
       />

       <div className="px-4 py-4 flex items-center justify-between border-b border-gray-100 dark:border-gray-800">
          <div>
            <div className="font-medium text-nexus-midnight dark:text-white">Read Receipts</div>
            <div className="text-sm text-gray-500 max-w-xs">If turned off, you won't send or receive read receipts.</div>
          </div>
          <button 
             onClick={() => updatePreference('readReceipts', !preferences.readReceipts)}
             className={`w-12 h-6 rounded-full relative transition-colors ${preferences.readReceipts ? 'bg-nexus-mint' : 'bg-gray-300 dark:bg-gray-600'}`}
          >
             <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-transform ${preferences.readReceipts ? 'translate-x-7' : 'translate-x-1'}`}></div>
          </button>
       </div>
    </div>
  );

  const HelpView = () => (
     <div className="animate-fade-in-up">
        <ListItem icon={HelpCircle} label="Help Center" onClick={() => {}} colorClass="bg-blue-100 text-blue-600" />
        <ListItem icon={FileText} label="Terms and Privacy Policy" onClick={() => {}} colorClass="bg-gray-100 text-gray-600" />
        <ListItem icon={User} label="App Info" subLabel="Nexus v2.0.4" onClick={() => {}} colorClass="bg-gray-100 text-gray-600" />
     </div>
  );

  // --- RENDER ---

  const renderView = () => {
    switch (currentView) {
      case 'profile': return <ProfileView />;
      case 'chats': return <ChatsView />;
      case 'notifications': return <NotificationsView />;
      case 'storage': return <StorageView />;
      case 'privacy': return <PrivacyView />;
      case 'help': return <HelpView />;
      default: return <MainView />;
    }
  };

  const getTitle = () => {
    switch (currentView) {
      case 'profile': return 'Profile';
      case 'chats': return 'Chats';
      case 'notifications': return 'Notifications';
      case 'storage': return 'Storage and Data';
      case 'privacy': return 'Privacy';
      case 'help': return 'Help';
      default: return 'Settings';
    }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-0 md:p-6">
