export const AuthScreen = ({ onAuthSuccess }: { onAuthSuccess: () => void }) => {
  const [view, setView] = useState<'welcome' | 'login' | 'signup'>('welcome');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (view === 'login') {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
      } else {
        const { data, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, phone: phone } }
        });
        if (signUpError) throw signUpError;
      }
      onAuthSuccess();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // 1. Welcome / Landing Page View
  if (view === 'welcome') {
      return (
          <div className="h-screen w-full bg-nexus-midnight flex flex-col items-center justify-between p-8 relative overflow-hidden">
             {/* Background Effects */}
             <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-nexus-mint/20 to-transparent opacity-30 pointer-events-none" />
             <div className="absolute -top-20 -right-20 w-64 h-64 bg-nexus-mint rounded-full blur-[100px] opacity-20 pointer-events-none" />
             <div className="absolute bottom-0 left-0 w-full h-1/3 bg-gradient-to-t from-black/50 to-transparent pointer-events-none" />

             <div className="flex-1 flex flex-col items-center justify-center z-10 w-full">
                <div className="w-24 h-24 bg-gradient-to-tr from-nexus-mint to-teal-400 rounded-3xl flex items-center justify-center shadow-[0_0_40px_rgba(42,245,152,0.4)] mb-8 transform rotate-3 animate-fade-in-down">
                   <span className="text-nexus-midnight text-5xl font-bold">N</span>
                </div>
                <h1 className="text-4xl md:text-5xl font-bold text-white mb-4 tracking-tight text-center">Nexus</h1>
                <p className="text-gray-400 text-center max-w-xs text-lg leading-relaxed">
