  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user) {
        setCurrentUser(session.user);
        // Apply theme preference if it exists
        if (session.user.preferences?.theme === 'dark') {
          setDarkMode(true);
        }
      }
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session?.user) {
        setCurrentUser(session.user);
        if (session.user.preferences?.theme === 'dark') {
           setDarkMode(true);
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages (INSERT) and updates (UPDATE - for reactions)
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {

          if (payload.eventType === 'INSERT') {
            const newMsg = payload.new;
            if (newMsg.sender_id === session.user.id) return; // Skip own inserts if handled optimistically

            const formattedMsg: Message = {
              id: newMsg.id,
              senderId: newMsg.sender_id,
              text: newMsg.content,
              timestamp: new Date(newMsg.created_at),
              isActionItem: newMsg.is_action_item,
              reactions: newMsg.reactions,
              scheduledFor: newMsg.scheduled_for ? new Date(newMsg.scheduled_for) : undefined,
              status: newMsg.status
            };

            setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return { ...c, messages: [...c.messages, formattedMsg] };
               }
               return c;
            }));
          } 
          else if (payload.eventType === 'UPDATE') {
             const updatedMsg = payload.new;
             setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return {
                   ...c,
                   messages: c.messages.map(m => m.id === updatedMsg.id ? {
                     ...m,
                     reactions: updatedMsg.reactions
                   } : m)
                 };
               }
               return c;
             }));
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode and Persist
  const handleToggleDarkMode = async () => {
    const newMode = !darkMode;
    setDarkMode(newMode);

    // Persist to user preferences
    if (session?.user?.id) {
       await updateUserProfile(session.user.id, {
         preferences: { 
           ...currentUser?.preferences, 
           theme: newMode ? 'dark' : 'light' 
         }
       });
       // Update local user state to reflect change
       setCurrentUser((prev: any) => ({
         ...prev,
         preferences: { ...prev.preferences, theme: newMode ? 'dark' : 'light' }
       }));
    }
  };

  // Apply Dark Mode class to HTML
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string, scheduledDate?: Date) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date(),
      scheduledFor: scheduledDate,
      status: scheduledDate ? 'scheduled' : 'sent'
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text, scheduledDate);

    // AI Analysis DISABLED as per request
    /*
    if (!scheduledDate) {
      const analysis = await detectActionItem(text);
      if (analysis.isAction) {
        // ... action item logic
      }
    }
    */
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
    setShowSettingsModal(false);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const handlePinChat = async (e: React.MouseEvent, chatId: string, currentPinned: boolean) => {
    e.stopPropagation();
    // Optimistic Update
    setChats(prev => prev.map(c => c.id === chatId ? { ...c, isPinned: !currentPinned } : c));
    await toggleChatPin(chatId, !currentPinned);
  };

  const handleStatusChange = async (status: string) => {
    if (!session?.user) return;
    const msg = status === 'busy' ? 'In a meeting' : '';
    await updateUserStatus(session.user.id, status, msg);
    setCurrentUser((prev: any) => ({ ...prev, status: status, statusMessage: msg }));
    setShowStatusMenu(false);
  };

  const getFilteredAndSortedChats = () => {
    if (!chats) return [];

    // 1. Filter Tab
    let filtered = chats;
    if (activeTab === 'priority') {
      filtered = chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
    } else if (activeTab === 'groups') {
      filtered = chats.filter(c => c.isGroup);
    }

    // 2. Sort Logic
    return filtered.sort((a, b) => {
      // Pinned always on top
      if (a.isPinned && !b.isPinned) return -1;
      if (!a.isPinned && b.isPinned) return 1;

      // Sort Option
      if (sortOption === 'time') {
         const timeA = a.messages.length > 0 ? new Date(a.messages[a.messages.length-1].timestamp).getTime() : 0;
         const timeB = b.messages.length > 0 ? new Date(b.messages[b.messages.length-1].timestamp).getTime() : 0;
         return timeB - timeA;
      } else if (sortOption === 'unread') {
         return (b.unreadCount || 0) - (a.unreadCount || 0);
      } else if (sortOption === 'alpha') {
         return a.name.localeCompare(b.name);
      }
      return 0;
    });
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-nexus-slate dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-mint"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden bg-nexus-slate dark:bg-nexus-dark ${darkMode ? 'dark' : ''}`}>
      {/* GLOBAL MODALS */}
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          user={currentUser}
          onClose={() => setShowSettingsModal(false)}
          onUpdate={async () => {
             const user = await getCurrentUser();
             setCurrentUser(user);
          }}
          isDarkMode={darkMode}
          toggleDarkMode={handleToggleDarkMode}
          onLogout={handleLogout}
        />
      )}

      {activeCall && (
        <CallOverlay 
          partnerName={activeCall.partnerName}
          isVideo={activeCall.isVideo}
          onEndCall={() => setActiveCall(null)}
        />
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* === SIDEBAR / MOBILE LIST VIEW === */}
        <div className={`
          flex flex-col h-full bg-nexus-slate dark:bg-nexus-dark border-r dark:border-gray-800 transition-all duration-300
          w-full md:w-[380px] lg:w-[420px] 
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* HEADER */}
          <div className="px-6 py-5 flex justify-between items-center bg-nexus-slate dark:bg-nexus-dark z-10 sticky top-0">
            <h1 className="text-2xl font-bold tracking-tight text-nexus-midnight dark:text-white flex items-center gap-2 relative">
              <Logo className="w-8 h-8" />
              <span>Nexus</span>

              {/* STATUS INDICATOR/SELECTOR */}
              <div className="relative ml-1">
                 <button onClick={() => setShowStatusMenu(!showStatusMenu)} className={`w-3 h-3 rounded-full ring-2 ring-white dark:ring-nexus-dark hover:scale-125 transition-transform ${currentUser?.status === 'online' ? 'bg-green-500' : currentUser?.status === 'busy' ? 'bg-red-500' : 'bg-yellow-500'}`}></button>
                 {showStatusMenu && (
                   <div className="absolute top-6 left-0 w-32 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-50 animate-fade-in-down">
                      <button onClick={() => handleStatusChange('online')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-500"></span> Online
                      </button>
                      <button onClick={() => handleStatusChange('away')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-yellow-500"></span> Away
                      </button>
                      <button onClick={() => handleStatusChange('busy')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-red-500"></span> Busy
                      </button>
                   </div>
                 )}
              </div>
            </h1>

            <div className="flex items-center gap-1">
              <button onClick={() => setShowNewChatModal(true)} className="p-2.5 text-nexus-mint hover:bg-nexus-mint/10 rounded-full transition-colors">
                <Plus size={22} />
              </button>
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2.5 text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-gray-200 dark:hover:bg-gray-800 rounded-full transition-colors"
              >
                <Settings size={22} />
              </button>
            </div>
          </div>

          {/* SEARCH & SORT */}
          <div className="px-6 pb-4 flex gap-2">
            <div className="bg-white dark:bg-nexus-card rounded-2xl flex-1 flex items-center px-4 py-3 transition-all focus-within:ring-2 focus-within:ring-nexus-mint/50 shadow-sm border border-transparent dark:border-gray-800">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text" 
                placeholder="Search..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
            <div className="relative">
              <button 
                onClick={() => setShowSortMenu(!showSortMenu)} 
                className={`h-full aspect-square flex items-center justify-center rounded-2xl transition-colors shadow-sm ${showSortMenu ? 'bg-nexus-mint text-nexus-midnight' : 'bg-white dark:bg-nexus-card text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              >
                <Filter size={18} />
              </button>
              {showSortMenu && (
                <div className="absolute top-12 right-0 w-40 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-40 animate-fade-in-down">
                    <button onClick={() => { setSortOption('time'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'time' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Recent {sortOption === 'time' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('unread'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'unread' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Unread {sortOption === 'unread' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('alpha'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'alpha' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      A-Z {sortOption === 'alpha' && <CheckSquare size={14} />}
                    </button>
                </div>
              )}
            </div>
          </div>

          {/* DESKTOP TABS (Hidden on Mobile) */}
          <div className="hidden md:flex px-6 space-x-6 border-b dark:border-gray-800 mb-2">
             <button onClick={() => setActiveTab('priority')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'priority' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'groups' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'actions' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Actions
             </button>
          </div>

          {/* SCROLLABLE LIST AREA */}
          <div className="flex-1 overflow-y-auto px-4 pb-24 md:pb-4 space-y-2 no-scrollbar">
            {activeTab === 'actions' ? (
              <div className="space-y-3 pt-2">
                 {actionItems.length === 0 && (
                   <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <CheckSquare size={32} className="opacity-40" />
                     </div>
                     <p>All caught up! No pending actions.</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <div className="space-y-1 pt-2">
                 {getFilteredAndSortedChats().length === 0 && (
                   <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <MessageSquare size={32} className="opacity-40" />
                     </div>
                     <span>No chats in {activeTab}.</span>
                     <button onClick={() => setShowNewChatModal(true)} className="mt-2 text-nexus-mint font-bold hover:underline">Start a chat</button>
                   </div>
                 )}
                 {getFilteredAndSortedChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
                       onClick={() => setSelectedChatId(chat.id)}
                       className={`w-full flex items-start p-4 rounded-2xl transition-all duration-200 group relative border border-transparent ${
                         selectedChatId === chat.id 
                           ? 'bg-nexus-midnight text-white shadow-xl shadow-nexus-midnight/20' 
                           : 'hover:bg-white dark:hover:bg-nexus-card hover:border-gray-100 dark:hover:border-gray-800'
                       }`}
                     >
                       <div className="relative mr-4 flex-shrink-0">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-bold transition-colors ${
                            selectedChatId === chat.id 
                              ? 'bg-white/20 text-white' 
                              : 'bg-white dark:bg-nexus-card text-nexus-midnight dark:text-gray-300 shadow-sm'
                          }`}>
                            {chat.name[0]}
                          </div>
                          {chat.isGroup && (
                            <div className="absolute -bottom-1 -right-1 bg-nexus-slate dark:bg-nexus-dark rounded-full p-0.5">
                              <div className="bg-nexus-mint text-nexus-midnight rounded-full p-0.5">
                                <Users size={10} />
                              </div>
                            </div>
                          )}
                          {chat.isPinned && (
                            <div className="absolute -top-1 -left-1 bg-nexus-slate dark:bg-nexus-dark rounded-full p-0.5">
                               <div className="bg-white dark:bg-nexus-card text-gray-400 p-0.5 rounded-full shadow-sm">
                                <Pin size={8} fill="currentColor" />
                               </div>
                            </div>
                          )}
                       </div>

                       <div className="flex-1 text-left min-w-0 py-0.5">
                         <div className="flex justify-between items-center mb-1">
                           <h3 className={`font-bold truncate text-[15px] ${selectedChatId === chat.id ? 'text-white' : 'text-nexus-midnight dark:text-white'}`}>
                             {chat.name}
                           </h3>
                           <div className="flex items-center gap-1">
                              {chat.isPinned && <Pin size={10} className={`${selectedChatId === chat.id ? 'text-nexus-mint' : 'text-gray-400'} rotate-45`} fill="currentColor" />}
                              <span className={`text-[11px] font-medium ${selectedChatId === chat.id ? 'text-gray-300' : 'text-gray-400 group-hover:text-gray-500'}`}>
                                {lastMsg?.timestamp ? new Date(lastMsg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                              </span>
                           </div>
                         </div>
                         <p className={`text-[13px] truncate leading-relaxed ${selectedChatId === chat.id ? 'text-gray-300' : 'text-gray-500 dark:text-gray-400'}`}>
                           {lastMsg?.senderId === 'me' && <span className="opacity-70">You: </span>}
                           {lastMsg?.text || <span className="italic opacity-60">Start the conversation</span>}
                         </p>
                       </div>

                       {/* Hover Action: Pin */}
                       <div className="absolute right-2 bottom-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <div 
                            onClick={(e) => handlePinChat(e, chat.id, !!chat.isPinned)}
                            className={`p-1.5 rounded-full hover:bg-black/10 dark:hover:bg-white/10 ${selectedChatId === chat.id ? 'text-white' : 'text-gray-400'}`}
                            title={chat.isPinned ? "Unpin" : "Pin"}
                          >
                            <Pin size={14} fill={chat.isPinned ? "currentColor" : "none"} />
                          </div>
                       </div>
                     </button>
                   );
                 })}
              </div>
            )}
          </div>

          {/* MOBILE BOTTOM NAVIGATION */}
          <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-nexus-dark border-t dark:border-gray-800 pb-safe z-30 flex justify-around items-center h-20 px-2 shadow-[0_-5px_10px_rgba(0,0,0,0.02)]">
            <button 
              onClick={() => setActiveTab('priority')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'priority' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <Star size={24} fill={activeTab === 'priority' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Priority</span>
            </button>
            <button 
              onClick={() => setActiveTab('groups')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'groups' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <Users size={24} fill={activeTab === 'groups' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Groups</span>
            </button>
            <button 
              onClick={() => setActiveTab('actions')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'actions' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <div className="relative">
                <Zap size={24} fill={activeTab === 'actions' ? "currentColor" : "none"} />
                {actionItems.some(i => !i.isCompleted) && (
                  <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-nexus-coral rounded-full border-2 border-white dark:border-nexus-dark"></span>
                )}
              </div>
              <span className="text-[10px] font-bold">Actions</span>
            </button>
          </div>
        </div>

        {/* === CHAT AREA === */}
        <div className={`
          flex-1 bg-white/50 dark:bg-black/20 relative
          ${!selectedChatId ? 'hidden md:flex items-center justify-center' : 'flex w-full absolute inset-0 md:static z-20'}
        `}>
          {activeChat ? (
            <ChatInterface 
              chat={activeChat} 
              onBack={() => setSelectedChatId(null)}
              onSendMessage={handleSendMessage}
              onCallStart={(isVideo) => setActiveCall({
                isActive: true,
                isIncoming: false,
                isVideo,
                partnerName: activeChat.name,
                status: 'ringing'
              })}
            />
          ) : (
            <div className="text-center opacity-40 max-w-sm px-6">
              <div className="w-32 h-32 mx-auto mb-8 flex items-center justify-center rotate-3 transform transition-transform hover:rotate-6">
                 <Logo className="w-full h-full shadow-2xl" />
              </div>
              <h2 className="text-3xl font-bold text-nexus-midnight dark:text-white mb-3">Nexus Web</h2>
              <p className="text-gray-500 dark:text-gray-400 text-lg leading-relaxed">
                Select a conversation from the sidebar to start messaging. 
              </p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Chat, Message } from '../types';
import { Send, ArrowLeft, Sparkles, MoreVertical, Paperclip, CheckCheck, Phone, Video, Smile, Share, Search, Clock, CalendarClock, X } from 'lucide-react';
import { summarizeChat } from '../services/geminiService';
import { sendTypingEvent, subscribeToTypingEvents, getCurrentUser, toggleReaction } from '../services/supabaseClient';
import { ChatInfoSidebar } from './ChatInfoSidebar';
import { ForwardModal } from './ForwardModal';

interface ChatInterfaceProps {
  chat: Chat;
  onBack: () => void;
  onSendMessage: (text: string, scheduledDate?: Date) => void;
  onCallStart: (isVideo: boolean) => void;
}

const REACTION_EMOJIS = ['👍', '❤️', '😂', '😮', '😢', '🔥'];

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage, onCallStart }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [currentUserId, setCurrentUserId] = useState<string>('');

  // New State
  const [showInfoSidebar, setShowInfoSidebar] = useState(false);
  const [forwardingMessage, setForwardingMessage] = useState<string | null>(null);
  const [activeReactionMessageId, setActiveReactionMessageId] = useState<string | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [scheduledTime, setScheduledTime] = useState<string>('');
  const [showScheduleInput, setShowScheduleInput] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    getCurrentUser().then(u => u && setCurrentUserId(u.id));
  }, []);

  useEffect(() => {
    scrollToBottom();
    setSummary(null);
    setShowInfoSidebar(false);
    setIsSearching(false);
    setSearchQuery('');
    setTypingUsers(new Set()); 

    const unsubscribe = subscribeToTypingEvents(chat.id, (userId, isTyping) => {
      if (userId === currentUserId) return;

      setTypingUsers(prev => {
        const next = new Set(prev);
        if (isTyping) {
          next.add(userId);
        } else {
          next.delete(userId);
        }
        return next;
      });
      setTimeout(scrollToBottom, 100);
    });

    return () => {
      unsubscribe();
    };
  }, [chat.id, currentUserId]);

  useEffect(() => {
    if (!isSearching) scrollToBottom();
  }, [chat.messages, isSearching]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputText(e.target.value);

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, true);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        sendTypingEvent(chat.id, currentUserId, false);
      }, 2000);
    }
  };

  const handleSend = () => {
    if (!inputText.trim()) return;
    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }

    let scheduledDate: Date | undefined;
    if (scheduledTime) {
      scheduledDate = new Date(scheduledTime);
    }

    onSendMessage(inputText, scheduledDate);
    setInputText('');
    setScheduledTime('');
    setShowScheduleInput(false);
  };

  const handleCatchMeUp = async () => {
    setIsSummarizing(true);
    const result = await summarizeChat(chat.messages);
    setSummary(result);
    setIsSummarizing(false);
  };

  const onReactionClick = async (msgId: string, emoji: string) => {
    await toggleReaction(chat.id, msgId, currentUserId, emoji);
    setActiveReactionMessageId(null);
  };

  const isSomeoneTyping = typingUsers.size > 0;

  const filteredMessages = chat.messages.filter(m => {
    if (!searchQuery) return true;
    const dateStr = new Date(m.timestamp).toLocaleDateString();
    return m.text.toLowerCase().includes(searchQuery.toLowerCase()) || dateStr.includes(searchQuery);
  });

  return (
    <div className="flex flex-row h-full w-full overflow-hidden relative">
      <div className="flex-1 flex flex-col h-full bg-[#f2f4f7] dark:bg-[#0b141a] relative min-w-0">

        {/* HEADER */}
        <div className="flex items-center justify-between px-4 py-3 bg-white/80 dark:bg-nexus-card/90 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800 sticky top-0 z-20 shadow-sm">
          {isSearching ? (
             <div className="flex-1 flex items-center gap-2 animate-fade-in-down">
               <button onClick={() => { setIsSearching(false); setSearchQuery(''); }} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
                 <ArrowLeft size={20} className="text-gray-500" />
               </button>
               <div className="flex-1 relative">
                 <input 
                   autoFocus
                   type="text" 
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   placeholder="Search messages or date..."
                   className="w-full bg-gray-100 dark:bg-gray-800 rounded-lg py-2 pl-3 pr-8 text-sm outline-none dark:text-white"
                 />
                 {searchQuery && (
                   <button onClick={() => setSearchQuery('')} className="absolute right-2 top-2 text-gray-400">
                     <X size={16} />
                   </button>
                 )}
               </div>
             </div>
          ) : (
            <>
              <div className="flex items-center gap-3">
                <button onClick={onBack} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full md:hidden text-nexus-midnight transition-colors">
                  <ArrowLeft size={24} />
                </button>

                <div className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => setShowInfoSidebar(!showInfoSidebar)}>
                  <div className="relative">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold shadow-sm ${chat.isGroup ? 'bg-nexus-midnight' : 'bg-gradient-to-tr from-gray-400 to-gray-500'}`}>
                      {chat.name[0]}
                    </div>
                    <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white dark:border-nexus-card"></div>
                  </div>
                  <div>
                    <h3 className="font-bold text-base text-nexus-midnight dark:text-white leading-tight">{chat.name}</h3>
                    <p className="text-xs text-nexus-mint font-medium dark:text-nexus-mint/80">
                      {isSomeoneTyping ? 'Typing...' : 'Online'}
                    </p>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-1 md:gap-2">
                <button onClick={() => setIsSearching(true)} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors">
                  <Search size={20} />
                </button>

                <div className="hidden sm:flex gap-1">
                  <button onClick={() => onCallStart(false)} className="p-2 text-nexus-midnight dark:text-white hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors">
                    <Phone size={20} />
                  </button>
                  <button onClick={() => onCallStart(true)} className="p-2 text-nexus-midnight dark:text-white hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors">
                    <Video size={20} />
                  </button>
                </div>

                {/* AI Summary Button Removed */}

                <button 
                  onClick={() => setShowInfoSidebar(!showInfoSidebar)}
                  className={`p-2 rounded-full transition-colors ${showInfoSidebar ? 'bg-nexus-midnight text-white' : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700'}`}
                >
                  <MoreVertical size={20} />
                </button>
              </div>
            </>
          )}
        </div>

        {/* SUMMARY CARD (Still support showing it if triggered elsewhere, but trigger removed) */}
        {summary && (
          <div className="mx-4 mt-4 p-4 bg-nexus-mint/10 border border-nexus-mint/20 rounded-2xl animate-fade-in-down">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-white dark:bg-nexus-card rounded-lg shadow-sm text-nexus-midnight">
                <Sparkles size={18} />
              </div>
              <div>
                <h4 className="text-xs font-bold uppercase text-nexus-midnight dark:text-nexus-mint mb-1 tracking-wider">AI Summary</h4>
                <p className="text-sm text-gray-700 dark:text-gray-200 leading-relaxed">{summary}</p>
              </div>
              <button onClick={() => setSummary(null)} className="ml-auto text-gray-400 hover:text-gray-600">×</button>
            </div>
          </div>
        )}

        {/* MESSAGES AREA */}
        <div 
          className="flex-1 overflow-y-auto p-4 space-y-4 sm:p-6 no-scrollbar"
          onClick={() => setActiveReactionMessageId(null)}
        >
          {filteredMessages.length === 0 && searchQuery && (
             <div className="text-center py-12 text-gray-400">No messages found matching "{searchQuery}"</div>
          )}

          {filteredMessages.map((msg, idx) => {
            const isMe = msg.senderId === 'me';
            const showAvatar = !isMe && (idx === 0 || chat.messages[idx - 1].senderId !== msg.senderId);
            const isScheduled = msg.status === 'scheduled';

            return (
              <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} group relative mb-2`}>
                <div className={`flex ${isMe ? 'justify-end' : 'justify-start'} max-w-full`}>
                  {!isMe && (
                    <div className={`w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-6 ${showAvatar ? 'opacity-100' : 'opacity-0'}`}>
                      {chat.name[0]}
                    </div>
                  )}

                  <div className="relative group/bubble">
                    {/* Message Bubble */}
                    <div className={`relative shadow-sm max-w-[85vw] md:max-w-[500px] ${
                      isMe 
                        ? (isScheduled ? 'bg-nexus-midnight/70 border border-dashed border-white/30 text-white' : 'bg-nexus-midnight text-white') + ' rounded-2xl rounded-tr-sm' 
                        : 'bg-white dark:bg-nexus-card dark:text-gray-100 rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800 shadow-sm'
                    }`}>
                        <div className="px-4 py-2 text-[15px] leading-relaxed whitespace-pre-wrap break-words">
                          {msg.text}
                        </div>
                        <div className={`px-2 pb-1 flex justify-end items-center gap-1 text-[10px] ${isMe ? 'text-gray-400' : 'text-gray-400'}`}>
                          {isScheduled && <CalendarClock size={10} className="mr-1" />}
                          <span>
                             {isScheduled && msg.scheduledFor 
                               ? `Scheduled for ${msg.scheduledFor.toLocaleDateString()} ${msg.scheduledFor.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}` 
                               : new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})
                             }
                          </span>
                          {isMe && !isScheduled && <CheckCheck size={14} className="text-nexus-mint" />}
                        </div>
                    </div>

                    {/* Reactions Display */}
                    {msg.reactions && Object.keys(msg.reactions).length > 0 && (
                      <div className={`absolute -bottom-3 ${isMe ? 'right-0' : 'left-0'} flex gap-1 z-10`}>
                        {Object.entries(msg.reactions).map(([emoji, users]) => (
                          <div key={emoji} className="bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-full px-1.5 py-0.5 text-[10px] shadow-sm flex items-center gap-0.5 scale-90">
                            <span>{emoji}</span>
                            {(users as string[]).length > 1 && <span className="text-gray-500 font-bold">{(users as string[]).length}</span>}
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Action Buttons (Hover) */}
                    {!isScheduled && (
                      <div className={`absolute -top-8 ${isMe ? 'right-0' : 'left-0'} flex items-center gap-1 opacity-0 group-hover/bubble:opacity-100 transition-opacity bg-white/90 dark:bg-gray-800/90 rounded-full px-2 py-1 shadow-sm backdrop-blur-sm`}>
                         <button 
                           onClick={(e) => { e.stopPropagation(); setActiveReactionMessageId(activeReactionMessageId === msg.id ? null : msg.id); }}
                           className="p-1.5 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-gray-500"
                           title="Add Reaction"
                         >
                           <Smile size={14} />
                         </button>
                         <button 
                           onClick={(e) => { e.stopPropagation(); setForwardingMessage(msg.text); }}
                           className="p-1.5 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-gray-500"
                           title="Forward Message"
                         >
                           <Share size={14} />
                         </button>
                      </div>
                    )}

                    {/* Reaction Picker Popover */}
                    {activeReactionMessageId === msg.id && (
                      <div className={`absolute -top-12 ${isMe ? 'right-0' : 'left-0'} bg-white dark:bg-nexus-card shadow-xl rounded-full p-1 flex gap-1 animate-fade-in-up z-20 border dark:border-gray-700`}>
                        {REACTION_EMOJIS.map(emoji => (
                          <button
                            key={emoji}
                            onClick={(e) => { e.stopPropagation(); onReactionClick(msg.id, emoji); }}
                            className="w-8 h-8 flex items-center justify-center hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-lg transition-transform hover:scale-125"
                          >
                            {emoji}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}

          {/* TYPING INDICATOR */}
          {isSomeoneTyping && (
            <div className="flex justify-start animate-fade-in-up">
              <div className="w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-1 opacity-100">
                {chat.name[0]}
              </div>
              <div className="bg-white dark:bg-nexus-card rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-800 px-4 py-3 shadow-sm">
                <div className="flex items-center gap-1 h-3">
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                </div>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* INPUT AREA */}
        <div className="p-3 sm:p-4 bg-white dark:bg-nexus-dark border-t border-gray-100 dark:border-gray-800">

          {/* Scheduler UI */}
          {showScheduleInput && (
             <div className="mb-2 p-2 bg-gray-100 dark:bg-gray-800 rounded-lg flex items-center gap-2 animate-fade-in-up">
               <Clock size={16} className="text-nexus-midnight dark:text-nexus-mint" />
               <span className="text-xs font-bold text-gray-500 uppercase">Schedule for:</span>
               <input 
                 type="datetime-local" 
                 value={scheduledTime}
                 onChange={(e) => setScheduledTime(e.target.value)}
                 className="bg-white dark:bg-gray-700 border-none rounded px-2 py-1 text-sm outline-none dark:text-white"
               />
               <button onClick={() => setShowScheduleInput(false)} className="ml-auto text-gray-400 hover:text-gray-600">
                 <X size={16} />
               </button>
             </div>
          )}

          <div className="flex items-center gap-2 max-w-4xl mx-auto bg-gray-100 dark:bg-gray-800/80 p-1.5 rounded-[24px] border border-transparent focus-within:border-nexus-mint/30 focus-within:ring-2 focus-within:ring-nexus-mint/20 transition-all">
            <button className="p-2.5 text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-white dark:hover:bg-gray-700 rounded-full transition-colors">
              <Paperclip size={20} />
            </button>

            <button 
              onClick={() => setShowScheduleInput(!showScheduleInput)}
              className={`p-2.5 rounded-full transition-colors ${showScheduleInput ? 'text-nexus-midnight bg-white dark:bg-gray-700' : 'text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-white dark:hover:bg-gray-700'}`}
              title="Schedule Message"
            >
              <Clock size={20} />
            </button>

            <input
              type="text"
              value={inputText}
              onChange={handleInputChange}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder={showScheduleInput ? "Type scheduled message..." : "Type a message..."}
              className="flex-1 bg-transparent border-none outline-none text-gray-800 dark:text-white placeholder-gray-500 px-2 py-2"
            />

            <button 
              onClick={handleSend}
              disabled={!inputText.trim()}
              className={`p-3 rounded-full transition-all duration-300 transform ${
                inputText.trim() 
                  ? 'bg-nexus-mint text-nexus-midnight shadow-lg shadow-nexus-mint/30 hover:scale-105 active:scale-95'
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-400'
              }`}
            >
              {scheduledTime ? <CalendarClock size={18} /> : <Send size={18} className={inputText.trim() ? "translate-x-0.5" : ""} />}
            </button>
          </div>
        </div>
      </div>

      {/* RIGHT SIDEBAR (SLIDEOUT) */}
      {showInfoSidebar && (
        <ChatInfoSidebar 
          chat={chat} 
          onClose={() => setShowInfoSidebar(false)} 
          onLeave={() => {
            setShowInfoSidebar(false);
            onBack();
          }}
        />
      )}

      {/* FORWARD MODAL */}
      {forwardingMessage && (
        <ForwardModal 
          messageText={forwardingMessage} 
          onClose={() => setForwardingMessage(null)}
          onForwardSuccess={() => {
             setForwardingMessage(null);
          }}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Message, Chat, ActionItem, TabType, SortOption, CallSession } from './types';
import { supabase, getCurrentUser, fetchUserChats, fetchMessages, sendMessageToDb, toggleChatPin, updateUserStatus, updateUserProfile } from './services/supabaseClient';
import { ChatInterface } from './components/ChatInterface';
import { ActionCard } from './components/ActionCard';
import { AuthScreen } from './components/AuthScreen';
import { NewChatModal } from './components/NewChatModal';
import { CallOverlay } from './components/CallOverlay';
import { SettingsModal } from './components/SettingsModal';
import { Logo } from './components/Logo';
import { 
  Search, Bell, Moon, Sun, Filter, 
  MessageSquare, Star, Zap, CheckSquare, Plus, LogOut,
  Users, Pin, ChevronDown, Clock, Activity, Circle, Settings
} from 'lucide-react';

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('priority');
  const [sortOption, setSortOption] = useState<SortOption>('time');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
  const [showNewChatModal, setShowNewChatModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showStatusMenu, setShowStatusMenu] = useState(false);
  const [showSortMenu, setShowSortMenu] = useState(false);

  const [chats, setChats] = useState<Chat[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);
  const [activeCall, setActiveCall] = useState<CallSession | null>(null);

  // 1. Auth Initialization
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user) {
        setCurrentUser(session.user);
        // Apply theme preference if it exists
        if (session.user.preferences?.theme === 'dark') {
          setDarkMode(true);
        }
      }
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session?.user) {
        setCurrentUser(session.user);
        if (session.user.preferences?.theme === 'dark') {
           setDarkMode(true);
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Load User Data (Chats)
  const loadChats = async () => {
    if (!session?.user) return;
    const myChats = await fetchUserChats(session.user.id);
    setChats(myChats);
  };

  useEffect(() => {
    if (session) {
      loadChats();
    }
  }, [session]);

  // 3. Load Messages for Selected Chat & Subscribe to Realtime
  useEffect(() => {
    if (!selectedChatId || !session) return;

    const loadMsgs = async () => {
      const msgs = await fetchMessages(selectedChatId);
      // Transform DB messages to UI format
      const formattedMsgs: Message[] = msgs.map((m: any) => ({
        ...m,
        senderId: m.senderId === session.user.id ? 'me' : m.senderId
      }));

      setChats(prev => prev.map(c => {
        if (c.id === selectedChatId) {
          return { ...c, messages: formattedMsgs };
        }
        return c;
      }));
    };

    loadMsgs();

    // Subscribe to new messages (INSERT) and updates (UPDATE - for reactions)
    const channel = supabase
      .channel(`chat:${selectedChatId}`)
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'messages', filter: `chat_id=eq.${selectedChatId}` }, 
        (payload) => {

          if (payload.eventType === 'INSERT') {
            const newMsg = payload.new;
            if (newMsg.sender_id === session.user.id) return; // Skip own inserts if handled optimistically

            const formattedMsg: Message = {
              id: newMsg.id,
              senderId: newMsg.sender_id,
              text: newMsg.content,
              timestamp: new Date(newMsg.created_at),
              isActionItem: newMsg.is_action_item,
              reactions: newMsg.reactions,
              scheduledFor: newMsg.scheduled_for ? new Date(newMsg.scheduled_for) : undefined,
              status: newMsg.status
            };

            setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return { ...c, messages: [...c.messages, formattedMsg] };
               }
               return c;
            }));
          } 
          else if (payload.eventType === 'UPDATE') {
             const updatedMsg = payload.new;
             setChats(prev => prev.map(c => {
               if (c.id === selectedChatId) {
                 return {
                   ...c,
                   messages: c.messages.map(m => m.id === updatedMsg.id ? {
                     ...m,
                     reactions: updatedMsg.reactions
                   } : m)
                 };
               }
               return c;
             }));
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedChatId, session]);

  // Toggle Dark Mode and Persist
  const handleToggleDarkMode = async () => {
    const newMode = !darkMode;
    setDarkMode(newMode);

    // Persist to user preferences
    if (session?.user?.id) {
       await updateUserProfile(session.user.id, {
         preferences: { 
           ...currentUser?.preferences, 
           theme: newMode ? 'dark' : 'light' 
         }
       });
       // Update local user state to reflect change
       setCurrentUser((prev: any) => ({
         ...prev,
         preferences: { ...prev.preferences, theme: newMode ? 'dark' : 'light' }
       }));
    }
  };

  // Apply Dark Mode class to HTML
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleSendMessage = async (text: string, scheduledDate?: Date) => {
    if (!selectedChatId || !session) return;

    const tempId = Date.now().toString();
    const newMessage: Message = {
      id: tempId,
      senderId: 'me',
      text,
      timestamp: new Date(),
      scheduledFor: scheduledDate,
      status: scheduledDate ? 'scheduled' : 'sent'
    };

    // Optimistic Update
    setChats(prev => prev.map(c => {
      if (c.id === selectedChatId) {
        return { ...c, messages: [...c.messages, newMessage] };
      }
      return c;
    }));

    // Send to DB
    await sendMessageToDb(selectedChatId, session.user.id, text, scheduledDate);

    // AI Analysis DISABLED as per request
    /*
    if (!scheduledDate) {
      const analysis = await detectActionItem(text);
      if (analysis.isAction) {
        // ... action item logic
      }
    }
    */
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setChats([]);
    setSelectedChatId(null);
    setShowSettingsModal(false);
  };

  const toggleActionComplete = (id: string) => {
    setActionItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const handlePinChat = async (e: React.MouseEvent, chatId: string, currentPinned: boolean) => {
    e.stopPropagation();
    // Optimistic Update
    setChats(prev => prev.map(c => c.id === chatId ? { ...c, isPinned: !currentPinned } : c));
    await toggleChatPin(chatId, !currentPinned);
  };

  const handleStatusChange = async (status: string) => {
    if (!session?.user) return;
    const msg = status === 'busy' ? 'In a meeting' : '';
    await updateUserStatus(session.user.id, status, msg);
    setCurrentUser((prev: any) => ({ ...prev, status: status, statusMessage: msg }));
    setShowStatusMenu(false);
  };

  const getFilteredAndSortedChats = () => {
    if (!chats) return [];

    // 1. Filter Tab
    let filtered = chats;
    if (activeTab === 'priority') {
      filtered = chats.filter(c => c.priority === 'high' || (c.unreadCount && c.unreadCount > 0));
    } else if (activeTab === 'groups') {
      filtered = chats.filter(c => c.isGroup);
    }

    // 2. Sort Logic
    return filtered.sort((a, b) => {
      // Pinned always on top
      if (a.isPinned && !b.isPinned) return -1;
      if (!a.isPinned && b.isPinned) return 1;

      // Sort Option
      if (sortOption === 'time') {
         const timeA = a.messages.length > 0 ? new Date(a.messages[a.messages.length-1].timestamp).getTime() : 0;
         const timeB = b.messages.length > 0 ? new Date(b.messages[b.messages.length-1].timestamp).getTime() : 0;
         return timeB - timeA;
      } else if (sortOption === 'unread') {
         return (b.unreadCount || 0) - (a.unreadCount || 0);
      } else if (sortOption === 'alpha') {
         return a.name.localeCompare(b.name);
      }
      return 0;
    });
  };

  const activeChat = chats.find(c => c.id === selectedChatId);

  // --- RENDERING ---

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-nexus-slate dark:bg-nexus-dark"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-nexus-mint"></div></div>;

  if (!session) {
    return <AuthScreen onAuthSuccess={() => loadChats()} />;
  }

  return (
    <div className={`h-screen w-full flex flex-col overflow-hidden bg-nexus-slate dark:bg-nexus-dark ${darkMode ? 'dark' : ''}`}>
      {/* GLOBAL MODALS */}
      {showNewChatModal && (
        <NewChatModal 
          currentUserId={session.user.id} 
          onClose={() => setShowNewChatModal(false)} 
          onChatCreated={() => {
            loadChats();
            setActiveTab('priority'); // Reset tab to see new chat usually
          }} 
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          user={currentUser}
          onClose={() => setShowSettingsModal(false)}
          onUpdate={async () => {
             const user = await getCurrentUser();
             setCurrentUser(user);
          }}
          isDarkMode={darkMode}
          toggleDarkMode={handleToggleDarkMode}
          onLogout={handleLogout}
        />
      )}

      {activeCall && (
        <CallOverlay 
          partnerName={activeCall.partnerName}
          isVideo={activeCall.isVideo}
          onEndCall={() => setActiveCall(null)}
        />
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* === SIDEBAR / MOBILE LIST VIEW === */}
        <div className={`
          flex flex-col h-full bg-nexus-slate dark:bg-nexus-dark border-r dark:border-gray-800 transition-all duration-300
          w-full md:w-[380px] lg:w-[420px] 
          ${selectedChatId ? 'hidden md:flex' : 'flex'}
        `}>

          {/* HEADER */}
          <div className="px-6 py-5 flex justify-between items-center bg-nexus-slate dark:bg-nexus-dark z-10 sticky top-0">
            <h1 className="text-2xl font-bold tracking-tight text-nexus-midnight dark:text-white flex items-center gap-2 relative">
              {/* Logo removed here for cleaner look */}
              <span>Nexus</span>

              {/* STATUS INDICATOR/SELECTOR */}
              <div className="relative ml-1">
                 <button onClick={() => setShowStatusMenu(!showStatusMenu)} className={`w-3 h-3 rounded-full ring-2 ring-white dark:ring-nexus-dark hover:scale-125 transition-transform ${currentUser?.status === 'online' ? 'bg-green-500' : currentUser?.status === 'busy' ? 'bg-red-500' : 'bg-yellow-500'}`}></button>
                 {showStatusMenu && (
                   <div className="absolute top-6 left-0 w-32 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-50 animate-fade-in-down">
                      <button onClick={() => handleStatusChange('online')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-500"></span> Online
                      </button>
                      <button onClick={() => handleStatusChange('away')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-yellow-500"></span> Away
                      </button>
                      <button onClick={() => handleStatusChange('busy')} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-200 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-red-500"></span> Busy
                      </button>
                   </div>
                 )}
              </div>
            </h1>

            <div className="flex items-center gap-1">
              <button onClick={() => setShowNewChatModal(true)} className="p-2.5 text-nexus-mint hover:bg-nexus-mint/10 rounded-full transition-colors">
                <Plus size={22} />
              </button>
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2.5 text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-gray-200 dark:hover:bg-gray-800 rounded-full transition-colors"
              >
                <Settings size={22} />
              </button>
            </div>
          </div>

          {/* SEARCH & SORT */}
          <div className="px-6 pb-4 flex gap-2">
            <div className="bg-white dark:bg-nexus-card rounded-2xl flex-1 flex items-center px-4 py-3 transition-all focus-within:ring-2 focus-within:ring-nexus-mint/50 shadow-sm border border-transparent dark:border-gray-800">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text" 
                placeholder="Search..." 
                className="bg-transparent border-none outline-none text-sm w-full dark:text-white placeholder-gray-500"
              />
            </div>
            <div className="relative">
              <button 
                onClick={() => setShowSortMenu(!showSortMenu)} 
                className={`h-full aspect-square flex items-center justify-center rounded-2xl transition-colors shadow-sm ${showSortMenu ? 'bg-nexus-mint text-nexus-midnight' : 'bg-white dark:bg-nexus-card text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              >
                <Filter size={18} />
              </button>
              {showSortMenu && (
                <div className="absolute top-12 right-0 w-40 bg-white dark:bg-nexus-card shadow-xl rounded-xl border dark:border-gray-700 py-1 z-40 animate-fade-in-down">
                    <button onClick={() => { setSortOption('time'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'time' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Recent {sortOption === 'time' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('unread'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'unread' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      Unread {sortOption === 'unread' && <CheckSquare size={14} />}
                    </button>
                    <button onClick={() => { setSortOption('alpha'); setShowSortMenu(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 dark:hover:bg-gray-800 flex items-center justify-between ${sortOption === 'alpha' ? 'text-nexus-mint font-bold' : 'dark:text-gray-300'}`}>
                      A-Z {sortOption === 'alpha' && <CheckSquare size={14} />}
                    </button>
                </div>
              )}
            </div>
          </div>

          {/* DESKTOP TABS (Hidden on Mobile) */}
          <div className="hidden md:flex px-6 space-x-6 border-b dark:border-gray-800 mb-2">
             <button onClick={() => setActiveTab('priority')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'priority' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Priority
             </button>
             <button onClick={() => setActiveTab('groups')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'groups' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Groups
             </button>
             <button onClick={() => setActiveTab('actions')} className={`pb-3 text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'actions' ? 'border-nexus-mint text-nexus-midnight dark:text-nexus-mint' : 'border-transparent text-gray-400 hover:text-gray-600'}`}>
               Actions
             </button>
          </div>

          {/* SCROLLABLE LIST AREA */}
          <div className="flex-1 overflow-y-auto px-4 pb-24 md:pb-4 space-y-2 no-scrollbar">
            {activeTab === 'actions' ? (
              <div className="space-y-3 pt-2">
                 {actionItems.length === 0 && (
                   <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <CheckSquare size={32} className="opacity-40" />
                     </div>
                     <p>All caught up! No pending actions.</p>
                   </div>
                 )}
                 {actionItems.map(item => (
                   <ActionCard 
                    key={item.id} 
                    item={item} 
                    onComplete={toggleActionComplete} 
                    onGoToChat={(id) => setSelectedChatId(id)}
                   />
                 ))}
              </div>
            ) : (
              <div className="space-y-1 pt-2">
                 {getFilteredAndSortedChats().length === 0 && (
                   <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center">
                     <div className="w-16 h-16 bg-white dark:bg-nexus-card rounded-full flex items-center justify-center mb-4">
                       <MessageSquare size={32} className="opacity-40" />
                     </div>
                     <span>No chats in {activeTab}.</span>
                     <button onClick={() => setShowNewChatModal(true)} className="mt-2 text-nexus-mint font-bold hover:underline">Start a chat</button>
                   </div>
                 )}
                 {getFilteredAndSortedChats().map(chat => {
                   const lastMsg = chat.messages[chat.messages.length - 1];
                   return (
                     <button
                       key={chat.id}
                       onClick={() => setSelectedChatId(chat.id)}
                       className={`w-full flex items-start p-4 rounded-2xl transition-all duration-200 group relative border border-transparent ${
                         selectedChatId === chat.id 
                           ? 'bg-nexus-midnight text-white shadow-xl shadow-nexus-midnight/20' 
                           : 'hover:bg-white dark:hover:bg-nexus-card hover:border-gray-100 dark:hover:border-gray-800'
                       }`}
                     >
                       <div className="relative mr-4 flex-shrink-0">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-bold transition-colors ${
                            selectedChatId === chat.id 
                              ? 'bg-white/20 text-white' 
                              : 'bg-white dark:bg-nexus-card text-nexus-midnight dark:text-gray-300 shadow-sm'
                          }`}>
                            {chat.name[0]}
                          </div>
                          {chat.isGroup && (
                            <div className="absolute -bottom-1 -right-1 bg-nexus-slate dark:bg-nexus-dark rounded-full p-0.5">
                              <div className="bg-nexus-mint text-nexus-midnight rounded-full p-0.5">
                                <Users size={10} />
                              </div>
                            </div>
                          )}
                          {chat.isPinned && (
                            <div className="absolute -top-1 -left-1 bg-nexus-slate dark:bg-nexus-dark rounded-full p-0.5">
                               <div className="bg-white dark:bg-nexus-card text-gray-400 p-0.5 rounded-full shadow-sm">
                                <Pin size={8} fill="currentColor" />
                               </div>
                            </div>
                          )}
                       </div>

                       <div className="flex-1 text-left min-w-0 py-0.5">
                         <div className="flex justify-between items-center mb-1">
                           <h3 className={`font-bold truncate text-[15px] ${selectedChatId === chat.id ? 'text-white' : 'text-nexus-midnight dark:text-white'}`}>
                             {chat.name}
                           </h3>
                           <div className="flex items-center gap-1">
                              {chat.isPinned && <Pin size={10} className={`${selectedChatId === chat.id ? 'text-nexus-mint' : 'text-gray-400'} rotate-45`} fill="currentColor" />}
                              <span className={`text-[11px] font-medium ${selectedChatId === chat.id ? 'text-gray-300' : 'text-gray-400 group-hover:text-gray-500'}`}>
                                {lastMsg?.timestamp ? new Date(lastMsg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                              </span>
                           </div>
                         </div>
                         <p className={`text-[13px] truncate leading-relaxed ${selectedChatId === chat.id ? 'text-gray-300' : 'text-gray-500 dark:text-gray-400'}`}>
                           {lastMsg?.senderId === 'me' && <span className="opacity-70">You: </span>}
                           {lastMsg?.text || <span className="italic opacity-60">Start the conversation</span>}
                         </p>
                       </div>

                       {/* Hover Action: Pin */}
                       <div className="absolute right-2 bottom-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <div 
                            onClick={(e) => handlePinChat(e, chat.id, !!chat.isPinned)}
                            className={`p-1.5 rounded-full hover:bg-black/10 dark:hover:bg-white/10 ${selectedChatId === chat.id ? 'text-white' : 'text-gray-400'}`}
                            title={chat.isPinned ? "Unpin" : "Pin"}
                          >
                            <Pin size={14} fill={chat.isPinned ? "currentColor" : "none"} />
                          </div>
                       </div>
                     </button>
                   );
                 })}
              </div>
            )}
          </div>

          {/* MOBILE BOTTOM NAVIGATION */}
          <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-nexus-dark border-t dark:border-gray-800 pb-safe z-30 flex justify-around items-center h-20 px-2 shadow-[0_-5px_10px_rgba(0,0,0,0.02)]">
            <button 
              onClick={() => setActiveTab('priority')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'priority' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <Star size={24} fill={activeTab === 'priority' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Priority</span>
            </button>
            <button 
              onClick={() => setActiveTab('groups')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'groups' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <Users size={24} fill={activeTab === 'groups' ? "currentColor" : "none"} />
              <span className="text-[10px] font-bold">Groups</span>
            </button>
            <button 
              onClick={() => setActiveTab('actions')}
              className={`flex-1 flex flex-col items-center justify-center gap-1 h-full rounded-2xl transition-all ${activeTab === 'actions' ? 'text-nexus-mint' : 'text-gray-400'}`}
            >
              <div className="relative">
                <Zap size={24} fill={activeTab === 'actions' ? "currentColor" : "none"} />
                {actionItems.some(i => !i.isCompleted) && (
                  <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-nexus-coral rounded-full border-2 border-white dark:border-nexus-dark"></span>
                )}
              </div>
              <span className="text-[10px] font-bold">Actions</span>
            </button>
          </div>
        </div>

        {/* === CHAT AREA === */}
        <div className={`
          flex-1 bg-white/50 dark:bg-black/20 relative
          ${!selectedChatId ? 'hidden md:flex items-center justify-center' : 'flex w-full absolute inset-0 md:static z-20'}
        `}>
          {activeChat ? (
            <ChatInterface 
              chat={activeChat} 
              onBack={() => setSelectedChatId(null)}
              onSendMessage={handleSendMessage}
              onCallStart={(isVideo) => setActiveCall({
                isActive: true,
                isIncoming: false,
                isVideo,
                partnerName: activeChat.name,
                status: 'ringing'
              })}
            />
          ) : (
            <div className="text-center opacity-40 max-w-sm px-6">
              <div className="w-32 h-32 mx-auto mb-8 flex items-center justify-center rotate-3 transform transition-transform hover:rotate-6">
                 <Logo className="w-full h-full shadow-2xl" />
              </div>
              <h2 className="text-3xl font-bold text-nexus-midnight dark:text-white mb-3">Nexus Web</h2>
              <p className="text-gray-500 dark:text-gray-400 text-lg leading-relaxed">
                Select a conversation from the sidebar to start messaging. 
              </p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ArrowRight, Loader2, Mail, Lock, User, Phone, ChevronLeft, Zap } from 'lucide-react';
import { Logo } from './Logo';

export const AuthScreen = ({ onAuthSuccess }: { onAuthSuccess: () => void }) => {
  const [view, setView] = useState<'welcome' | 'login' | 'signup'>('welcome');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (view === 'login') {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
      } else {
        const { data, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, phone: phone } }
        });
        if (signUpError) throw signUpError;
      }
      onAuthSuccess();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // 1. Welcome / Landing Page View
  if (view === 'welcome') {
      return (
          <div className="h-screen w-full bg-white dark:bg-nexus-dark flex flex-col items-center justify-between p-8 relative overflow-hidden transition-colors">

             {/* Simple Decorative Shapes (Flat Colors) */}
             <div className="absolute top-[-10%] right-[-10%] w-64 h-64 bg-nexus-mint/20 rounded-full pointer-events-none" />
             <div className="absolute bottom-[10%] left-[-5%] w-40 h-40 bg-nexus-coral/10 rounded-full pointer-events-none" />

             <div className="flex-1 flex flex-col items-center justify-center z-10 w-full mt-10">
                <div className="mb-8">
                   <Logo className="w-32 h-32 shadow-xl" />
                </div>

                <h1 className="text-4xl md:text-5xl font-black text-nexus-midnight dark:text-white mb-4 tracking-tight text-center">
                  Nexus
                </h1>
                <p className="text-gray-500 text-center max-w-xs text-lg font-medium leading-relaxed">
                   The friendly way to stay in touch with your favorite people.
                </p>
             </div>

             <div className="w-full max-w-sm z-10 space-y-4 mb-8 animate-fade-in-up">
                <button 
                  onClick={() => setView('login')}
                  className="w-full py-4 bg-nexus-midnight text-white font-bold rounded-2xl shadow-xl hover:shadow-2xl hover:bg-nexus-midnight-hover transition-all transform hover:-translate-y-1"
                >
                  Log In
                </button>
                <button 
                  onClick={() => setView('signup')}
                  className="w-full py-4 bg-gray-100 dark:bg-gray-800 text-nexus-midnight dark:text-white font-bold rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-700 transition-all transform hover:-translate-y-1"
                >
                  Create Account
                </button>
                <p className="text-center text-xs text-gray-400 mt-6 font-medium">
                   Simple. Fast. Secure.
                </p>
             </div>
          </div>
      );
  }

  // 2. Auth Form View (Shared)
  return (
     <div className="h-screen w-full bg-white dark:bg-nexus-dark flex flex-col relative animate-fade-in-up">
        {/* Header */}
        <div className="p-4 flex items-center absolute top-0 left-0 z-20">
           <button 
             onClick={() => setView('welcome')} 
             className="p-3 -ml-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
           >
              <ChevronLeft size={28} className="text-nexus-midnight dark:text-white" />
           </button>
        </div>

        <div className="flex-1 flex flex-col px-8 pt-24 max-w-md mx-auto w-full overflow-y-auto no-scrollbar">
            <div className="mb-8">
               <h2 className="text-3xl font-bold text-nexus-midnight dark:text-white mb-2">
                 {view === 'login' ? 'Welcome back!' : 'Join the fun'}
               </h2>
               <p className="text-gray-500 font-medium">
                 {view === 'login' ? 'Ready to catch up?' : 'Create an account to start chatting.'}
               </p>
            </div>

            {error && (
              <div className="mb-6 p-4 bg-nexus-coral/10 border-l-4 border-nexus-coral text-nexus-coral text-sm rounded-r-xl font-medium animate-fade-in-down">
                 {error}
              </div>
            )}

            <form onSubmit={handleAuth} className="space-y-5 pb-8">
               {view === 'signup' && (
                  <>
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-400 uppercase ml-1">Full Name</label>
                       <input 
                          required
                          type="text" 
                          value={fullName}
                          onChange={(e) => setFullName(e.target.value)}
                          className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                          placeholder="e.g. Sarah Connor"
                       />
                    </div>
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-400 uppercase ml-1">Phone (Optional)</label>
                       <input 
                          type="tel" 
                          value={phone}
                          onChange={(e) => setPhone(e.target.value)}
                          className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                          placeholder="+1 (555) 000-0000"
                       />
                    </div>
                  </>
               )}

               <div className="space-y-1">
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Email</label>
                  <input 
                     required
                     type="email" 
                     value={email}
                     onChange={(e) => setEmail(e.target.value)}
                     className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                     placeholder="you@example.com"
                  />
               </div>

               <div className="space-y-1">
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Password</label>
                  <input 
                     required
                     type="password" 
                     value={password}
                     onChange={(e) => setPassword(e.target.value)}
                     className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                     placeholder="••••••••"
                  />
               </div>

               <button 
                 type="submit" 
                 disabled={loading}
                 className="w-full py-4 mt-6 bg-nexus-midnight dark:bg-white text-white dark:text-nexus-midnight font-bold rounded-2xl shadow-lg flex items-center justify-center gap-2 hover:scale-[1.02] active:scale-95 transition-all"
               >
                 {loading ? <Loader2 className="animate-spin" /> : <ArrowRight size={20} />}
                 <span>{view === 'login' ? 'Sign In' : 'Get Started'}</span>
               </button>
            </form>

