export const updateUserStatus = async (userId: string, status: string, message: string) => {
  const users = getStore(USERS_KEY);
  const idx = users.findIndex((u: any) => u.id === userId);
  if (idx !== -1) {
    users[idx].status = status;
    users[idx].statusMessage = message;
    setStore(USERS_KEY, users);
    localStorage.setItem(SESSION_KEY, JSON.stringify(users[idx]));
  }
};

export const updateUserProfile = async (userId: string, updates: any) => {
  await delay(500);
  const users = getStore(USERS_KEY);
  const idx = users.findIndex((u: any) => u.id === userId);

  if (idx !== -1) {
    const updatedUser = { ...users[idx], ...updates };
    if (updates.preferences && users[idx].preferences) {
        updatedUser.preferences = { ...users[idx].preferences, ...updates.preferences };
    }

    users[idx] = updatedUser;
    setStore(USERS_KEY, users);

    localStorage.setItem(SESSION_KEY, JSON.stringify(updatedUser));
    return updatedUser;
  }
  throw new Error("User not found");
};

// --- TYPING INDICATOR REALTIME HELPERS ---
export const sendTypingEvent = (chatId: string, userId: string, isTyping: boolean) => {
  broadcast.postMessage({
    type: 'TYPING',
    chatId,
    userId,
    isTyping
  });
};

export const subscribeToTypingEvents = (chatId: string, callback: (userId: string, isTyping: boolean) => void) => {
  const handler = (event: MessageEvent) => {
    const data = event.data;
    if (data.type === 'TYPING' && data.chatId === chatId) {
      callback(data.userId, data.isTyping);
    }
  };
  broadcast.addEventListener('message', handler);
  return () => broadcast.removeEventListener('message', handler);
};

import React, { useState, useEffect, useRef } from 'react';
import { Chat, Message, Attachment } from '../types';
import { 
  Send, ArrowLeft, MoreVertical, Paperclip, CheckCheck, 
  Phone, Video, Smile, Share, Search, Clock, CalendarClock, 
  X, Reply, Image as ImageIcon, MapPin, FileText, User, 
  Trash2, Edit2, CornerUpRight
} from 'lucide-react';
import { summarizeChat } from '../services/geminiService';
import { 
  sendTypingEvent, subscribeToTypingEvents, getCurrentUser, 
  toggleReaction, editMessage, deleteMessage 
} from '../services/supabaseClient';
import { ChatInfoSidebar } from './ChatInfoSidebar';
import { ForwardModal } from './ForwardModal';

interface ChatInterfaceProps {
  chat: Chat;
  onBack: () => void;
  onSendMessage: (text: string, scheduledDate?: Date, replyTo?: any, media?: Attachment) => void;
  onCallStart: (isVideo: boolean) => void;
}

const REACTION_EMOJIS = ['👍', '❤️', '😂', '😮', '😢', '🔥'];

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage, onCallStart }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [currentUserId, setCurrentUserId] = useState<string>('');

  // UI States
  const [showInfoSidebar, setShowInfoSidebar] = useState(false);
  const [forwardingMessage, setForwardingMessage] = useState<string | null>(null);
  const [activeReactionMessageId, setActiveReactionMessageId] = useState<string | null>(null);
  const [activeContextMenuId, setActiveContextMenuId] = useState<string | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [scheduledTime, setScheduledTime] = useState<string>('');
  const [showScheduleInput, setShowScheduleInput] = useState(false);

  // Action States
  const [replyingTo, setReplyingTo] = useState<Message | null>(null);
  const [editingMessageState, setEditingMessageState] = useState<Message | null>(null);
  const [showAttachMenu, setShowAttachMenu] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<Attachment | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<any>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    getCurrentUser().then(u => u && setCurrentUserId(u.id));
  }, []);

  useEffect(() => {
    scrollToBottom();
    // Reset transient states when chat changes
    setSummary(null);
    setShowInfoSidebar(false);
    setIsSearching(false);
    setSearchQuery('');
    setTypingUsers(new Set()); 
    setReplyingTo(null);
    setEditingMessageState(null);
    setSelectedMedia(null);
    setShowAttachMenu(false);

    const unsubscribe = subscribeToTypingEvents(chat.id, (userId, isTyping) => {
      if (userId === currentUserId) return;

      setTypingUsers(prev => {
        const next = new Set(prev);
        if (isTyping) {
          next.add(userId);
        } else {
          next.delete(userId);
        }
        return next;
      });
      setTimeout(scrollToBottom, 100);
    });

    return () => {
      unsubscribe();
    };
  }, [chat.id, currentUserId]);

  useEffect(() => {
    if (!isSearching) scrollToBottom();
  }, [chat.messages, isSearching]);

  // Handle Editing State
  useEffect(() => {
    if (editingMessageState) {
      setInputText(editingMessageState.text);
      inputRef.current?.focus();
    } else {
      // Only clear if we were editing
      if (inputText && chat.messages.find(m => m.text === inputText && m.id === editingMessageState?.id)) {
        setInputText('');
      }
    }
  }, [editingMessageState]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputText(e.target.value);

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, true);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        sendTypingEvent(chat.id, currentUserId, false);
      }, 2000);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setSelectedMedia({
          type: file.type.startsWith('image') ? 'image' : 'file',
          url: ev.target?.result as string,
          name: file.name,
          size: file.size
        });
        setShowAttachMenu(false);
        inputRef.current?.focus();
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if (!inputText.trim() && !selectedMedia) return;

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }

    // IF EDITING
    if (editingMessageState) {
      await editMessage(editingMessageState.id, inputText);
      setEditingMessageState(null);
      setInputText('');
      return;
    }

    // IF SENDING NEW
    let scheduledDate: Date | undefined;
    if (scheduledTime) {
      scheduledDate = new Date(scheduledTime);
    }

    const replyContext = replyingTo ? {
      id: replyingTo.id,
      text: replyingTo.text,
      senderName: replyingTo.senderId === 'me' ? 'You' : chat.name, 
      previewMedia: replyingTo.media?.type === 'image' ? replyingTo.media.url : undefined
    } : undefined;

    onSendMessage(inputText, scheduledDate, replyContext, selectedMedia || undefined);

    setInputText('');
    setScheduledTime('');
    setShowScheduleInput(false);
    setReplyingTo(null);
    setSelectedMedia(null);
  };

  const handleDelete = async (msgId: string) => {
    if (confirm("Are you sure you want to delete this message?")) {
      await deleteMessage(msgId);
      setActiveContextMenuId(null);
    }
  };

  const onReactionClick = async (msgId: string, emoji: string) => {
    await toggleReaction(chat.id, msgId, currentUserId, emoji);
    setActiveReactionMessageId(null);
  };

  const isSomeoneTyping = typingUsers.size > 0;

  const filteredMessages = chat.messages.filter(m => {
    if (!searchQuery) return true;
    const dateStr = new Date(m.timestamp).toLocaleDateString();
    return m.text.toLowerCase().includes(searchQuery.toLowerCase()) || dateStr.includes(searchQuery);
  });

  return (
    <div className="flex flex-row h-full w-full overflow-hidden relative">
      <div className="flex-1 flex flex-col h-full bg-[#e4e4e9] dark:bg-[#0f1115] relative min-w-0">

        {/* WALLPAPER PATTERN OVERLAY */}
        <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>

        {/* HEADER */}
        <div className="flex items-center justify-between px-4 py-2.5 bg-white/85 dark:bg-[#1c1c1e]/85 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800 sticky top-0 z-20 transition-all">
          {isSearching ? (
             <div className="flex-1 flex items-center gap-2 animate-fade-in-down">
               <button onClick={() => { setIsSearching(false); setSearchQuery(''); }} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
                 <ArrowLeft size={20} className="text-gray-500" />
               </button>
               <div className="flex-1 relative">
                 <input 
                   autoFocus
                   type="text" 
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   placeholder="Search messages..."
                   className="w-full bg-gray-100 dark:bg-gray-800 rounded-lg py-2 pl-3 pr-8 text-sm outline-none dark:text-white"
                 />
                 {searchQuery && (
                   <button onClick={() => setSearchQuery('')} className="absolute right-2 top-2 text-gray-400">
                     <X size={16} />
                   </button>
                 )}
               </div>
             </div>
          ) : (
            <>
              <div className="flex items-center gap-3">
                <button onClick={onBack} className="p-2 -ml-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full md:hidden text-nexus-midnight dark:text-white transition-colors">
                  <ArrowLeft size={22} />
                </button>

                <div className="flex items-center gap-3 cursor-pointer" onClick={() => setShowInfoSidebar(!showInfoSidebar)}>
                  <div className="relative">
                    <div className={`w-9 h-9 rounded-full flex items-center justify-center text-white font-bold shadow-sm ${chat.isGroup ? 'bg-gradient-to-tr from-blue-500 to-purple-600' : 'bg-gradient-to-tr from-nexus-midnight to-gray-600'}`}>
                      {chat.name[0]}
                    </div>
                    {/* Status Dot */}
                    <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-[#e4e4e9] dark:border-[#0f1115]"></div>
                  </div>
                  <div>
                    <h3 className="font-bold text-sm text-nexus-midnight dark:text-white leading-tight">{chat.name}</h3>
                    <p className="text-[11px] text-nexus-mint font-medium dark:text-nexus-mint/80 opacity-90">
                      {isSomeoneTyping ? 'Typing...' : 'Online'}
                    </p>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-1 md:gap-3 text-nexus-midnight dark:text-gray-300">
                <button onClick={() => setIsSearching(true)} className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors">
                  <Search size={20} />
                </button>

                <button onClick={() => onCallStart(false)} className="hidden sm:block p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors">
                    <Phone size={20} />
                </button>

                <button 
                  onClick={() => setShowInfoSidebar(!showInfoSidebar)}
                  className={`p-2 rounded-full transition-colors ${showInfoSidebar ? 'bg-black/5 dark:bg-white/10' : 'hover:bg-black/5 dark:hover:bg-white/10'}`}
                >
                  <MoreVertical size={20} />
                </button>
              </div>
            </>
          )}
        </div>

        {/* MESSAGES AREA */}
        <div 
          className="flex-1 overflow-y-auto p-4 space-y-1 sm:p-6 no-scrollbar z-0"
          onClick={() => {
            setActiveReactionMessageId(null);
            setActiveContextMenuId(null);
            setShowAttachMenu(false);
          }}
        >
          {filteredMessages.length === 0 && searchQuery && (
             <div className="text-center py-12 text-gray-400">No messages found matching "{searchQuery}"</div>
          )}

          {filteredMessages.map((msg, idx) => {
            const isMe = msg.senderId === 'me';
            const showAvatar = !isMe && (idx === 0 || chat.messages[idx - 1].senderId !== msg.senderId);
            const isScheduled = msg.status === 'scheduled';

            // Render Deleted Message Placeholder
