              return (
                <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} mb-2 opacity-50`}>
                   <div className="px-4 py-2 bg-gray-200 dark:bg-gray-800 rounded-lg text-xs italic text-gray-500 flex items-center gap-2">
                     <Trash2 size={12} />
                     This message was deleted
