export const AuthScreen = ({ onAuthSuccess }: { onAuthSuccess: () => void }) => {
  const [view, setView] = useState<'welcome' | 'login' | 'signup'>('welcome');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');

  // Country Picker State
  const [selectedCountry, setSelectedCountry] = useState(COUNTRY_CODES[0]);
  const [showCountryPicker, setShowCountryPicker] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Password Strength State
  const [strengthScore, setStrengthScore] = useState(0);

  useEffect(() => {
    if (view === 'signup') {
      let score = 0;
      if (password.length >= 8) score++;
      if (/[A-Z]/.test(password)) score++;
      if (/[0-9]/.test(password)) score++;
      if (/[^A-Za-z0-9]/.test(password)) score++;
      setStrengthScore(score);
    }
  }, [password, view]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccess(null);

    try {
      if (view === 'login') {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        onAuthSuccess();
      } else {
        // --- SIGNUP VALIDATION ---

        // 1. Password Strength Check
        if (strengthScore < 3) {
           throw new Error("Password is too weak. Please meet more requirements.");
        }

        // 2. Confirm Password Check
        if (password !== confirmPassword) {
           throw new Error("Passwords do not match.");
        }

        // Combine country code and phone number
        const fullPhone = phoneNumber ? `${selectedCountry.code} ${phoneNumber}` : '';

        const { error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, phone: fullPhone } }
        });
        if (signUpError) throw signUpError;

        // Switch to login view on success
        setView('login');
        setSuccess('Registration successful! Please verify your email.');
        setPassword('');
        setConfirmPassword('');
        setEmail('');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const filteredCountries = useMemo(() => {
    if (!searchQuery) return COUNTRY_CODES;
    const lowerQ = searchQuery.toLowerCase();
    return COUNTRY_CODES.filter(c => 
      c.name.toLowerCase().includes(lowerQ) || 
      c.code.includes(lowerQ) ||
      c.iso.toLowerCase().includes(lowerQ)
    );
  }, [searchQuery]);

  const getStrengthLabel = () => {
    if (strengthScore === 0) return { label: 'Too Weak', color: 'bg-gray-200' };
    if (strengthScore === 1) return { label: 'Weak', color: 'bg-red-500' };
    if (strengthScore === 2) return { label: 'Fair', color: 'bg-orange-500' };
    if (strengthScore === 3) return { label: 'Good', color: 'bg-yellow-400' };
    return { label: 'Strong', color: 'bg-green-500' };
  };

  const strengthInfo = getStrengthLabel();

  // 1. Welcome / Landing Page View
  if (view === 'welcome') {
      return (
          <div className="h-screen w-full bg-white dark:bg-nexus-dark flex flex-col items-center justify-between p-8 relative overflow-hidden transition-colors">
             {/* Decorative Shapes */}
             <div className="absolute top-[-10%] right-[-10%] w-64 h-64 bg-nexus-mint/20 rounded-full pointer-events-none" />
             <div className="absolute bottom-[10%] left-[-5%] w-40 h-40 bg-nexus-coral/10 rounded-full pointer-events-none" />

             <div className="flex-1 flex flex-col items-center justify-center z-10 w-full mt-10">
                <div className="mb-8">
                   <Logo className="w-32 h-32 shadow-xl" />
                </div>

                <h1 className="text-4xl md:text-5xl font-black text-nexus-midnight dark:text-white mb-4 tracking-tight text-center">
                  Nexus
                </h1>
                <p className="text-gray-500 text-center max-w-xs text-lg font-medium leading-relaxed">
                   The friendly way to stay in touch with your favorite people.
                </p>
             </div>

             <div className="w-full max-w-sm z-10 space-y-4 mb-8 animate-fade-in-up">
                <button 
                  onClick={() => setView('login')}
                  className="w-full py-4 bg-nexus-midnight text-white font-bold rounded-2xl shadow-xl hover:shadow-2xl hover:bg-nexus-midnight-hover transition-all transform hover:-translate-y-1"
                >
                  Log In
                </button>
                <button 
                  onClick={() => setView('signup')}
                  className="w-full py-4 bg-gray-100 dark:bg-gray-800 text-nexus-midnight dark:text-white font-bold rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-700 transition-all transform hover:-translate-y-1"
                >
                  Create Account
                </button>
                <p className="text-center text-xs text-gray-400 mt-6 font-medium">
                   Simple. Fast. Secure.
                </p>
             </div>
          </div>
      );
  }

  // 2. Auth Form View (Shared)
  return (
     <div className="h-screen w-full bg-white dark:bg-nexus-dark flex flex-col relative animate-fade-in-up">
        {/* Header */}
        <div className="p-4 flex items-center absolute top-0 left-0 z-20">
           <button 
             onClick={() => setView('welcome')} 
             className="p-3 -ml-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
           >
              <ChevronLeft size={28} className="text-nexus-midnight dark:text-white" />
           </button>
        </div>

        <div className="flex-1 flex flex-col px-8 pt-24 max-w-md mx-auto w-full overflow-y-auto no-scrollbar">
            <div className="mb-8">
               <h2 className="text-3xl font-bold text-nexus-midnight dark:text-white mb-2">
                 {view === 'login' ? 'Welcome back!' : 'Join the fun'}
               </h2>
               <p className="text-gray-500 font-medium">
                 {view === 'login' ? 'Ready to catch up?' : 'Create an account to start chatting.'}
               </p>
            </div>

            {error && (
              <div className="mb-6 p-4 bg-nexus-coral/10 border-l-4 border-nexus-coral text-nexus-coral text-sm rounded-r-xl font-medium animate-fade-in-down flex items-start gap-2">
                 <AlertCircle size={18} className="mt-0.5 flex-shrink-0" />
                 <span>{error}</span>
              </div>
            )}

            {success && (
              <div className="mb-6 p-4 bg-green-100 dark:bg-green-900/30 border-l-4 border-green-500 text-green-700 dark:text-green-300 text-sm rounded-r-xl font-medium animate-fade-in-down flex items-center gap-2">
                 <Check size={18} />
                 <span>{success}</span>
              </div>
            )}

            <form onSubmit={handleAuth} className="space-y-5 pb-8">
               {view === 'signup' && (
                  <>
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-400 uppercase ml-1">Full Name</label>
                       <input 
                          required
                          type="text" 
                          value={fullName}
                          onChange={(e) => setFullName(e.target.value)}
                          className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                          placeholder="e.g. Sarah Connor"
                       />
                    </div>
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-400 uppercase ml-1">Phone Number</label>
                       <div className="flex gap-2">
                         {/* Custom Country Picker Trigger */}
                         <button
                           type="button"
                           onClick={() => setShowCountryPicker(true)}
                           className="relative w-1/3 min-w-[110px] bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent flex items-center justify-between"
                         >
                           <div className="flex items-center gap-2">
                             <span className="text-lg leading-none">{selectedCountry.flag}</span>
                             <span className="text-sm">{selectedCountry.iso}</span>
                           </div>
                           <ChevronDown size={14} className="text-gray-400" />
                         </button>

                         <input 
                            type="tel" 
                            value={phoneNumber}
                            onChange={(e) => setPhoneNumber(e.target.value)}
                            className="w-2/3 bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                            placeholder="812 345 6789"
                         />
                       </div>
                    </div>
                  </>
               )}

               <div className="space-y-1">
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Email</label>
                  <input 
                     required
                     type="email" 
                     value={email}
                     onChange={(e) => setEmail(e.target.value)}
                     className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                     placeholder="you@example.com"
                  />
               </div>

               <div className="space-y-1">
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Password</label>
                  <input 
                     required
                     type="password" 
                     value={password}
                     onChange={(e) => setPassword(e.target.value)}
                     className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800"
                     placeholder="••••••••"
                  />

                  {/* SIGNUP: Strong Password Meter */}
                  {view === 'signup' && (
                    <div className="px-1 pt-2 animate-fade-in-up">
                       <div className="flex items-center justify-between mb-1">
                          <span className="text-[10px] font-bold text-gray-400 uppercase">Strength: <span className={`${strengthScore >= 3 ? 'text-green-500' : strengthScore >= 2 ? 'text-yellow-500' : 'text-nexus-coral'}`}>{strengthInfo.label}</span></span>
                       </div>
                       <div className="flex gap-1 h-1 mb-2">
                          {[1,2,3,4].map((step) => (
                             <div 
                               key={step} 
                               className={`flex-1 rounded-full transition-all duration-300 ${strengthScore >= step ? strengthInfo.color : 'bg-gray-200 dark:bg-gray-700'}`} 
                             />
                          ))}
                       </div>
                       <div className="flex flex-wrap gap-x-3 gap-y-1">
                          <span className={`text-[10px] flex items-center gap-1 ${password.length >= 8 ? 'text-green-500' : 'text-gray-400'}`}>
                             {password.length >= 8 ? <Check size={10} /> : <div className="w-2.5 h-2.5 rounded-full border border-gray-400" />} 8+ chars
                          </span>
                          <span className={`text-[10px] flex items-center gap-1 ${/[A-Z]/.test(password) ? 'text-green-500' : 'text-gray-400'}`}>
                             {/[A-Z]/.test(password) ? <Check size={10} /> : <div className="w-2.5 h-2.5 rounded-full border border-gray-400" />} Uppercase
                          </span>
                          <span className={`text-[10px] flex items-center gap-1 ${/[0-9]/.test(password) ? 'text-green-500' : 'text-gray-400'}`}>
                             {/[0-9]/.test(password) ? <Check size={10} /> : <div className="w-2.5 h-2.5 rounded-full border border-gray-400" />} Number
                          </span>
                          <span className={`text-[10px] flex items-center gap-1 ${/[^A-Za-z0-9]/.test(password) ? 'text-green-500' : 'text-gray-400'}`}>
                             {/[^A-Za-z0-9]/.test(password) ? <Check size={10} /> : <div className="w-2.5 h-2.5 rounded-full border border-gray-400" />} Special
                          </span>
                       </div>
                    </div>
                  )}
               </div>

               {/* SIGNUP: Confirm Password */}
               {view === 'signup' && (
                  <div className="space-y-1 animate-fade-in-up">
                     <label className="text-xs font-bold text-gray-400 uppercase ml-1">Confirm Password</label>
                     <div className="relative">
                       <input 
                          required
                          type="password" 
                          value={confirmPassword}
                          onChange={(e) => setConfirmPassword(e.target.value)}
                          className={`w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-4 rounded-xl outline-none focus:ring-2 transition-all font-bold border-2 ${
                             confirmPassword && confirmPassword !== password 
                               ? 'border-nexus-coral focus:ring-nexus-coral focus:border-nexus-coral' 
                               : 'border-transparent focus:ring-nexus-mint focus:bg-white dark:focus:bg-gray-800'
                          }`}
                          placeholder="••••••••"
                       />
                       {confirmPassword && confirmPassword === password && (
                          <div className="absolute right-4 top-1/2 -translate-y-1/2 text-green-500 animate-fade-in-up">
                             <Check size={20} />
                          </div>
                       )}
                       {confirmPassword && confirmPassword !== password && (
                          <div className="absolute right-4 top-1/2 -translate-y-1/2 text-nexus-coral animate-fade-in-up">
                             <X size={20} />
                          </div>
                       )}
                     </div>
                     {confirmPassword && confirmPassword !== password && (
                        <p className="text-[10px] text-nexus-coral font-bold ml-1">Passwords do not match</p>
                     )}
                  </div>
               )}

               <button 
                 type="submit" 
                 disabled={loading || (view === 'signup' && (strengthScore < 3 || password !== confirmPassword))}
                 className={`w-full py-4 mt-6 text-white font-bold rounded-2xl shadow-lg flex items-center justify-center gap-2 transition-all 
                   ${loading || (view === 'signup' && (strengthScore < 3 || password !== confirmPassword))
                     ? 'bg-gray-300 dark:bg-gray-700 cursor-not-allowed'
                     : 'bg-nexus-midnight dark:bg-white dark:text-nexus-midnight hover:scale-[1.02] active:scale-95'
                   }`}
               >
                 {loading ? <Loader2 className="animate-spin" /> : <ArrowRight size={20} />}
                 <span>{view === 'login' ? 'Sign In' : 'Sign Up'}</span>
               </button>
            </form>

            <div className="mt-auto pb-8 text-center">
               <p className="text-gray-400 text-sm font-medium">
                 {view === 'login' ? "New here?" : "Already have an account?"}
                 <button 
                   onClick={() => {
                     setError(null);
                     setSuccess(null);
                     setView(view === 'login' ? 'signup' : 'login');
                     // Reset fields on switch
                     setPassword('');
                     setConfirmPassword('');
                   }}
                   className="ml-2 font-bold text-nexus-mint hover:text-nexus-mint-hover hover:underline transition-all"
                 >
                   {view === 'login' ? 'Create an account' : 'Log In'}
                 </button>
               </p>
            </div>
        </div>

        {/* COUNTRY PICKER MODAL */}
        {showCountryPicker && (
          <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center sm:p-4 animate-fade-in-up">
            <div className="bg-white dark:bg-nexus-card w-full sm:max-w-sm h-[80vh] sm:h-auto sm:max-h-[80vh] rounded-t-3xl sm:rounded-3xl shadow-2xl flex flex-col overflow-hidden">
               {/* Search Header */}
               <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex items-center gap-3">
                 <div className="flex-1 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center px-3 py-2.5">
                   <Search size={18} className="text-gray-400 mr-2" />
                   <input 
                     autoFocus
                     type="text"
                     placeholder="Search country or code..."
                     className="bg-transparent outline-none w-full text-sm dark:text-white"
                     value={searchQuery}
                     onChange={e => setSearchQuery(e.target.value)}
                   />
                 </div>
                 <button 
                   onClick={() => {
                     setShowCountryPicker(false);
                     setSearchQuery('');
                   }}
                   className="p-2 bg-gray-100 dark:bg-gray-800 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
                 >
                   <X size={20} className="dark:text-white" />
                 </button>
               </div>

               {/* List */}
               <div className="flex-1 overflow-y-auto no-scrollbar">
                  {filteredCountries.length === 0 ? (
                    <div className="p-8 text-center text-gray-400 text-sm">No countries found</div>
                  ) : (
                    <>
                      {/* If searching, show flat list. If not, show categories */}
                      {searchQuery ? (
                        <div className="p-2 space-y-1">
                          {filteredCountries.map((c, idx) => (
                             <button
                                key={`${c.name}-${idx}`}
                                onClick={() => {
                                  setSelectedCountry(c);
                                  setShowCountryPicker(false);
                                  setSearchQuery('');
                                }}
                                className={`w-full flex items-center gap-3 p-3 rounded-xl transition-colors ${selectedCountry.name === c.name ? 'bg-nexus-mint/10' : 'hover:bg-gray-50 dark:hover:bg-gray-800'}`}
                             >
                                <span className="text-2xl">{c.flag}</span>
                                <div className="flex-1 flex flex-col text-left">
                                  <span className="font-medium dark:text-white">{c.name}</span>
                                </div>
                                <div className="flex items-center gap-2">
                                  <span className="text-gray-400 font-bold text-xs bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded">{c.iso}</span>
                                  <span className="text-gray-500 font-mono text-sm">{c.code}</span>
                                </div>
                                {selectedCountry.name === c.name && <Check size={16} className="text-nexus-mint" />}
                             </button>
                          ))}
                        </div>
                      ) : (
                        <div className="p-2 space-y-4">
                           {/* Africa Section */}
                           <div>
                              <div className="px-3 py-2 text-xs font-bold text-gray-400 uppercase tracking-wider sticky top-0 bg-white dark:bg-nexus-card z-10">
                                Africa
                              </div>
                              <div className="space-y-1">
                                {COUNTRY_CODES.filter(c => c.region === 'Africa').map((c, idx) => (
                                  <button
                                    key={`africa-${idx}`}
                                    onClick={() => {
                                      setSelectedCountry(c);
                                      setShowCountryPicker(false);
                                    }}
                                    className={`w-full flex items-center gap-3 p-3 rounded-xl transition-colors ${selectedCountry.name === c.name ? 'bg-nexus-mint/10' : 'hover:bg-gray-50 dark:hover:bg-gray-800'}`}
                                  >
                                    <span className="text-2xl">{c.flag}</span>
                                    <div className="flex-1 flex flex-col text-left">
                                      <span className="font-medium dark:text-white">{c.name}</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                      <span className="text-gray-400 font-bold text-xs bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded">{c.iso}</span>
                                      <span className="text-gray-500 font-mono text-sm">{c.code}</span>
                                    </div>
                                    {selectedCountry.name === c.name && <Check size={16} className="text-nexus-mint" />}
                                  </button>
                                ))}
                              </div>
                           </div>

                           {/* World Section */}
                           <div>
                              <div className="px-3 py-2 text-xs font-bold text-gray-400 uppercase tracking-wider sticky top-0 bg-white dark:bg-nexus-card z-10">
                                International
                              </div>
                              <div className="space-y-1">
                                {COUNTRY_CODES.filter(c => c.region === 'World').map((c, idx) => (
                                  <button
                                    key={`world-${idx}`}
                                    onClick={() => {
                                      setSelectedCountry(c);
                                      setShowCountryPicker(false);
                                    }}
                                    className={`w-full flex items-center gap-3 p-3 rounded-xl transition-colors ${selectedCountry.name === c.name ? 'bg-nexus-mint/10' : 'hover:bg-gray-50 dark:hover:bg-gray-800'}`}
                                  >
                                    <span className="text-2xl">{c.flag}</span>
                                    <div className="flex-1 flex flex-col text-left">
                                      <span className="font-medium dark:text-white">{c.name}</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                      <span className="text-gray-400 font-bold text-xs bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded">{c.iso}</span>
                                      <span className="text-gray-500 font-mono text-sm">{c.code}</span>
                                    </div>
                                    {selectedCountry.name === c.name && <Check size={16} className="text-nexus-mint" />}
                                  </button>
                                ))}
                              </div>
                           </div>
                        </div>
                      )}
                    </>
                  )}
               </div>
            </div>
          </div>
        )}
     </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
