export const AuthScreen = ({ onAuthSuccess }: { onAuthSuccess: () => void }) => {
  const [view, setView] = useState<'welcome' | 'login' | 'signup'>('welcome');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');

  // Country Picker State
  const [selectedCountry, setSelectedCountry] = useState(COUNTRY_CODES[0]);
  const [showCountryPicker, setShowCountryPicker] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Password Strength State
  const [strengthScore, setStrengthScore] = useState(0);

  useEffect(() => {
    if (view === 'signup') {
      let score = 0;
      if (password.length >= 8) score++;
      if (/[A-Z]/.test(password)) score++;
      if (/[0-9]/.test(password)) score++;
      if (/[^A-Za-z0-9]/.test(password)) score++;
      setStrengthScore(score);
    }
  }, [password, view]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccess(null);

    try {
      if (view === 'login') {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        onAuthSuccess();
      } else {
        // --- SIGNUP VALIDATION ---

        // 1. Password Strength Check
        if (strengthScore < 3) {
           throw new Error("Password is too weak. Please meet more requirements.");
        }

        // 2. Confirm Password Check
        if (password !== confirmPassword) {
           throw new Error("Passwords do not match.");
        }

        // Combine country code and phone number
        const fullPhone = phoneNumber ? `${selectedCountry.code} ${phoneNumber}` : '';

        const { error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, phone: fullPhone } }
        });
        if (signUpError) throw signUpError;

        // Switch to login view on success
        setView('login');
        setSuccess('Registration successful! Please verify your email.');
        setPassword('');
        setConfirmPassword('');
        setEmail('');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const filteredCountries = useMemo(() => {
    if (!searchQuery) return COUNTRY_CODES;
    const lowerQ = searchQuery.toLowerCase();
    return COUNTRY_CODES.filter(c => 
      c.name.toLowerCase().includes(lowerQ) || 
      c.code.includes(lowerQ) ||
      c.iso.toLowerCase().includes(lowerQ)
    );
  }, [searchQuery]);

  const getStrengthLabel = () => {
    if (strengthScore === 0) return { label: 'Too Weak', color: 'bg-gray-200' };
    if (strengthScore === 1) return { label: 'Weak', color: 'bg-red-500' };
    if (strengthScore === 2) return { label: 'Fair', color: 'bg-orange-500' };
    if (strengthScore === 3) return { label: 'Good', color: 'bg-yellow-400' };
    return { label: 'Strong', color: 'bg-green-500' };
  };

  const strengthInfo = getStrengthLabel();

  // 1. Welcome / Landing Page View
  if (view === 'welcome') {
      return (
          <div className="h-screen w-full bg-white dark:bg-nexus-dark flex flex-col items-center justify-between p-6 relative overflow-hidden transition-colors">

             {/* Decorative Shapes - Reduced opacity and size for mobile */}
             <div className="absolute top-[-5%] right-[-10%] w-48 h-48 md:w-64 md:h-64 bg-nexus-mint/10 md:bg-nexus-mint/20 rounded-full pointer-events-none" />
             <div className="absolute bottom-[5%] left-[-5%] w-32 h-32 md:w-40 md:h-40 bg-nexus-coral/5 md:bg-nexus-coral/10 rounded-full pointer-events-none" />

             <div className="flex-1 flex flex-col items-center justify-center z-10 w-full mt-8 md:mt-10">
                <div className="mb-6 md:mb-8">
                   <Logo className="w-24 h-24 md:w-32 md:h-32 shadow-xl" />
                </div>

                <h1 className="text-3xl md:text-5xl font-black text-nexus-midnight dark:text-white mb-3 md:mb-4 tracking-tight text-center">
                  Nexus
                </h1>
                <p className="text-gray-500 text-center max-w-xs text-base md:text-lg font-medium leading-relaxed">
                   The friendly way to stay in touch with your favorite people.
                </p>
             </div>

             <div className="w-full max-w-sm z-10 space-y-3 md:space-y-4 mb-6 md:mb-8 animate-fade-in-up">
                <button 
                  onClick={() => setView('login')}
                  className="w-full py-3.5 md:py-4 bg-nexus-midnight text-white font-bold rounded-2xl shadow-xl hover:shadow-2xl hover:bg-nexus-midnight-hover transition-all transform hover:-translate-y-1"
                >
                  Log In
                </button>
                <button 
                  onClick={() => setView('signup')}
                  className="w-full py-3.5 md:py-4 bg-gray-100 dark:bg-gray-800 text-nexus-midnight dark:text-white font-bold rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-700 transition-all transform hover:-translate-y-1"
                >
                  Create Account
                </button>
                <p className="text-center text-xs text-gray-400 mt-4 md:mt-6 font-medium">
                   Simple. Fast. Secure.
                </p>
             </div>
          </div>
      );
  }

  // 2. Auth Form View (Shared)
  return (
     <div className="h-screen w-full bg-white dark:bg-nexus-dark flex flex-col relative animate-fade-in-up">
        {/* Header - Reduced padding */}
        <div className="p-4 flex items-center absolute top-0 left-0 z-20">
           <button 
             onClick={() => setView('welcome')} 
             className="p-2 md:p-3 -ml-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
           >
              <ChevronLeft size={24} className="md:w-7 md:h-7 text-nexus-midnight dark:text-white" />
           </button>
        </div>

        {/* Container - Reduced top padding and side padding for mobile */}
        <div className="flex-1 flex flex-col px-6 pt-16 md:pt-24 max-w-md mx-auto w-full overflow-y-auto no-scrollbar">
            <div className="mb-6 md:mb-8">
               <h2 className="text-2xl md:text-3xl font-bold text-nexus-midnight dark:text-white mb-2">
                 {view === 'login' ? 'Welcome back!' : 'Join the fun'}
               </h2>
               <p className="text-gray-500 text-sm md:text-base font-medium">
                 {view === 'login' ? 'Ready to catch up?' : 'Create an account to start chatting.'}
               </p>
            </div>

            {/* Error/Success Messages */}
            {error && (
              <div className="mb-4 md:mb-6 p-3 md:p-4 bg-nexus-coral/10 border-l-4 border-nexus-coral text-nexus-coral text-xs md:text-sm rounded-r-xl font-medium animate-fade-in-down flex items-start gap-2">
                 <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                 <span>{error}</span>
              </div>
            )}

            {success && (
              <div className="mb-4 md:mb-6 p-3 md:p-4 bg-green-100 dark:bg-green-900/30 border-l-4 border-green-500 text-green-700 dark:text-green-300 text-xs md:text-sm rounded-r-xl font-medium animate-fade-in-down flex items-center gap-2">
                 <Check size={16} />
                 <span>{success}</span>
              </div>
            )}

            {/* Form - Reduced spacing */}
            <form onSubmit={handleAuth} className="space-y-4 md:space-y-5 pb-8">
               {view === 'signup' && (
                  <>
                    <div className="space-y-1">
                       <label className="text-[10px] md:text-xs font-bold text-gray-400 uppercase ml-1">Full Name</label>
                       <input 
                          required
                          type="text" 
                          value={fullName}
                          onChange={(e) => setFullName(e.target.value)}
                          className="w-full bg-gray-50 dark:bg-gray-800 text-nexus-midnight dark:text-white p-3.5 md:p-4 rounded-xl outline-none focus:ring-2 focus:ring-nexus-mint transition-all font-bold border-2 border-transparent focus:bg-white dark:focus:bg-gray-800 text-sm md:text-base"
                          placeholder="e.g. Sarah Connor"
                       />
                    </div>
                    <div className="space-y-1">
                       <label className="text-[10px] md:text-xs font-bold text-gray-400 uppercase ml-1">Phone Number</label>
                       <div className="flex gap-2">
                         {/* Custom Country Picker Trigger */}
                         <button
                           type="button"
                           onClick={() => setShowCountryPicker(true)}
