export const sendTypingEvent = (chatId: string, userId: string, isTyping: boolean) => {
  broadcast.postMessage({
    type: 'TYPING',
    chatId,
    userId,
    isTyping
  });
};

export const subscribeToTypingEvents = (chatId: string, callback: (userId: string, isTyping: boolean) => void) => {
  const handler = (event: MessageEvent) => {
    const data = event.data;
    if (data.type === 'TYPING' && data.chatId === chatId) {
      callback(data.userId, data.isTyping);
    }
  };
  broadcast.addEventListener('message', handler);
  return () => broadcast.removeEventListener('message', handler);
};

import React, { useState } from 'react';
import { Search, UserPlus, X, Send, Mail, MessageSquare, Users, CheckCircle, ArrowRight, ArrowLeft } from 'lucide-react';
import { searchUsers, createNewChat, createGhostUser, sendInvite } from '../services/supabaseClient';

interface NewChatModalProps {
  currentUserId: string;
  onClose: () => void;
  onChatCreated: () => void;
}

type ModalStep = 'search' | 'group_participants' | 'group_details';

export const NewChatModal: React.FC<NewChatModalProps> = ({ currentUserId, onClose, onChatCreated }) => {
  const [step, setStep] = useState<ModalStep>('search');
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [inviteSent, setInviteSent] = useState(false);

  // Group Creation State
  const [selectedUsers, setSelectedUsers] = useState<any[]>([]);
  const [groupName, setGroupName] = useState('');

  const handleSearch = async (val: string) => {
    setQuery(val);
    setInviteSent(false); // Reset if typing
    if (val.length > 2) {
      setLoading(true);
      const users = await searchUsers(val);
      // Filter out self
      setResults(users.filter((u: any) => u.id !== currentUserId));
      setLoading(false);
    } else {
      setResults([]);
    }
  };

  const startOneOnOneChat = async (userId: string, userName: string) => {
    try {
      setLoading(true);
      // Pass isGroup = false
      await createNewChat(currentUserId, [userId], userName, false);
      onChatCreated();
      onClose();
    } catch (e) {
      console.error(e);
      setLoading(false);
    }
