  const createGroup = async () => {
    if (!groupName.trim() || selectedUsers.length === 0) return;
    try {
      setLoading(true);
      const participantIds = selectedUsers.map(u => u.id);
      await createNewChat(currentUserId, participantIds, groupName, true);
