import React, { useState, useEffect, useRef } from 'react';
import { Chat, Message, Attachment } from '../types';
import { 
  Send, ArrowLeft, MoreVertical, Paperclip, CheckCheck, 
  Phone, Video, Smile, Share, Search, Clock, CalendarClock, 
  X, Reply, Image as ImageIcon, MapPin, FileText, User, 
  Trash2, Edit2, CornerUpRight, Sparkles
} from 'lucide-react';
import { summarizeChat } from '../services/geminiService';
import { 
  sendTypingEvent, subscribeToTypingEvents, getCurrentUser, 
  toggleReaction, editMessage, deleteMessage 
} from '../services/supabaseClient';
import { ChatInfoSidebar } from './ChatInfoSidebar';
import { ForwardModal } from './ForwardModal';

interface ChatInterfaceProps {
  chat: Chat;
  onBack: () => void;
  onSendMessage: (text: string, scheduledDate?: Date, replyTo?: any, media?: Attachment) => void;
  onCallStart: (isVideo: boolean) => void;
}

const REACTION_EMOJIS = ['👍', '❤️', '😂', '😮', '😢', '🔥'];

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ chat, onBack, onSendMessage, onCallStart }) => {
  const [inputText, setInputText] = useState('');
  const [summary, setSummary] = useState<string | null>(null);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [currentUserId, setCurrentUserId] = useState<string>('');

  // UI States
  const [showInfoSidebar, setShowInfoSidebar] = useState(false);
  const [forwardingMessage, setForwardingMessage] = useState<string | null>(null);
  const [activeReactionMessageId, setActiveReactionMessageId] = useState<string | null>(null);
  const [activeContextMenuId, setActiveContextMenuId] = useState<string | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [scheduledTime, setScheduledTime] = useState<string>('');
  const [showScheduleInput, setShowScheduleInput] = useState(false);

  // Action States
  const [replyingTo, setReplyingTo] = useState<Message | null>(null);
  const [editingMessageState, setEditingMessageState] = useState<Message | null>(null);
  const [showAttachMenu, setShowAttachMenu] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<Attachment | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<any>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    getCurrentUser().then(u => u && setCurrentUserId(u.id));
  }, []);

  useEffect(() => {
    scrollToBottom();
    // Reset transient states when chat changes
    setSummary(null);
    setIsSummarizing(false);
    setShowInfoSidebar(false);
    setIsSearching(false);
    setSearchQuery('');
    setTypingUsers(new Set()); 
    setReplyingTo(null);
    setEditingMessageState(null);
    setSelectedMedia(null);
    setShowAttachMenu(false);

    const unsubscribe = subscribeToTypingEvents(chat.id, (userId, isTyping) => {
      if (userId === currentUserId) return;

      setTypingUsers(prev => {
        const next = new Set(prev);
        if (isTyping) {
          next.add(userId);
        } else {
          next.delete(userId);
        }
        return next;
      });
      setTimeout(scrollToBottom, 100);
    });

    return () => {
      unsubscribe();
    };
  }, [chat.id, currentUserId]);

  useEffect(() => {
    if (!isSearching) scrollToBottom();
  }, [chat.messages, isSearching]);

  // Handle Editing State
  useEffect(() => {
    if (editingMessageState) {
      setInputText(editingMessageState.text);
      inputRef.current?.focus();
    } else {
      // Only clear if we were editing
      if (inputText && chat.messages.find(m => m.text === inputText && m.id === editingMessageState?.id)) {
        setInputText('');
      }
    }
  }, [editingMessageState]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputText(e.target.value);

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, true);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        sendTypingEvent(chat.id, currentUserId, false);
      }, 2000);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setSelectedMedia({
          type: file.type.startsWith('image') ? 'image' : 'file',
          url: ev.target?.result as string,
          name: file.name,
          size: file.size
        });
        setShowAttachMenu(false);
        inputRef.current?.focus();
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if (!inputText.trim() && !selectedMedia) return;

    if (currentUserId) {
      sendTypingEvent(chat.id, currentUserId, false);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    }

    // IF EDITING
    if (editingMessageState) {
      await editMessage(editingMessageState.id, inputText);
      setEditingMessageState(null);
      setInputText('');
      return;
    }

    // IF SENDING NEW
    let scheduledDate: Date | undefined;
    if (scheduledTime) {
      scheduledDate = new Date(scheduledTime);
    }

    const replyContext = replyingTo ? {
      id: replyingTo.id,
      text: replyingTo.text,
      senderName: replyingTo.senderId === 'me' ? 'You' : chat.name, 
      previewMedia: replyingTo.media?.type === 'image' ? replyingTo.media.url : undefined
    } : undefined;

    onSendMessage(inputText, scheduledDate, replyContext, selectedMedia || undefined);

    setInputText('');
    setScheduledTime('');
    setShowScheduleInput(false);
    setReplyingTo(null);
    setSelectedMedia(null);
  };

  const handleDelete = async (msgId: string) => {
    if (confirm("Are you sure you want to delete this message?")) {
      await deleteMessage(msgId);
      setActiveContextMenuId(null);
    }
  };

  const onReactionClick = async (msgId: string, emoji: string) => {
    await toggleReaction(chat.id, msgId, currentUserId, emoji);
    setActiveReactionMessageId(null);
  };

  const handleSummarize = async () => {
    if (chat.messages.length === 0) return;
    setIsSummarizing(true);
    const text = await summarizeChat(chat.messages);
    setSummary(text);
    setIsSummarizing(false);
  };

  const isSomeoneTyping = typingUsers.size > 0;

  const filteredMessages = chat.messages.filter(m => {
    if (!searchQuery) return true;
    const dateStr = new Date(m.timestamp).toLocaleDateString();
    return m.text.toLowerCase().includes(searchQuery.toLowerCase()) || dateStr.includes(searchQuery);
  });

  return (
    <div className="flex flex-row h-full w-full overflow-hidden relative">
      <div className="flex-1 flex flex-col h-full bg-[#e4e4e9] dark:bg-[#0f1115] relative min-w-0">

        {/* WALLPAPER PATTERN OVERLAY */}
        <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>

        {/* HEADER */}
        <div className="flex items-center justify-between px-4 py-2.5 bg-white/85 dark:bg-[#1c1c1e]/85 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800 sticky top-0 z-20 transition-all">
          {isSearching ? (
             <div className="flex-1 flex items-center gap-2 animate-fade-in-down">
               <button onClick={() => { setIsSearching(false); setSearchQuery(''); }} className="p-2 -ml-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
                 <ArrowLeft size={20} className="text-gray-500" />
               </button>
               <div className="flex-1 relative">
                 <input 
                   autoFocus
                   type="text" 
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   placeholder="Search messages..."
                   className="w-full bg-gray-100 dark:bg-gray-800 rounded-lg py-2 pl-3 pr-8 text-sm outline-none dark:text-white"
                 />
                 {searchQuery && (
                   <button onClick={() => setSearchQuery('')} className="absolute right-2 top-2 text-gray-400">
                     <X size={16} />
                   </button>
                 )}
               </div>
             </div>
          ) : (
            <>
              <div className="flex items-center gap-3">
                <button onClick={onBack} className="p-2 -ml-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full md:hidden text-nexus-midnight dark:text-white transition-colors">
                  <ArrowLeft size={22} />
                </button>

                <div className="flex items-center gap-3 cursor-pointer" onClick={() => setShowInfoSidebar(!showInfoSidebar)}>
                  <div className="relative">
                    <div className={`w-9 h-9 rounded-full flex items-center justify-center text-white font-bold shadow-sm ${chat.isGroup ? 'bg-gradient-to-tr from-blue-500 to-purple-600' : 'bg-gradient-to-tr from-nexus-midnight to-gray-600'}`}>
                      {chat.name[0]}
                    </div>
                    {/* Status Dot */}
                    <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-[#e4e4e9] dark:border-[#0f1115]"></div>
                  </div>
                  <div>
                    <h3 className="font-bold text-sm text-nexus-midnight dark:text-white leading-tight">{chat.name}</h3>
                    <p className="text-[11px] text-nexus-mint font-medium dark:text-nexus-mint/80 opacity-90">
                      {isSomeoneTyping ? 'Typing...' : 'Online'}
                    </p>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-1 md:gap-3 text-nexus-midnight dark:text-gray-300">
                {/* AI Summary Button */}
                <button 
                  onClick={handleSummarize}
                  disabled={isSummarizing || chat.messages.length === 0}
                  className={`p-2 rounded-full transition-colors ${
                    isSummarizing 
                      ? 'bg-nexus-mint/20 text-nexus-mint animate-pulse' 
                      : 'hover:bg-black/5 dark:hover:bg-white/10'
                  }`}
                  title="Summarize Chat"
                >
                  <Sparkles size={20} className={isSummarizing ? "animate-spin" : ""} />
                </button>

                <button onClick={() => setIsSearching(true)} className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors">
                  <Search size={20} />
                </button>

                <button onClick={() => onCallStart(false)} className="hidden sm:block p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors">
                    <Phone size={20} />
                </button>

                <button 
                  onClick={() => setShowInfoSidebar(!showInfoSidebar)}
                  className={`p-2 rounded-full transition-colors ${showInfoSidebar ? 'bg-black/5 dark:bg-white/10' : 'hover:bg-black/5 dark:hover:bg-white/10'}`}
                >
                  <MoreVertical size={20} />
                </button>
              </div>
            </>
          )}
        </div>

        {/* AI SUMMARY CARD */}
        {summary && (
          <div className="mx-4 mt-4 bg-white/90 dark:bg-nexus-card/90 backdrop-blur-md rounded-2xl p-4 shadow-lg border border-nexus-mint/30 animate-fade-in-down z-10 relative">
             <div className="flex items-start gap-3">
                <div className="p-2 bg-nexus-mint/20 rounded-lg text-nexus-mint">
                   <Sparkles size={20} />
                </div>
                <div className="flex-1">
                   <h4 className="font-bold text-nexus-midnight dark:text-white text-sm mb-1">AI Summary</h4>
                   <p className="text-sm text-gray-600 dark:text-gray-300 leading-relaxed">{summary}</p>
                </div>
                <button 
                  onClick={() => setSummary(null)}
                  className="p-1 hover:bg-black/5 dark:hover:bg-white/10 rounded-full text-gray-400"
                >
                   <X size={16} />
                </button>
             </div>
          </div>
        )}

        {/* MESSAGES AREA */}
        <div 
          className="flex-1 overflow-y-auto p-4 space-y-1 sm:p-6 no-scrollbar z-0"
          onClick={() => {
            setActiveReactionMessageId(null);
            setActiveContextMenuId(null);
            setShowAttachMenu(false);
          }}
        >
          {filteredMessages.length === 0 && searchQuery && (
             <div className="text-center py-12 text-gray-400">No messages found matching "{searchQuery}"</div>
          )}

          {filteredMessages.map((msg, idx) => {
            const isMe = msg.senderId === 'me';
            const showAvatar = !isMe && (idx === 0 || chat.messages[idx - 1].senderId !== msg.senderId);
            const isScheduled = msg.status === 'scheduled';

            // Render Deleted Message Placeholder
            if (msg.isDeleted) {
              return (
                <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} mb-2 opacity-50`}>
                   <div className="px-4 py-2 bg-gray-200 dark:bg-gray-800 rounded-lg text-xs italic text-gray-500 flex items-center gap-2">
                     <Trash2 size={12} />
                     This message was deleted
                   </div>
                </div>
              );
            }

            // System Messages (e.g. Group Created)
            if (msg.senderId === 'system') {
               return (
                 <div key={msg.id} className="flex justify-center my-4">
                    <span className="bg-gray-200/50 dark:bg-gray-800/50 text-gray-500 text-xs px-3 py-1 rounded-full font-medium">
                      {msg.text}
                    </span>
                 </div>
               );
            }

            return (
              <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} group relative mb-1`}>
                <div className={`flex ${isMe ? 'justify-end' : 'justify-start'} max-w-full`}>

                  {/* Avatar for Group/Partner */}
                  {!isMe && (
                    <div className={`w-8 h-8 rounded-full bg-gradient-to-br from-gray-400 to-gray-500 flex items-center justify-center text-xs font-bold text-white mr-2 self-end mb-1 transition-opacity duration-300 ${showAvatar ? 'opacity-100' : 'opacity-0'}`}>
                      {chat.name[0]}
                    </div>
                  )}

                  <div className="relative group/bubble max-w-[85vw] md:max-w-[480px]">

                    {/* CONTEXT MENU (Reply, Edit, Delete) */}
                    {activeContextMenuId === msg.id && (
                       <div className={`absolute bottom-full mb-2 ${isMe ? 'right-0' : 'left-0'} z-50 min-w-[160px] bg-white/90 dark:bg-[#2c2c2e]/90 backdrop-blur-xl shadow-2xl rounded-xl border border-gray-100 dark:border-gray-700 overflow-hidden animate-fade-in-up flex flex-col`}>
                          <button onClick={(e) => { e.stopPropagation(); setReplyingTo(msg); inputRef.current?.focus(); setActiveContextMenuId(null); }} className="px-4 py-3 text-left text-sm hover:bg-black/5 dark:hover:bg-white/5 flex items-center gap-3 dark:text-white">
                             <Reply size={16} /> Reply
                          </button>
                          {isMe && (
                            <button onClick={(e) => { e.stopPropagation(); setEditingMessageState(msg); setActiveContextMenuId(null); }} className="px-4 py-3 text-left text-sm hover:bg-black/5 dark:hover:bg-white/5 flex items-center gap-3 dark:text-white">
                              <Edit2 size={16} /> Edit
                            </button>
                          )}
                          <button onClick={(e) => { e.stopPropagation(); setForwardingMessage(msg.text); setActiveContextMenuId(null); }} className="px-4 py-3 text-left text-sm hover:bg-black/5 dark:hover:bg-white/5 flex items-center gap-3 dark:text-white">
                             <CornerUpRight size={16} /> Forward
                          </button>
                          {isMe && (
                             <button onClick={(e) => { e.stopPropagation(); handleDelete(msg.id); }} className="px-4 py-3 text-left text-sm hover:bg-red-50 dark:hover:bg-red-900/20 text-red-500 flex items-center gap-3 border-t dark:border-gray-700">
                               <Trash2 size={16} /> Delete
                             </button>
                          )}
                       </div>
                    )}

                    {/* Message Bubble */}
                    <div 
                      onDoubleClick={() => setReplyingTo(msg)}
                      onContextMenu={(e) => { e.preventDefault(); setActiveContextMenuId(msg.id); }}
                      className={`relative shadow-sm transition-all duration-200 overflow-hidden cursor-pointer
                      ${isMe 
                        ? (isScheduled 
                            ? 'bg-nexus-midnight/80 border border-dashed border-white/20 text-white rounded-[20px] rounded-br-md' 
                            : 'bg-nexus-midnight text-white rounded-[20px] rounded-br-md')
                        : 'bg-white dark:bg-[#1c1c1e] text-nexus-midnight dark:text-gray-100 rounded-[20px] rounded-bl-md'
                      }`}
                    >
                        {/* REPLY CONTEXT DISPLAY */}
                        {msg.replyTo && (
                           <div className={`mx-1 mt-1 mb-1 p-1 rounded-lg flex items-center gap-2 border-l-2 text-xs overflow-hidden
                             ${isMe 
                               ? 'bg-white/10 border-white/50 text-gray-200' 
                               : 'bg-gray-100 dark:bg-gray-800 border-nexus-mint/80 text-gray-600 dark:text-gray-300'
                             }`}
                           >
                             {msg.replyTo.previewMedia && (
                               <img src={msg.replyTo.previewMedia} alt="Reply" className="w-8 h-8 object-cover rounded-md" />
                             )}
                             <div className="flex-1 min-w-0">
                               <div className="font-bold truncate opacity-90">{msg.replyTo.senderName}</div>
                               <div className="truncate opacity-75">{msg.replyTo.text || 'Photo'}</div>
                             </div>
                           </div>
                        )}

                        {/* IMAGE CONTENT */}
                        {msg.media && msg.media.type === 'image' && (
                          <div className="p-1 pb-0">
                            <img src={msg.media.url} alt="Shared" className="rounded-xl w-full h-auto max-h-[300px] object-cover" />
                          </div>
                        )}

                        <div className={`px-3 py-1.5 text-[15px] leading-relaxed whitespace-pre-wrap break-words ${msg.media ? 'pt-2' : ''}`}>
                          {msg.text}
                        </div>

                        {/* Timestamp & Status */}
                        <div className={`px-3 pb-1 flex justify-end items-center gap-1 text-[10px] select-none ${isMe ? 'text-gray-400' : 'text-gray-400'}`}>
                          {msg.editedAt && <span className="italic mr-1">edited</span>}
                          {isScheduled && <CalendarClock size={10} className="mr-1" />}
                          <span>
                             {isScheduled && msg.scheduledFor 
                               ? `Scheduled: ${msg.scheduledFor.toLocaleDateString()}` 
                               : new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})
                             }
                          </span>
                          {isMe && !isScheduled && <CheckCheck size={14} className={msg.status === 'read' ? 'text-nexus-mint' : 'text-gray-400'} />}
                        </div>
                    </div>

                    {/* Reactions Display */}
                    {msg.reactions && Object.keys(msg.reactions).length > 0 && (
                      <div className={`absolute -bottom-2 ${isMe ? 'right-0' : 'left-0'} flex gap-1 z-10 scale-90`}>
                        {Object.entries(msg.reactions).map(([emoji, users]) => (
                          <div key={emoji} className="bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm border dark:border-gray-700 rounded-full px-1.5 py-0.5 text-[10px] shadow-sm flex items-center gap-0.5 cursor-pointer hover:scale-110 transition-transform">
                            <span>{emoji}</span>
                            {(users as string[]).length > 1 && <span className="text-gray-500 font-bold">{(users as string[]).length}</span>}
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Hover Quick Actions */}
                    {!isScheduled && (
                      <div className={`absolute top-1/2 -translate-y-1/2 ${isMe ? '-left-20' : '-right-20'} flex items-center gap-2 opacity-0 group-hover/bubble:opacity-100 transition-opacity`}>
                         <button 
                           onClick={(e) => { e.stopPropagation(); setReplyingTo(msg); inputRef.current?.focus(); }}
                           className="p-2 bg-white/10 dark:bg-black/20 hover:bg-white/20 dark:hover:bg-white/10 rounded-full backdrop-blur-md text-gray-500 dark:text-gray-400 shadow-sm"
                         >
                           <Reply size={16} />
                         </button>
                         <button 
                           onClick={(e) => { e.stopPropagation(); setActiveReactionMessageId(activeReactionMessageId === msg.id ? null : msg.id); }}
                           className="p-2 bg-white/10 dark:bg-black/20 hover:bg-white/20 dark:hover:bg-white/10 rounded-full backdrop-blur-md text-gray-500 dark:text-gray-400 shadow-sm"
                         >
                           <Smile size={16} />
                         </button>
                         <button 
                           onClick={(e) => { e.stopPropagation(); setActiveContextMenuId(activeContextMenuId === msg.id ? null : msg.id); }}
                           className="p-2 bg-white/10 dark:bg-black/20 hover:bg-white/20 dark:hover:bg-white/10 rounded-full backdrop-blur-md text-gray-500 dark:text-gray-400 shadow-sm md:hidden"
                         >
                           <MoreVertical size={16} />
                         </button>
                      </div>
                    )}

                    {/* Reaction Picker Popover */}
                    {activeReactionMessageId === msg.id && (
                      <div className={`absolute -top-12 ${isMe ? 'right-0' : 'left-0'} bg-white/90 dark:bg-[#1c1c1e]/90 backdrop-blur-xl shadow-xl rounded-full p-1.5 flex gap-1 animate-fade-in-up z-20 border dark:border-gray-700`}>
                        {REACTION_EMOJIS.map(emoji => (
                          <button
                            key={emoji}
                            onClick={(e) => { e.stopPropagation(); onReactionClick(msg.id, emoji); }}
                            className="w-8 h-8 flex items-center justify-center hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full text-lg transition-transform hover:scale-125 origin-bottom"
                          >
                            {emoji}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}

          {/* TYPING INDICATOR */}
          {isSomeoneTyping && (
            <div className="flex justify-start animate-fade-in-up">
              <div className="w-8 h-8 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center text-xs font-bold mr-2 self-end mb-1 opacity-100">
                {chat.name[0]}
              </div>
              <div className="bg-white dark:bg-[#1c1c1e] rounded-2xl rounded-bl-sm px-4 py-3 shadow-sm">
                <div className="flex items-center gap-1 h-3">
                  <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                  <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                  <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></span>
                </div>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* INPUT AREA */}
        <div className="p-3 bg-white/80 dark:bg-[#1c1c1e]/80 backdrop-blur-lg border-t border-gray-100 dark:border-gray-800 relative z-30">

          {/* EDITING INDICATOR */}
          {editingMessageState && (
             <div className="flex items-center justify-between mb-2 pl-4 pr-2 py-2 bg-nexus-midnight/5 dark:bg-white/5 border-l-4 border-nexus-midnight dark:border-white rounded-r-lg animate-fade-in-up">
               <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <Edit2 size={12} className="text-nexus-midnight dark:text-white" />
                    <span className="text-xs font-bold text-nexus-midnight dark:text-white uppercase">Editing Message</span>
                  </div>
                  <div className="text-sm truncate text-gray-600 dark:text-gray-300 ml-5">{editingMessageState.text}</div>
               </div>
               <button onClick={() => { setEditingMessageState(null); setInputText(''); }} className="p-1 hover:bg-black/10 dark:hover:bg-white/10 rounded-full transition-colors">
                 <X size={16} className="text-gray-500" />
               </button>
             </div>
          )}

          {/* REPLY CONTEXT BAR */}
          {replyingTo && !editingMessageState && (
            <div className="flex items-center justify-between mb-2 pl-4 pr-2 py-2 bg-nexus-mint/10 dark:bg-nexus-mint/5 border-l-4 border-nexus-mint rounded-r-lg animate-fade-in-up">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <Reply size={12} className="text-nexus-mint" />
                  <span className="text-xs font-bold text-nexus-mint uppercase">Reply to {replyingTo.senderId === 'me' ? 'Yourself' : chat.name}</span>
                </div>
                <div className="text-sm truncate text-gray-600 dark:text-gray-300 ml-5">{replyingTo.text || 'Photo'}</div>
              </div>

              {replyingTo.media && replyingTo.media.type === 'image' && (
                 <img src={replyingTo.media.url} className="w-10 h-10 rounded object-cover mr-2" alt="preview" />
              )}

              <button onClick={() => setReplyingTo(null)} className="p-1 hover:bg-black/10 dark:hover:bg-white/10 rounded-full transition-colors">
                <X size={16} className="text-gray-500" />
              </button>
            </div>
          )}

          {/* MEDIA PREVIEW BAR */}
          {selectedMedia && (
            <div className="flex items-center gap-4 mb-2 p-3 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-gray-100 dark:border-gray-700 animate-fade-in-up">
               <div className="relative">
                 {selectedMedia.type === 'image' ? (
                   <img src={selectedMedia.url} alt="Upload" className="w-16 h-16 object-cover rounded-lg shadow-sm" />
                 ) : (
                   <div className="w-16 h-16 bg-blue-100 dark:bg-blue-900 rounded-lg flex items-center justify-center">
                     <FileText size={24} className="text-blue-500" />
                   </div>
                 )}
                 <button 
                  onClick={() => setSelectedMedia(null)}
                  className="absolute -top-2 -right-2 bg-gray-500 text-white rounded-full p-0.5 shadow-md hover:bg-red-500 transition-colors"
                 >
                   <X size={12} />
                 </button>
               </div>
               <div>
                  <div className="font-bold text-sm dark:text-white">Sending {selectedMedia.type}</div>
                  <div className="text-xs text-gray-500">{selectedMedia.name}</div>
               </div>
            </div>
          )}

          {/* ATTACHMENT MENU (TELEGRAM STYLE) */}
          {showAttachMenu && (
             <div className="absolute bottom-20 left-4 bg-white/90 dark:bg-[#2c2c2e]/90 backdrop-blur-2xl p-4 rounded-3xl shadow-2xl border dark:border-gray-700 animate-fade-in-up flex flex-wrap gap-4 w-64 z-50">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="flex flex-col items-center gap-2 cursor-pointer group"
                >
                   <div className="w-12 h-12 rounded-full bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                      <ImageIcon size={20} />
                   </div>
                   <span className="text-xs font-medium dark:text-gray-200">Photo</span>
                </div>
                <div className="flex flex-col items-center gap-2 cursor-pointer group">
                   <div className="w-12 h-12 rounded-full bg-gradient-to-br from-green-400 to-emerald-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                      <FileText size={20} />
                   </div>
                   <span className="text-xs font-medium dark:text-gray-200">File</span>
                </div>
                <div className="flex flex-col items-center gap-2 cursor-pointer group">
                   <div className="w-12 h-12 rounded-full bg-gradient-to-br from-red-400 to-orange-500 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                      <MapPin size={20} />
                   </div>
                   <span className="text-xs font-medium dark:text-gray-200">Location</span>
                </div>
             </div>
          )}

          {/* HIDDEN FILE INPUT */}
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileSelect} 
            accept="image/*"
            className="hidden" 
          />

          <div className="flex items-end gap-2 max-w-4xl mx-auto">
            <button 
              onClick={() => setShowAttachMenu(!showAttachMenu)}
              className={`p-3 rounded-full transition-all duration-300 ${showAttachMenu ? 'rotate-45 bg-nexus-midnight text-white' : 'text-gray-500 hover:text-nexus-midnight dark:hover:text-white hover:bg-gray-100 dark:hover:bg-gray-700'}`}
            >
              <Paperclip size={22} />
            </button>

            <div className="flex-1 bg-gray-100 dark:bg-[#2c2c2e] rounded-[24px] border border-transparent focus-within:border-nexus-mint/30 focus-within:bg-white dark:focus-within:bg-black transition-all flex items-center px-4 py-2">
               <input
                ref={inputRef}
                type="text"
                value={inputText}
                onChange={handleInputChange}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder={selectedMedia ? "Add a caption..." : (editingMessageState ? "Edit message..." : "Message")}
                className="flex-1 bg-transparent border-none outline-none text-gray-800 dark:text-white placeholder-gray-500 py-1"
               />

               <button 
                 onClick={() => setShowScheduleInput(!showScheduleInput)}
                 className={`p-1.5 ml-2 rounded-full transition-colors ${showScheduleInput ? 'text-nexus-mint' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 <Clock size={18} />
               </button>
            </div>

            {showScheduleInput && (
               <input 
                 type="datetime-local" 
                 value={scheduledTime}
                 onChange={(e) => setScheduledTime(e.target.value)}
                 className="absolute bottom-20 right-4 bg-white dark:bg-nexus-card p-2 rounded-xl shadow-xl border dark:border-gray-700 outline-none text-sm dark:text-white animate-fade-in-up"
               />
            )}

            <button 
              onClick={handleSend}
              disabled={!inputText.trim() && !selectedMedia}
              className={`p-3 rounded-full transition-all duration-300 transform shadow-md ${
                (inputText.trim() || selectedMedia)
                  ? 'bg-nexus-midnight dark:bg-nexus-mint text-white dark:text-nexus-midnight hover:scale-105 active:scale-95'
                  : 'bg-gray-200 dark:bg-gray-800 text-gray-400'
              }`}
            >
              {editingMessageState ? <CheckCheck size={20} /> : (scheduledTime ? <CalendarClock size={20} /> : <Send size={20} className={(inputText.trim() || selectedMedia) ? "translate-x-0.5" : ""} />)}
            </button>
          </div>
        </div>
      </div>

      {/* RIGHT SIDEBAR (SLIDEOUT) */}
      {showInfoSidebar && (
        <ChatInfoSidebar 
          chat={chat} 
          onClose={() => setShowInfoSidebar(false)} 
          onLeave={() => {
            setShowInfoSidebar(false);
            onBack();
          }}
        />
      )}

      {/* FORWARD MODAL */}
      {forwardingMessage && (
        <ForwardModal 
          messageText={forwardingMessage} 
          onClose={() => setForwardingMessage(null)}
          onForwardSuccess={() => {
             setForwardingMessage(null);
          }}
        />
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { ArrowRight, Loader2, ChevronLeft, ChevronDown, Search, X, Check, Lock, AlertCircle } from 'lucide-react';
import { Logo } from './Logo';

// Comprehensive list of African countries + Major Global
